function buildOutreachUserPrompt(p: any, tone?: string): string {
  const country = p.country || p.location || "United Kingdom";
  const milestoneLabel: Record<string, string> = {
    anniversary: "Company Anniversary",
    end_of_year: "End-of-Year / Christmas Celebration",
    product_launch: "Product Launch / Office Opening",
    celebration: "Milestone Achievement / Award Win",
    general: "General Corporate Event",
  };
  return `COMPANY NAME: ${p.company_name}
EVENT TYPE: ${milestoneLabel[p.milestone_type] || p.milestone_type}
MILESTONE / OCCASION: ${p.milestone_detail || "Milestone celebration"}
WHAT THEY ARE KNOWN FOR: ${p.industry || "Business services"}
COUNTRY: ${country}
TONE: ${tone || "warm, premium, intelligent"}
OPTIONAL NOTES: ${p.notes ? p.notes.split('\n')[0] : "None"}`;
}

