  const getIamHerSummary = async () => {
    const now = Date.now();
    if (iamHerSummaryCache && now - iamHerSummaryCache.at < 5 * 60 * 1000) {
      return iamHerSummaryCache.data;
    }

    const eventDate = new Date("2026-10-30T00:00:00");
    const today = new Date();
    const daysToEvent = Math.max(0, Math.ceil((eventDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24)));

    const [coCreatorsRes, partnersRes, guestRes, approvedRes, tasksRes, overdueRes, nextRes] = await Promise.all([
      db.execute(sql`SELECT COUNT(*)::int AS cnt FROM event_applications WHERE event_key = 'iamher-2026-08-28' AND final_status = 'accepted'`).catch(() => ({ rows: [{ cnt: 0 }] })),
      db.execute(sql`SELECT COUNT(*)::int AS cnt FROM event_applications WHERE event_key = 'iamher-2026-08-28' AND final_status IN ('accepted','pending')`).catch(() => ({ rows: [{ cnt: 0 }] })),
      db.execute(sql`SELECT COUNT(*)::int AS cnt FROM event_applications WHERE event_key = 'iamher-2026-08-28'`).catch(() => ({ rows: [{ cnt: 0 }] })),
      db.execute(sql`SELECT COUNT(*)::int AS cnt FROM event_applications WHERE event_key = 'iamher-2026-08-28' AND final_status = 'accepted'`).catch(() => ({ rows: [{ cnt: 0 }] })),
      db.execute(sql`SELECT COUNT(*)::int AS cnt FROM tasks WHERE event_id IS NOT NULL`).catch(() => ({ rows: [{ cnt: 0 }] })),
      db.execute(sql`SELECT COUNT(*)::int AS cnt FROM tasks WHERE due_date < NOW() AND status != 'done'`).catch(() => ({ rows: [{ cnt: 0 }] })),
      db.execute(sql`SELECT title, due_date FROM tasks WHERE due_date >= NOW() ORDER BY due_date ASC LIMIT 1`).catch(() => ({ rows: [] })),
    ]);

    const next = (nextRes.rows[0] as any) || null;
    const data = {
      active_event: true,
      event_name: "I Am Her",
      event_date: "2026-10-30",
      event_location: "Milton Keynes",
      days_to_event: daysToEvent,
      co_creators_confirmed: (coCreatorsRes.rows[0] as any).cnt || 0,
      corporate_partners_count: (partnersRes.rows[0] as any).cnt || 0,
      guest_applications_count: (guestRes.rows[0] as any).cnt || 0,
      guest_applications_approved: (approvedRes.rows[0] as any).cnt || 0,
      tasks_total: (tasksRes.rows[0] as any).cnt || 0,
      tasks_overdue: (overdueRes.rows[0] as any).cnt || 0,
      next_milestone: next ? { title: next.title, date: new Date(next.due_date).toISOString() } : null,
    };

    iamHerSummaryCache = { at: now, data };
    return data;
  };

  app.get("/api/summary/iam-her", async (req, res) => {
    const key = String(req.headers["x-cross-system-key"] || req.headers["authorization"] || req.headers["x-alli-sync-key"] || "");
    const bearer = key.replace(/^Bearer\s+/i, "").trim();
    const expected = (process.env.EP_CROSS_SYSTEM_KEY || process.env.ALLI_SYNC_KEY || "").trim();
    if (!expected || bearer !== expected) {
      return res.status(401).json({ message: "Unauthorized" });
    }

    try {
      const data = await getIamHerSummary();
      return res.json(data);
    } catch (err: any) {
      return res.status(500).json({ message: err.message });
    }
  });

