  app.post("/api/auth/register", async (req, res) => {
    try {
      const { name, email, password, country, role, phone, department, jobTitle } = req.body;
      
      // Check if user already exists
      const existingUser = await storage.getUserByEmail?.(email);
      if (existingUser) {
        return res.status(400).json({ message: "Email already registered" });
      }

      // Hash password
      const hashedPassword = await bcrypt.hash(password, 10);
      
      // Self-registration must never grant a privileged role. Role elevation is
      // admin-only via /api/admin/users. Any client-supplied `role` is ignored.
      const userRole = 'client';

      // Create user
      const userData: any = {
        name,
        email,
        password: hashedPassword,
        country: country || null,
        role: userRole,
        username: email,
        phone: phone || null,
        department: department || null,
        jobTitle: jobTitle || null,
      };

      const user = await storage.createUser(userData);
      
      // Generate JWT token
      const token = jwt.sign({ 
        userId: user.id, 
        email: user.email, 
        role: user.role, 
        name: user.name 
      }, getJwtSecret(), { expiresIn: '24h' });
      
      // Send welcome email
      await sendEmail(
        email,
        'Welcome to Event Perfekt!',
        `
        <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
          <h2 style="color: #722F37;">Welcome to Event Perfekt, ${name}!</h2>
          <p>Thank you for creating your account with us. We're excited to help you plan your perfect event.</p>
          <p>You can now log in and start planning your event by visiting our <a href="/about">About Us</a> page to learn more about our services.</p>
          <div style="background: #f8f9fa; padding: 20px; border-radius: 8px; margin: 20px 0;">
            <h3 style="color: #722F37;">What's Next?</h3>
            <ol>
              <li>Complete your event details form</li>
              <li>Receive a personalized quote within 24 hours</li>
              <li>Accept the quote and make your deposit</li>
              <li>Get matched with a dedicated planner</li>
            </ol>
          </div>
          <p>Best regards,<br>The Event Perfekt Team</p>
        </div>
        `
      );

      res.json({ token, user: { id: user.id, name: user.name, email: user.email, role: user.role } });
    } catch (error) {
      console.error('Registration error:', error);
      res.status(500).json({ message: "Registration failed" });
    }
  });

  app.post("/api/auth/login", async (req, res) => {
    try {
      const { email, password } = req.body;
      
      // Find user by email
      const user = await storage.getUserByEmail?.(email);
      if (!user) {
        return res.status(400).json({ message: "Invalid credentials" });
      }

      // Check password
      const validPassword = await bcrypt.compare(password, user.password);
      if (!validPassword) {
        return res.status(400).json({ message: "Invalid credentials" });
      }

      // Generate JWT token
      const token = jwt.sign({ 
        userId: user.id, 
        email: user.email, 
        role: user.role, 
        name: user.name 
      }, getJwtSecret(), { expiresIn: '24h' });
      
      res.json({ token, user: { id: user.id, name: user.name, email: user.email, role: user.role } });
    } catch (error) {
      console.error('Login error:', error);
      res.status(500).json({ message: "Login failed" });
    }
  });

  app.get("/api/me", authenticateToken, async (req, res) => {
    try {
      const userId = (req as any).user?.userId;
      if (!userId) {
        return res.status(401).json({ message: "Not authenticated" });
      }
      const user = await storage.getUser(userId);
      if (!user) {
        return res.status(404).json({ message: "User not found" });
      }
      res.json({ id: user.id, name: user.name, email: user.email, role: user.role, username: user.username });
    } catch (error) {
      console.error('Get current user error:', error);
      res.status(500).json({ message: "Failed to get user" });
    }
  });

  app.get("/api/company-prospects", optionalAuth, async (req: any, res) => {
    try {
      const { status, milestone, country } = req.query;
      let query = sql`SELECT * FROM company_prospects WHERE 1=1 AND (
        industry IS NULL OR 
        industry ILIKE '%corporate%' OR 
        industry ILIKE '%consulting%' OR 
        industry ILIKE '%finance%' OR 
        industry ILIKE '%banking%' OR 
        industry ILIKE '%investment%' OR 
        industry ILIKE '%oil%' OR 
        industry ILIKE '%gas%' OR 
        industry ILIKE '%energy%' OR 
        industry ILIKE '%manufacturing%' OR 
        industry ILIKE '%technology%' OR 
        industry ILIKE '%pharmaceutical%' OR 
        industry ILIKE '%healthcare%' OR 
        industry ILIKE '%telecommunications%' OR 
        industry ILIKE '%utilities%' OR 
        industry ILIKE '%real estate%' OR 
        industry ILIKE '%automotive%' OR 
        industry ILIKE '%retail%' OR 
        industry ILIKE '%hospitality%' OR 
        industry ILIKE '%travel%' OR 
        industry ILIKE '%logistics%' OR 
        industry ILIKE '%transportation%' OR 
        industry ILIKE '%government%' OR 
        industry ILIKE '%public%' OR 
        industry ILIKE '%education%' OR 
        industry ILIKE '%media%' OR 
        industry ILIKE '%entertainment%'
      )`;
      if (status && status !== "all") query = sql`${query} AND status = ${status}`;
      if (milestone && milestone !== "all") query = sql`${query} AND milestone_type = ${milestone}`;
      if (country && country !== "all") {
        if (country === "UK") {
          query = sql`${query} AND (
            country ILIKE '%united kingdom%' OR country ILIKE '%england%' OR
            country ILIKE '%scotland%' OR country ILIKE '%wales%' OR
            country = 'UK' OR country = 'GB' OR
            location ILIKE '%united kingdom%' OR location ILIKE '%england%' OR
            location ILIKE '%london%' OR location ILIKE '%manchester%' OR
            location ILIKE '%birmingham%' OR location ILIKE '%leeds%' OR
            location ILIKE '%bristol%' OR location ILIKE '%milton keynes%'
          )`;
        } else if (country === "Nigeria") {
          query = sql`${query} AND (
            country ILIKE '%nigeria%' OR country = 'NG' OR
            location ILIKE '%nigeria%' OR location ILIKE '%lagos%' OR
            location ILIKE '%abuja%' OR location ILIKE '%port harcourt%'
          )`;
        } else {
          query = sql`${query} AND (country = ${country} OR location ILIKE ${'%' + country + '%'})`;
        }
      }
      const result = await db.execute(sql`${query} ORDER BY created_at DESC`);
      res.json(result.rows);
    } catch (error: any) { res.status(500).json({ message: error.message }); }
  });

  app.post("/api/company-prospects", authenticateToken, async (req: any, res) => {
    try {
      const d = req.body;
      const userId = req.user?.id;
      const result = await db.execute(sql`
        INSERT INTO company_prospects (company_name, industry, location, country, website, milestone_type, milestone_detail, founded_year, contact_info, notes, priority)
        VALUES (${d.company_name ?? null}, ${d.industry ?? null}, ${d.location ?? null}, ${d.country ?? null}, ${d.website ?? null}, ${d.milestone_type ?? 'general'}, ${d.milestone_detail ?? null}, ${d.founded_year ?? null}, ${d.contact_info ?? null}, ${d.notes ?? null}, ${d.priority ?? 'medium'})
        RETURNING *
      `);
      
      const newProspect = result.rows[0] as any;
      const prospectId = newProspect.id;

      // Auto-generate draft sequence when prospect is created
      if (tenderOpenAI && newProspect.company_name) {
        try {
          const countryTones: Record<string, string> = {
            GB: "formal, concise, direct",
            NG: "warm, relationship-first, local context-aware",
            US: "confident, value-led, ROI-focused",
            CA: "formal, concise, direct",
            GH: "warm, relationship-first, local context-aware",
            KE: "warm, relationship-first, local context-aware",
            ZA: "warm, relationship-first, local context-aware",
            AE: "formal, prestige and exclusivity emphasized",
            DE: "precise, structured, fact-based",
            FR: "relationship-aware, quality-led",
          };
          const emailTone = countryTones[newProspect.country] || countryTones["GB"];

          const content = await callClaude(
            `You are an expert email copywriter for Event Perfekt, a luxury event planning company. Generate a 4-touch outreach sequence for a prospect. Email tone: ${emailTone}. Return ONLY valid JSON with this exact structure: {"touches":[{"touchNumber":1,"channel":"email","subject":"subject line","body":"email body"},{"touchNumber":2,"channel":"whatsapp","subject":null,"body":"whatsapp message"},{"touchNumber":3,"channel":"email","subject":"subject line","body":"email body"},{"touchNumber":4,"channel":"email","subject":"subject line","body":"email body"}]}`,
            `Generate a 4-touch outreach sequence for:\n- Company: ${newProspect.company_name}\n- Industry: ${newProspect.industry || "Unknown"}\n- Country: ${newProspect.country || "GB"}\n- Milestone: ${newProspect.milestone_type} (${newProspect.milestone_detail || "N/A"})\n- Priority: ${newProspect.priority || "medium"}\n- Location: ${newProspect.location || "Unknown"}\n\nUse distinct angles for each touch. No repetition. Make it personal and compelling.`,
            1200
          );
          let sequenceData: any = {};
          
          try {
            sequenceData = JSON.parse(content || "{}");
          } catch {
            console.log("Failed to parse auto-sequence");
          }

          // Create draft sequence record
          if (sequenceData.touches && sequenceData.touches.length > 0) {
            const sequenceResult = await db.execute(sql`
              INSERT INTO prospect_sequences (prospect_id, status, created_by, created_at)
              VALUES (${prospectId}, 'draft', ${userId}, NOW())
              RETURNING id
            `);

            const sequenceId = sequenceResult.rows[0]?.id;

            // Create scheduled messages
            const touchDays = [0, 4, 9, 14];
            for (let touch of sequenceData.touches) {
              const scheduledDay = touchDays[touch.touchNumber - 1] || 0;
              await db.execute(sql`
                INSERT INTO sequenced_messages (
                  sequence_id, touch_number, channel, scheduled_day, subject, body, status, created_at
                ) VALUES (
                  ${sequenceId}, ${touch.touchNumber}, ${touch.channel}, 
                  ${scheduledDay}, ${touch.subject || null}, ${touch.body}, 'pending', NOW()
                )
              `);
            }
          }
        } catch (seqErr: any) {
          console.log("Auto-sequence generation failed (non-fatal):", seqErr.message);
          // Don't fail prospect creation if sequence generation fails
        }
      }

      // Trigger automatic contact finding in background (async, don't block response)
      if (newProspect.company_name && newProspect.website) {
        (async () => {
          try {
            const { runContactAndDraftForProspect } = await import("../outreach-routes");
            await runContactAndDraftForProspect(prospectId);
          } catch (err: any) {
            console.log("Background contact finding failed:", err.message);
          }
        })();
      }

      res.json(newProspect);
    } catch (error: any) { res.status(500).json({ message: error.message }); }
  });

  app.patch("/api/company-prospects/:id", authenticateToken, async (req: any, res) => {
    try {
      const d = req.body;
      const id = parseInt(req.params.id);
      const userId = req.user?.id;

      // Fetch current prospect to check if status is changing to "contacted"
      const currentResult = await db.execute(sql`SELECT status FROM company_prospects WHERE id = ${id}`);
      const currentProspect = currentResult.rows[0] as any;
      const statusChangingToContacted = d.status === "contacted" && currentProspect?.status !== "contacted";

      // Auto-update last_contacted_at on status change or certain updates
      const contactingStatuses = ['contacted', 'meeting', 'proposal', 'negotiation'];
      const autoUpdateContact = d.status && contactingStatuses.includes(d.status) && d.status !== currentProspect?.status;

      const result = await db.execute(sql`
        UPDATE company_prospects SET
          company_name = COALESCE(${d.company_name ?? null}, company_name),
          status = COALESCE(${d.status ?? null}, status),
          priority = COALESCE(${d.priority ?? null}, priority),
          notes = COALESCE(${d.notes ?? null}, notes),
          industry = COALESCE(${d.industry ?? null}, industry),
          location = COALESCE(${d.location ?? null}, location),
          country = COALESCE(${d.country ?? null}, country),
          website = COALESCE(${d.website ?? null}, website),
          contact_info = COALESCE(${d.contact_info ?? null}, contact_info),
          milestone_type = COALESCE(${d.milestone_type ?? null}, milestone_type),
          milestone_detail = COALESCE(${d.milestone_detail ?? null}, milestone_detail),
          founded_year = COALESCE(${d.founded_year ?? null}, founded_year),
          estimated_value = COALESCE(${d.estimated_value ?? null}, estimated_value),
          currency = COALESCE(${d.currency ?? null}, currency),
          assigned_to = COALESCE(${d.assigned_to ?? null}, assigned_to),
          contact_name = COALESCE(${d.contact_name ?? null}, contact_name),
          contact_title = COALESCE(${d.contact_title ?? null}, contact_title),
          contact_email = COALESCE(${d.contact_email ?? null}, contact_email),
          contact_linkedin = COALESCE(${d.contact_linkedin ?? null}, contact_linkedin),
          contact_confidence = COALESCE(${d.contact_confidence ?? null}, contact_confidence),
          last_contacted_at = CASE WHEN ${autoUpdateContact} THEN NOW() ELSE COALESCE(${d.last_contacted_at ?? null}, last_contacted_at) END,
          updated_at = NOW()
        WHERE id = ${id} RETURNING *
      `);

      const updatedProspect = result.rows[0] as any;

      // Auto-generate sequence when status changes to "contacted"
      if (statusChangingToContacted && tenderOpenAI) {
        try {
          const countryTones: Record<string, string> = {
            GB: "formal, concise, direct",
            NG: "warm, relationship-first, local context-aware",
            US: "confident, value-led, ROI-focused",
            CA: "formal, concise, direct",
            GH: "warm, relationship-first, local context-aware",
            KE: "warm, relationship-first, local context-aware",
            ZA: "warm, relationship-first, local context-aware",
            AE: "formal, prestige and exclusivity emphasized",
            DE: "precise, structured, fact-based",
            FR: "relationship-aware, quality-led",
          };
          const emailTone = countryTones[updatedProspect.country] || countryTones["GB"];

          const content = await callClaude(
            `You are an expert email copywriter for Event Perfekt, a luxury event planning company. Generate a 4-touch outreach sequence for a prospect. Email tone: ${emailTone}. Return ONLY valid JSON with this exact structure: {"touches":[{"touchNumber":1,"channel":"email","subject":"subject line","body":"email body"},{"touchNumber":2,"channel":"whatsapp","subject":null,"body":"whatsapp message"},{"touchNumber":3,"channel":"email","subject":"subject line","body":"email body"},{"touchNumber":4,"channel":"email","subject":"subject line","body":"email body"}]}`,
            `Generate a 4-touch outreach sequence for:\n- Company: ${updatedProspect.company_name}\n- Industry: ${updatedProspect.industry || "Unknown"}\n- Country: ${updatedProspect.country || "GB"}\n- Milestone: ${updatedProspect.milestone_type} (${updatedProspect.milestone_detail || "N/A"})\n- Priority: ${updatedProspect.priority}\n- Location: ${updatedProspect.location || "Unknown"}\n\nUse distinct angles for each touch. No repetition. Make it personal and compelling.`,
            1200
          );
          let sequenceData: any = {};
          
          try {
            sequenceData = JSON.parse(content || "{}");
          } catch {
            console.log("Failed to parse auto-sequence, user can generate manually");
          }

          // Create sequence record
          if (sequenceData.touches && sequenceData.touches.length > 0) {
            const sequenceResult = await db.execute(sql`
              INSERT INTO prospect_sequences (prospect_id, status, created_by, created_at)
              VALUES (${id}, 'draft', ${userId}, NOW())
              RETURNING id
            `);

            const sequenceId = sequenceResult.rows[0]?.id;

            // Create scheduled messages
            const touchDays = [0, 4, 9, 14];
            for (let touch of sequenceData.touches) {
              const scheduledDay = touchDays[touch.touchNumber - 1] || 0;
              await db.execute(sql`
                INSERT INTO sequenced_messages (
                  sequence_id, touch_number, channel, scheduled_day, subject, body, status, created_at
                ) VALUES (
                  ${sequenceId}, ${touch.touchNumber}, ${touch.channel}, 
                  ${scheduledDay}, ${touch.subject || null}, ${touch.body}, 'pending', NOW()
                )
              `);
            }
          }
        } catch (seqErr: any) {
          console.log("Auto-sequence generation failed (non-fatal):", seqErr.message);
          // Don't fail the prospect update if sequence generation fails
        }
      }

      res.json(updatedProspect);
    } catch (error: any) { res.status(500).json({ message: error.message }); }
  });

