  app.get("/api/company-prospects/agent-outreach", authenticateToken, async (req: any, res) => {
    try {
      const result = await db.execute(sql`
        SELECT * FROM company_prospects 
        WHERE status NOT IN ('won', 'lost')
          AND (
            status != 'contacted'
            OR last_contacted_at IS NULL
            OR last_contacted_at < NOW() - INTERVAL '7 days'
          )
        ORDER BY 
          CASE priority WHEN 'high' THEN 1 WHEN 'medium' THEN 2 ELSE 3 END,
          CASE milestone_type WHEN 'anniversary' THEN 1 WHEN 'end_of_year' THEN 2 WHEN 'product_launch' THEN 3 ELSE 4 END,
          created_at DESC
        LIMIT 20
      `);
      const candidates = result.rows as any[];

      if (!tenderOpenAI || candidates.length === 0) {
        return res.json({ 
          recommendations: candidates.slice(0, 10).map((c: any) => ({
            ...c,
            reason: c.priority === 'high' ? 'High priority prospect' : 'New lead awaiting outreach',
            urgency: c.priority === 'high' ? 'high' : 'medium',
          }))
        });
      }

      const summaries = candidates.slice(0, 15).map((c: any) => 
        `ID:${c.id} | ${c.company_name} | Industry: ${c.industry || 'Unknown'} | Location: ${c.location || c.country || 'Unknown'} | Milestone: ${c.milestone_type} (${c.milestone_detail || 'N/A'}) | Priority: ${c.priority} | Status: ${c.status} | Founded: ${c.founded_year || 'Unknown'} | Has Contact: ${c.contact_info ? 'Yes' : 'No'} | Website: ${c.website ? 'Yes' : 'No'}`
      ).join('\n');

      const response = await tenderOpenAI.chat.completions.create({
        model: "gpt-4o-mini",
        messages: [{
          role: "system",
          content: `You are an expert business development strategist for Event Perfekt, a luxury event planning company operating in the UK and Nigeria.

Analyze these prospects and rank the TOP 8 most promising to contact RIGHT NOW. Consider:
- Companies with upcoming milestones or anniversaries (most time-sensitive)
- High priority prospects
- Industries that typically spend big on events (finance, oil & gas, tech, luxury brands, government)
- Companies with contact info available (easier to reach)
- Companies with websites (can derive email addresses)

For each recommendation, provide a compelling reason WHY to contact them now and a suggested email angle.

Prospects:
${summaries}

Return a JSON object with "recommendations" array. Each item: { "id": number, "reason": "Why contact now", "email_angle": "Suggested email approach", "urgency": "high"|"medium"|"low", "suggested_subject": "Email subject line" }`
        }],
        response_format: { type: "json_object" }
      });

      const aiResult = JSON.parse(response.choices[0].message.content || '{"recommendations":[]}');
      
      const enriched = (aiResult.recommendations || []).map((rec: any) => {
        const prospect = candidates.find((c: any) => c.id === rec.id);
        return prospect ? { ...prospect, ...rec } : null;
      }).filter(Boolean);

      res.json({ recommendations: enriched });
    } catch (error: any) {
      console.error("Smart outreach error:", error);
      res.status(500).json({ message: "Failed to generate recommendations: " + error.message });
    }
  });

