  app.post("/api/company-prospects/:id/convert", authenticateToken, async (req: any, res) => {
    try {
      const prospectId = parseInt(req.params.id);
      const userId = req.user?.userId || req.user?.id;

      const prospectResult = await db.execute(sql`SELECT * FROM company_prospects WHERE id = ${prospectId}`);
      if (prospectResult.rows.length === 0) {
        return res.status(404).json({ message: "Prospect not found" });
      }
      
      const prospect = prospectResult.rows[0] as any;

      // Create new event from prospect data
      const newEventResult = await db.execute(sql`
        INSERT INTO events (
          name, 
          client_name, 
          client_email, 
          client_phone, 
          client_company,
          event_type,
          guest_count,
          budget,
          currency,
          workflow_status,
          assigned_to,
          notes,
          created_at,
          updated_at
        ) VALUES (
          ${prospect.company_name ? `${prospect.company_name} Event` : 'Converted Prospect Event'},
          ${prospect.contact_info?.split(',')[0]?.trim() || prospect.company_name},
          ${prospect.email || ''},
          ${prospect.phone || ''},
          ${prospect.company_name || ''},
          ${prospect.milestone_type || 'corporate'},
          ${0},
          ${'0'},
          ${'GBP'},
          ${'new_intake'},
          ${userId || null},
          ${`Converted from Prospect Finder. Milestone: ${prospect.milestone_type || 'N/A'}. Notes: ${prospect.notes || ''}`},
          NOW(),
          NOW()
        )
        RETURNING id, name
      `);

      if (newEventResult.rows.length === 0) {
        return res.status(500).json({ message: "Failed to create event" });
      }

      const newEvent = newEventResult.rows[0] as any;
      const eventId = newEvent.id;

      // Update prospect status to won
      await db.execute(sql`
        UPDATE company_prospects 
        SET status = 'won', updated_at = NOW() 
        WHERE id = ${prospectId}
      `);

      // Create audit log entry
      try {
        await db.execute(sql`
          INSERT INTO activity_audit_log (id, changed_by, change_type, field_changed, new_value, timestamp)
          VALUES (
            gen_random_uuid(),
            ${userId || 'system'},
            'prospect_converted',
            'prospect_id',
            ${prospectId.toString()},
            NOW()
          )
        `);
      } catch (auditErr: any) {
        console.error("Audit log error:", auditErr.message);
        // Don't fail the response if audit logging fails
      }

      res.json({
        eventId,
        eventName: newEvent.name,
        message: "Prospect successfully converted to event"
      });

    } catch (error: any) {
      console.error("Convert prospect error:", error);
      res.status(500).json({ message: "Failed to convert prospect to event", error: error.message });
    }
  });

