  app.get("/api/gdpr/export", authenticateToken, async (req: any, res) => {
    try {
      const userId = req.user?.userId;
      if (!userId) return res.status(401).json({ message: "Not authenticated" });
      const user = await storage.getUser(userId);
      if (!user) return res.status(404).json({ message: "User not found" });
      const userEvents = await storage.getAllEvents();
      const myEvents = userEvents.filter((e: any) => e.client_id === userId || e.planner_id === userId || e.created_by === userId);
      let myTasks: any[] = [];
      try { const tr = await db.execute(sql`SELECT id, title, status FROM tasks WHERE assigned_to = ${userId} OR created_by = ${userId}`); myTasks = tr.rows as any[]; } catch(e) {}
      let contractRows: any[] = [];
      try { const c = await db.execute(sql`SELECT id, title, event_id, status, created_at FROM contracts WHERE client_id = ${userId} OR user_id = ${userId}`); contractRows = c.rows as any[]; } catch(e) {}
      let invoiceRows: any[] = [];
      try { const i = await db.execute(sql`SELECT id, invoice_number, amount, currency, status, created_at FROM invoices WHERE client_id = ${userId} OR user_id = ${userId}`); invoiceRows = i.rows as any[]; } catch(e) {}
      let auditCount = 0;
      try { const a = await db.execute(sql`SELECT COUNT(*) as cnt FROM activity_audit_log WHERE changed_by = ${userId}`); auditCount = parseInt((a.rows[0] as any)?.cnt || "0"); } catch(e) {}
      const exportData = {
        export_date: new Date().toISOString(),
        gdpr_notice: "This export contains all personal data held by Event Perfekt for your account, as per your rights under GDPR Article 20 (Right to Data Portability).",
        user: { id: user.id, name: user.name, email: user.email, role: user.role, username: user.username, country: (user as any).country || null, phone: (user as any).phone || null, created_at: (user as any).created_at || null },
        events: myEvents.map((e: any) => ({ id: e.id, name: e.name, date: e.date, status: e.status, type: e.event_type, country: e.country, created_at: e.created_at })),
        tasks: myTasks.map((t: any) => ({ id: t.id, title: t.title, status: t.status })),
        contracts: contractRows.map((c: any) => ({ id: c.id, title: c.title, status: c.status, created_at: c.created_at })),
        invoices: invoiceRows.map((i: any) => ({ id: i.id, number: i.invoice_number, amount: i.amount, currency: i.currency, status: i.status })),
        activity_log_entries: auditCount,
      };
      res.setHeader('Content-Type', 'application/json');
      res.setHeader('Content-Disposition', `attachment; filename="event-perfekt-data-export-${userId}-${format(new Date(), "yyyy-MM-dd")}.json"`);
      res.json(exportData);
    } catch (error: any) {
      console.error("GDPR export error:", error);
      res.status(500).json({ message: "Export failed" });
    }
  });

