  app.post("/api/vendor-portal/login", async (req, res) => {
    try {
      const { email, password } = req.body;

      // Find vendor user
      const vendorUser = await storage.getVendorUserByEmail?.(email);
      if (!vendorUser) {
        return res.status(401).json({ message: "Invalid credentials" });
      }

      // Verify password
      const validPassword = await bcrypt.compare(password, vendorUser.password);
      if (!validPassword) {
        return res.status(401).json({ message: "Invalid credentials" });
      }

      // Update last login date
      await storage.updateVendorUser?.(vendorUser.id, {
        lastLoginDate: new Date()
      });

      // Generate JWT token
      const token = jwt.sign({ 
        vendorUserId: vendorUser.id, 
        email: vendorUser.email, 
        companyName: vendorUser.companyName 
      }, getJwtSecret(), { expiresIn: '24h' });
      
      res.json({ 
        token, 
        user: { 
          id: vendorUser.id, 
          companyName: vendorUser.companyName, 
          email: vendorUser.email,
          status: vendorUser.status,
          profileCompletionStatus: vendorUser.profileCompletionStatus
        } 
      });
    } catch (error) {
      console.error('Vendor login error:', error);
      res.status(500).json({ message: "Login failed" });
    }
  });

  // Middleware for vendor authentication
  const authenticateVendor = (req: any, res: any, next: any) => {
    const token = req.header('Authorization')?.replace('Bearer ', '');
    
    if (!token) {
      return res.status(401).json({ message: "Access denied. No token provided." });
    }

    try {
      const decoded = jwt.verify(token, getJwtSecret()) as any;
      req.vendorUser = decoded;
      next();
    } catch (error) {
      res.status(401).json({ message: "Invalid token" });
    }
  };

