  // Events — role-based filtering
  app.get("/api/events", optionalAuth, async (req: any, res) => {
    try {
      const allEvents = await storage.getAllEvents();
      const userRole = req.user?.role;
      const userId = req.user?.id;

      let filtered = allEvents;
      // TRAINING MODE: demo-planner sees all events
      if (userRole === 'planner' && userId !== 'demo-planner') {
        filtered = allEvents.filter((e: any) => e.plannerId === userId);
      } else if (userRole === 'staff' || userRole === 'collaborator') {
        const assigned = await db.execute(sql`
          SELECT DISTINCT event_id FROM event_collaborators WHERE user_id = ${userId} AND status = 'accepted'
          UNION
          SELECT DISTINCT event_id FROM event_resources WHERE assigned_to = ${userId}
        `);
        const assignedIds = new Set((assigned.rows as any[]).map((r: any) => r.event_id));
        filtered = allEvents.filter((e: any) => assignedIds.has(e.id));
      }

      const eventsWithPlanners = await Promise.all(
        filtered.map(async (event) => {
          const planner = event.plannerId ? await storage.getUser(event.plannerId) : null;
          return { ...event, planner };
        })
      );
      res.json(eventsWithPlanners);
    } catch (error) {
      res.status(500).json({ message: "Failed to fetch events" });
    }
  });

  app.get("/api/events/:id", async (req, res) => {
    try {
      const event = await storage.getEvent(req.params.id);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }
      
      const planner = event.plannerId ? await storage.getUser(event.plannerId) : null;
      const tasks = await storage.getTasksByEventId(event.id);
      const vendors = await storage.getVendorsByEventId(event.id);
      const budgetItems = await storage.getBudgetItemsByEventId(event.id);
      const contracts = await storage.getContractsByEventId(event.id);
      
      res.json({
        ...event,
        planner,
        tasks,
        vendors,
        budgetItems,
        contracts
      });
    } catch (error) {
      console.error("GET /api/events/:id error:", (error as Error).message, (error as Error).stack?.split('\n')[1]);
      res.status(500).json({ message: "Failed to fetch event", detail: (error as Error).message });
    }
  });

  app.post("/api/events", upload.fields([
    { name: 'heroImage', maxCount: 1 },
    { name: 'companyLogo', maxCount: 1 }
  ]), async (req, res) => {
    try {
      const files = req.files as { [fieldname: string]: Express.Multer.File[] };
      
      const rawEventType = req.body.type || "";
      const corporateTypes = ["corporate", "government_public", "charity_community", "education", "international_cross_border", "ticketing"];
      const resolvedType = corporateTypes.includes(rawEventType) ? "corporate" : "private";

      const eventData = {
        ...req.body,
        type: resolvedType,
        startDate: new Date(req.body.startDate),
        endDate: new Date(req.body.endDate),
        guestCount: parseInt(req.body.guestCount) || 0,
        eventDays: parseInt(req.body.eventDays) || 1,
        budget: req.body.budget || "0",
        heroImage: files?.heroImage?.[0] ? `/uploads/${files.heroImage[0].filename}` : null,
        companyLogo: files?.companyLogo?.[0] ? `/uploads/${files.companyLogo[0].filename}` : null,
        // Convert string booleans to actual booleans
        hasVenue: req.body.hasVenue === 'true',
        needsDecor: req.body.needsDecor === 'true',
        needsVendorSupport: req.body.needsVendorSupport === 'true',
        needsPlanningServices: req.body.needsPlanningServices === 'true',
        needsBranding: req.body.needsBranding === 'true',
        needsCatering: req.body.needsCatering === 'true',
        needsVendorCoordination: req.body.needsVendorCoordination === 'true',
        needsEndToEndPlanning: req.body.needsEndToEndPlanning === 'true',
        needsDayCoordination: req.body.needsDayCoordination === 'true',
        needsVenueDecoration: req.body.needsVenueDecoration === 'true',
        needsVenueSearch: req.body.needsVenueSearch === 'true',
        needsBrandedStyling: req.body.needsBrandedStyling === 'true',
        needsHumanResources: req.body.needsHumanResources === 'true',
        needsPartyPacks: req.body.needsPartyPacks === 'true',
        needsCorporateGifting: req.body.needsCorporateGifting === 'true',
        needsConceptDelivery: req.body.needsConceptDelivery === 'true',
        needsOtherServices: req.body.needsOtherServices === 'true',
        hasAdults: req.body.hasAdults === 'true',
        hasTeenagers: req.body.hasTeenagers === 'true',
        hasPreteens: req.body.hasPreteens === 'true',
        hasChildren: req.body.hasChildren === 'true',
        rsvpEnabled: req.body.rsvpEnabled !== 'false',
        eventWebsiteEnabled: req.body.eventWebsiteEnabled !== 'false',
        ceremonyDate: req.body.ceremonyDate ? new Date(req.body.ceremonyDate) : null,
        receptionDate: req.body.receptionDate ? new Date(req.body.receptionDate) : null,
        afterPartyDate: req.body.afterPartyDate ? new Date(req.body.afterPartyDate) : null,
        planningMode: req.body.planningMode || 'full_planning',
        // Event type-specific fields
        publicSectorBody: req.body.publicSectorBody || null,
        charityRegistration: req.body.charityRegistration || null,
        schoolOrInstitution: req.body.schoolOrInstitution || null,
        privateOccasionType: req.body.privateOccasionType || null,
        crossBorderCountries: req.body.crossBorderCountries || null,
        twinPaayEnabled: req.body.twinPaayEnabled === 'true',
        internationalTravelRequired: req.body.internationalTravelRequired === 'true',
        internationalVisaSupport: req.body.internationalVisaSupport === 'true',
        clientOwnPlanner: req.body.clientOwnPlanner || null,
        existingVendors: req.body.existingVendors || null,
        existingTimeline: req.body.existingTimeline || null,
        coordinationScope: req.body.coordinationScope || null,
        setupTime: req.body.setupTime || null,
        clientContactOnDay: req.body.clientContactOnDay || null,
        emergencyContact: req.body.emergencyContact || null,
      };

      let weddingEventsData: any[] = [];
      try {
        if (req.body.weddingEvents) {
          weddingEventsData = JSON.parse(req.body.weddingEvents);
        }
      } catch (e) {}

      if (weddingEventsData.length > 1) {
        const parentData = { ...eventData, weddingScope: 'parent' };
        delete parentData.weddingEvents;
        const parentEvent = await storage.createEvent(parentData as any);

        const childEvents = [];
        for (const scope of weddingEventsData) {
          const scopeLabels: Record<string, string> = {
            "Traditional": "Traditional Engagement",
            "Church Wedding": "Church Wedding",
            "Reception": "Reception (Party)",
            "After Party": "After Party",
          };
          const scopeName = `${eventData.name} — ${scopeLabels[scope.type] || scope.type}`;
          const scopeDate = scope.date ? new Date(scope.date) : eventData.startDate;
          const childData = {
            ...eventData,
            name: scopeName,
            description: scope.description || eventData.description,
            startDate: scopeDate,
            endDate: scopeDate,
            eventDays: 1,
            guestCount: parseInt(scope.guestCount) || eventData.guestCount,
            parentEventId: parentEvent.id,
            weddingScope: scope.type.toLowerCase(),
            ceremonyVenue: scope.type === "Church Wedding" ? scope.churchName : null,
            receptionVenue: scope.venue || null,
            city: scope.city || eventData.city,
          };
          delete childData.weddingEvents;
          const child = await storage.createEvent(childData as any);
          childEvents.push(child);
        }

        storage.createPlanningLogEntry({
          eventId: parentEvent.id,
          category: 'general',
          action: 'event_created',
          description: `Event "${parentEvent.name}" created with ${childEvents.length} wedding scopes`,
          entityType: 'event',
          entityId: parentEvent.id,
          entityName: parentEvent.name,
          changedByName: 'Planner',
          decisionType: 'event_created',
          decisionRationale: `New ${parentEvent.type} event created for ${parentEvent.guestCount} guests in ${parentEvent.city}, ${parentEvent.country}`,
          priority: 'critical',
          tags: ['event', 'created', 'milestone'],
        }).catch(() => {});
        for (const child of childEvents) {
          storage.createPlanningLogEntry({
            eventId: child.id,
            category: 'general',
            action: 'event_created',
            description: `Wedding scope "${child.name}" created as part of ${parentEvent.name}`,
            entityType: 'event',
            entityId: child.id,
            entityName: child.name,
            changedByName: 'Planner',
            priority: 'high',
            tags: ['event', 'wedding_scope', 'created'],
          }).catch(() => {});
        }
        autoGenerateProposal(parentEvent.id).then(p => {
          if (p) console.log(`Auto-generated proposal for wedding event: ${parentEvent.name}`);
        }).catch(err => console.error("Auto proposal error:", err));

        autoGenerateBudget(parentEvent.id, req.body).then(items => {
          if (items.length) console.log(`Auto-generated ${items.length} budget items for wedding event: ${parentEvent.name}`);
        }).catch(err => console.error("Auto budget error:", err));

        autoGenerateVendors(parentEvent.id, req.body).then(v => {
          if (v.length) console.log(`Auto-generated ${v.length} vendor slots for wedding event: ${parentEvent.name}`);
        }).catch(err => console.error("Auto vendor error:", err));

        autoGenerateInvoice(parentEvent.id).then(inv => {
          if (inv) console.log(`Auto-generated deposit invoice for wedding event: ${parentEvent.name}`);
        }).catch(err => console.error("Auto invoice error:", err));

        autoGeneratePlanner(parentEvent.id).then(count => {
          if (count) console.log(`Auto-generated ${count} Enhanced Planner tasks for wedding event: ${parentEvent.name}`);
        }).catch(err => console.error("Auto planner error:", err));

        for (const child of childEvents) {
          autoGenerateBudget(child.id, req.body).catch(() => {});
          autoGenerateVendors(child.id, req.body).catch(() => {});
          autoGeneratePlanner(child.id).catch(() => {});
        }

        res.json({ ...parentEvent, childEvents });
      } else {
        if (weddingEventsData.length === 1) {
          eventData.weddingScope = weddingEventsData[0].type.toLowerCase();
        }
        delete eventData.weddingEvents;
        const event = await storage.createEvent(eventData as any);
        storage.createPlanningLogEntry({
          eventId: event.id,
          category: 'general',
          action: 'event_created',
          description: `Event "${event.name}" created — ${event.type} for ${event.guestCount} guests`,
          entityType: 'event',
          entityId: event.id,
          entityName: event.name,
          changedByName: 'Planner',
          decisionType: 'event_created',
          decisionRationale: `New ${event.type} event created for ${event.guestCount} guests in ${event.city || ''}, ${event.country || ''}`,
          priority: 'critical',
          tags: ['event', 'created', 'milestone'],
        }).catch(() => {});

        // ──────────────────────────────────────────────────────────────────────
        // SEND NOTIFICATIONS TO ADMIN, FAYE, AND LOLADE
        // ──────────────────────────────────────────────────────────────────────
        (async () => {
          try {
            const adminEmails = ['info@eventperfekt.com', 'faye@eventperfekt.com', 'lolade@eventperfekt.com'];
            const eventLink = `https://eventperfekt.net/event-dashboard/${event.id}`;
            
            const emailBody = `
            <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
              <h2 style="color: #8B1538;">🎉 New Event Created</h2>
              <p>A new event has been created in Event Perfekt!</p>
              <div style="background: #f8f9fa; padding: 20px; border-radius: 8px; margin: 20px 0;">
                <p><strong>Event Name:</strong> ${event.name}</p>
                <p><strong>Type:</strong> ${event.type}</p>
                <p><strong>Guests:</strong> ${event.guestCount}</p>
                <p><strong>Location:</strong> ${event.city || 'TBD'}, ${event.country || 'TBD'}</p>
                <p><strong>Date:</strong> ${event.startDate.toLocaleDateString()}</p>
                <p><strong>Budget:</strong> ${event.currency} ${event.budget}</p>
              </div>
              <p><a href="${eventLink}" style="background: #8B1538; color: white; padding: 10px 20px; text-decoration: none; border-radius: 4px; display: inline-block;">View Event</a></p>
            </div>
            `;
            
            // Send emails to admin, Faye, and Lolade
            await Promise.all(adminEmails.map(email => 
              sendEmail(email, `🎉 New Event Created: ${event.name}`, emailBody).catch(e => console.error(`Failed to email ${email}:`, e))
            ));
            
            // Create in-app notifications for them
            const userResult = await db.execute(sql`SELECT id FROM users WHERE email IN ('info@eventperfekt.com', 'faye@eventperfekt.com', 'lolade@eventperfekt.com')`);
            const userIds = userResult.rows.map((r: any) => r.id);
            
            await Promise.all(userIds.map(userId =>
              notificationService.sendNotification({
                userId,
                title: `New Event: ${event.name}`,
                message: `A new ${event.type} event for ${event.guestCount} guests has been created`,
                type: 'event_created',
                relatedEntityId: event.id,
                relatedEntityType: 'event',
                actionUrl: `/event-dashboard/${event.id}`
              }).catch(e => console.error('Notification error:', e))
            ));
            
            console.log(`✉️ Event notifications sent to admin, Faye, and Lolade`);
          } catch (err) {
            console.error('Error sending event notifications:', err);
          }
        })();

        autoGenerateProposal(event.id).then(p => {
          if (p) console.log(`Auto-generated proposal for event: ${event.name}`);
        }).catch(err => console.error("Auto proposal error:", err));

        autoGenerateBudget(event.id, req.body).then(items => {
          if (items.length) console.log(`Auto-generated ${items.length} budget items for event: ${event.name}`);
        }).catch(err => console.error("Auto budget error:", err));

        autoGenerateVendors(event.id, req.body).then(v => {
          if (v.length) console.log(`Auto-generated ${v.length} vendor slots for event: ${event.name}`);
        }).catch(err => console.error("Auto vendor error:", err));

        autoGenerateInvoice(event.id).then(inv => {
          if (inv) console.log(`Auto-generated deposit invoice for event: ${event.name}`);
        }).catch(err => console.error("Auto invoice error:", err));

        autoGeneratePlanner(event.id).then(count => {
          if (count) console.log(`Auto-generated ${count} Enhanced Planner tasks for event: ${event.name}`);
        }).catch(err => console.error("Auto planner error:", err));

        res.json(event);
      }
    } catch (error) {
      console.error("Event creation error:", error);
      res.status(400).json({ message: "Invalid event data", error: error instanceof Error ? error.message : 'Unknown error' });
    }
  });

