  app.patch("/api/events/:id", upload.single('heroImage'), async (req, res) => {
    try {
      const updateData: any = { ...req.body };
      
      if (req.body.date) {
        updateData.date = new Date(req.body.date);
      }
      if (req.body.guestCount) {
        updateData.guestCount = parseInt(req.body.guestCount);
      }
      if (req.file) {
        updateData.heroImage = `/uploads/${req.file.filename}`;
      }
      if (typeof req.body.preferredColors === "string") {
        try { updateData.preferredColors = JSON.parse(req.body.preferredColors); } catch {}
      }
      if (typeof req.body.floorPlanData === "string") {
        try { updateData.floorPlanData = JSON.parse(req.body.floorPlanData); } catch {}
      }
      
      const event = await storage.updateEvent(req.params.id, updateData);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }
      res.json(event);
    } catch (error) {
      console.error('Event update error:', error);
      res.status(400).json({ message: "Invalid update data" });
    }
  });

