  app.post("/api/vendors/import-google-sheet", authenticateToken, async (req, res) => {
    try {
      const { sheetUrl } = req.body;
      if (!sheetUrl) {
        return res.status(400).json({ message: "Google Sheet URL is required" });
      }
      const sheetIdMatch = sheetUrl.match(/\/spreadsheets\/d\/([a-zA-Z0-9-_]+)/);
      if (!sheetIdMatch) {
        return res.status(400).json({ message: "Invalid Google Sheets URL. Please provide a valid link." });
      }
      const sheetId = sheetIdMatch[1];
      const csvUrl = `https://docs.google.com/spreadsheets/d/${sheetId}/export?format=csv`;
      const response = await fetch(csvUrl);
      if (!response.ok) {
        return res.status(400).json({ message: "Could not access the Google Sheet. Make sure it is set to 'Anyone with the link can view'." });
      }
      const csvText = await response.text();
      const lines = csvText.split('\n').map(line => {
        const result: string[] = [];
        let current = '';
        let inQuotes = false;
        for (const char of line) {
          if (char === '"') { inQuotes = !inQuotes; }
          else if (char === ',' && !inQuotes) { result.push(current.trim()); current = ''; }
          else { current += char; }
        }
        result.push(current.trim());
        return result;
      });
      if (lines.length < 2) {
        return res.status(400).json({ message: "Sheet appears to be empty or has no data rows." });
      }
      const headers = lines[0].map(h => h.toLowerCase().replace(/[^a-z0-9]/g, ''));
      const rows = lines.slice(1).filter(row => row.some(cell => cell.trim())).map(row => {
        const obj: Record<string, string> = {};
        headers.forEach((header, i) => { obj[header] = row[i] || ''; });
        return obj;
      });
      const columnMap: Record<string, string> = {};
      const fieldMappings: Record<string, string[]> = {
        name: ['name', 'vendorname', 'vendor', 'companyname', 'company', 'businessname', 'suppliername', 'supplier'],
        email: ['email', 'emailaddress', 'mail', 'contactemail'],
        phone: ['phone', 'phonenumber', 'telephone', 'tel', 'mobile', 'contactphone', 'contact'],
        serviceType: ['servicetype', 'service', 'category', 'type', 'serviceoffered', 'speciality', 'specialty'],
        quotedAmount: ['quotedamount', 'amount', 'price', 'cost', 'quote', 'rate', 'fee', 'budget'],
        website: ['website', 'url', 'web', 'site'],
        notes: ['notes', 'description', 'comments', 'details', 'info'],
        status: ['status', 'vendorstatus'],
        currency: ['currency', 'curr'],
        companyName: ['companyname', 'company', 'businessname', 'organisation', 'organization'],
      };
      for (const header of headers) {
        for (const [field, aliases] of Object.entries(fieldMappings)) {
          if (aliases.includes(header) && !columnMap[field]) {
            columnMap[field] = header;
            break;
          }
        }
      }
      const mappedRows = rows.map(row => {
        const mapped: Record<string, string> = {};
        for (const [field, headerKey] of Object.entries(columnMap)) {
          mapped[field] = row[headerKey] || '';
        }
        if (!mapped.name && columnMap.companyName) mapped.name = row[columnMap.companyName] || '';
        return mapped;
      }).filter(row => row.name);
      res.json({ rows: mappedRows, headers, columnMap, totalRows: mappedRows.length });
    } catch (error) {
      console.error("Google Sheet import error:", error);
      res.status(500).json({ message: "Failed to fetch Google Sheet data" });
    }
  });

