  app.patch("/api/tasks/:id", async (req, res) => {
    try {
      const updateData = { ...req.body };
      if (req.body.dueDate) {
        updateData.dueDate = new Date(req.body.dueDate);
      }
      const task = await storage.updateTask(req.params.id, updateData);
      if (!task) {
        return res.status(404).json({ message: "Task not found" });
      }
      const changedFields: { field: string; oldValue: any; newValue: any }[] = [];
      for (const key of Object.keys(req.body)) {
        changedFields.push({ field: key, oldValue: undefined, newValue: req.body[key] });
      }
      const isStatusChange = req.body.status !== undefined;
      const isDecision = isStatusChange && (req.body.status === 'completed' || req.body.status === 'cancelled');
      storage.createPlanningLogEntry({
        eventId: task.eventId,
        category: 'task',
        action: isStatusChange ? `status_changed_to_${req.body.status}` : 'updated',
        description: isStatusChange 
          ? `Task "${task.title}" marked as ${req.body.status}`
          : `Task "${task.title}" updated (${Object.keys(req.body).join(', ')})`,
        entityType: 'task',
        entityId: task.id,
        entityName: task.title,
        changedByName: req.body.updatedBy || 'Planner',
        fieldsChanged: changedFields,
        decisionType: isDecision ? (req.body.status === 'completed' ? 'task_completed' : 'task_cancelled') : undefined,
        decisionRationale: isDecision ? `Task "${task.title}" was ${req.body.status}` : undefined,
        priority: isStatusChange ? 'high' : 'normal',
        tags: ['task', req.body.status || 'updated'],
      }).catch(() => {});
      res.json(task);
    } catch (error) {
      res.status(400).json({ message: "Invalid update data" });
    }
  });

