  // Send email from contract management
  app.post("/api/contracts/:contractId/send-email", async (req, res) => {
    try {
      const { to, subject, message, includeContract } = req.body;
      if (!to || !subject) {
        return res.status(400).json({ message: "Email address and subject are required" });
      }
      const contract = await storage.getContractById(req.params.contractId);
      if (!contract) {
        return res.status(404).json({ message: "Contract not found" });
      }
      const cc = contract.contractContent as any;
      const event = contract.eventId ? await storage.getEvent(contract.eventId) : null;

      const emailCompanyName = cc?.parties?.eventManager?.name || 'Event Perfekt Global Ltd';
      const emailCompanyAddress = cc?.parties?.eventManager?.address || '25 Kusenla Street, Lagos, Nigeria';
      let htmlContent = `
        <div style="font-family: 'Georgia', serif; max-width: 700px; margin: 0 auto; padding: 20px;">
          <div style="text-align: center; border-bottom: 3px solid #330311; padding-bottom: 20px; margin-bottom: 30px;">
            <h1 style="color: #330311; font-size: 24px; margin: 0;">${emailCompanyName}</h1>
            <p style="color: #666; font-size: 14px; margin: 5px 0;">${emailCompanyAddress}</p>
          </div>
          <div style="font-size: 15px; line-height: 1.8; color: #333;">
            <p>${message.replace(/\n/g, '<br/>')}</p>
          </div>`;

      if (includeContract && cc) {
        htmlContent += `
          <div style="margin-top: 30px; border-top: 2px solid #e5e5e5; padding-top: 20px;">
            <h2 style="color: #330311; font-size: 18px;">${cc.agreementTitle || 'Contract Details'}</h2>
            <table style="width: 100%; border-collapse: collapse; margin: 15px 0; font-size: 14px;">
              <tr style="border-bottom: 1px solid #ddd;">
                <td style="padding: 8px; font-weight: bold; width: 40%;">Event</td>
                <td style="padding: 8px;">${event?.name || cc.eventDetails?.eventName || 'N/A'}</td>
              </tr>
              <tr style="border-bottom: 1px solid #ddd;">
                <td style="padding: 8px; font-weight: bold;">Date</td>
                <td style="padding: 8px;">${cc.eventDetails?.eventDate || 'N/A'}</td>
              </tr>
              <tr style="border-bottom: 1px solid #ddd;">
                <td style="padding: 8px; font-weight: bold;">Contract Status</td>
                <td style="padding: 8px;">${contract.status}</td>
              </tr>
              <tr style="border-bottom: 1px solid #ddd;">
                <td style="padding: 8px; font-weight: bold;">Version</td>
                <td style="padding: 8px;">v${contract.version || 1}</td>
              </tr>
            </table>
            ${contract.status === 'draft' || contract.status === 'sent' ? `
              <div style="text-align: center; margin: 25px 0;">
                <a href="https://eventperfekt.net/contract-sign/${contract.id}" 
                   style="display: inline-block; background: #330311; color: white; padding: 12px 30px; text-decoration: none; border-radius: 6px; font-weight: bold;">
                   Review & Sign Contract
                </a>
              </div>` : ''}
          </div>`;
      }

      htmlContent += `
          <div style="margin-top: 40px; border-top: 2px solid #330311; padding-top: 15px; text-align: center; color: #888; font-size: 12px;">
            <p>${emailCompanyName} | Professional Event Management</p>
            <p>This email was sent from Event Perfekt contract management system.</p>
          </div>
        </div>`;

      const { EmailNotificationService } = await import('../emailService.js');
      const emailService = new EmailNotificationService();
      await emailService.sendEmail(to, subject, htmlContent, message);

      await storage.createContractChangeLogEntry({
        contractId: req.params.contractId,
        changedByName: (req as any).user?.fullName || 'System',
        changeType: 'sent',
        changeDescription: `Email sent to ${to} - Subject: "${subject}"`,
        fieldsChanged: [],
      });

      res.json({ success: true, message: `Email sent to ${to}` });
    } catch (error) {
      console.error("Send email error:", error);
      res.status(500).json({ message: "Failed to send email" });
    }
  });

