  app.post("/api/events/:eventId/send-activity-summary", async (req, res) => {
    try {
      const { to, subject } = req.body;
      if (!to) {
        return res.status(400).json({ message: "Email address is required" });
      }

      const summaryRes = await fetch(`${req.protocol}://${req.get('host')}/api/events/${req.params.eventId}/activity-summary`);
      const summary = await summaryRes.json();

      const summaryEvent = await storage.getEvent(req.params.eventId);
      const summaryCountry = (summaryEvent?.country || '').toLowerCase().trim();
      const summaryIsUK = summaryCountry === 'united kingdom' || summaryCountry === 'uk' || summaryCountry === 'england' || summaryCountry === 'scotland' || summaryCountry === 'wales';
      const summaryCompanyName = summaryIsUK ? 'Event Perfekt Global Ltd' : 'Event Perfekt Services Ltd';

      let personsHtml = '';
      for (const person of (summary.persons || [])) {
        personsHtml += `
          <div style="margin-bottom: 20px; border: 1px solid #e5e5e5; border-radius: 8px; padding: 15px;">
            <h3 style="color: #330311; margin: 0 0 5px;">${person.name}</h3>
            <p style="color: #666; font-size: 13px; margin: 0 0 10px;">Role: ${person.role}${person.taskCount > 0 ? ` | Tasks: ${person.completedTasks}/${person.taskCount} completed` : ''}</p>
            <ul style="margin: 0; padding-left: 20px; font-size: 14px; color: #333;">
              ${person.activities.map((a: any) => `<li style="margin-bottom: 4px;">${a.action}</li>`).join('')}
            </ul>
          </div>`;
      }

      const html = `
        <div style="font-family: 'Georgia', serif; max-width: 700px; margin: 0 auto; padding: 20px;">
          <div style="text-align: center; border-bottom: 3px solid #330311; padding-bottom: 20px; margin-bottom: 30px;">
            <h1 style="color: #330311; font-size: 24px; margin: 0;">Event Activity Summary Report</h1>
            <p style="color: #666; font-size: 14px; margin: 5px 0;">${summaryCompanyName}</p>
          </div>
          <h2 style="color: #333; margin-bottom: 15px;">${summary.eventName}</h2>
          <table style="width: 100%; border-collapse: collapse; margin: 15px 0; font-size: 14px;">
            <tr style="border-bottom: 1px solid #ddd;"><td style="padding: 8px; font-weight: bold;">Event Date</td><td style="padding: 8px;">${summary.eventDate}</td></tr>
            <tr style="border-bottom: 1px solid #ddd;"><td style="padding: 8px; font-weight: bold;">Generated</td><td style="padding: 8px;">${new Date().toLocaleDateString()}</td></tr>
            <tr style="border-bottom: 1px solid #ddd;"><td style="padding: 8px; font-weight: bold;">Tasks</td><td style="padding: 8px;">${summary.completedTasks}/${summary.totalTasks} completed</td></tr>
            <tr style="border-bottom: 1px solid #ddd;"><td style="padding: 8px; font-weight: bold;">Vendors</td><td style="padding: 8px;">${summary.totalVendors}</td></tr>
            <tr style="border-bottom: 1px solid #ddd;"><td style="padding: 8px; font-weight: bold;">Contracts</td><td style="padding: 8px;">${summary.totalContracts}</td></tr>
          </table>
          <h2 style="color: #330311; margin: 30px 0 15px;">Person Activity Breakdown</h2>
          ${personsHtml || '<p style="color: #888;">No activity recorded yet.</p>'}
          <div style="margin-top: 40px; border-top: 2px solid #330311; padding-top: 15px; text-align: center; color: #888; font-size: 12px;">
            <p>${summaryCompanyName} | Professional Event Management</p>
          </div>
        </div>`;

      const { EmailNotificationService } = await import('../emailService.js');
      const emailService = new EmailNotificationService();
      await emailService.sendEmail(to, subject || `Activity Summary Report - ${summary.eventName}`, html);
      res.json({ success: true, message: `Activity summary sent to ${to}` });
    } catch (error) {
      console.error("Send activity summary error:", error);
      res.status(500).json({ message: "Failed to send activity summary" });
    }
  });

