  app.post("/api/ai-decor/generate", async (req, res) => {
    try {
      const { eventType, eventName, colors, style, theme, budget, currency, guestCount } = req.body;

      const prompt = `You are an expert event décor planner and interior designer. Generate a comprehensive Agent-powered decor plan for an event.

Event Details:
- Name: ${eventName || "Event"}
- Type: ${eventType || "private"}
- Guest Count: ${guestCount || 100}
- Budget: ${currency || "$"}${budget || "5000"}
- Primary Colors: ${(colors || []).join(", ") || "#8B1538, #FFD700"}
- Decor Style: ${style || "Classic Elegance"}
- Theme: ${theme || "Elegant"}

Return a JSON object with this exact structure:
{
  "moodBoard": [
    {
      "title": "Color/design concept name",
      "description": "Description of this design concept",
      "tags": ["tag1", "tag2"],
      "category": "primary|accent|texture|floral|lighting"
    }
  ],
  "decorPlan": [
    {
      "category": "Centerpieces|Lighting|Linens & Fabrics|Backdrop & Staging|Reception Decor|Floral Arrangements|Table Settings|Signage",
      "item": "Specific item name",
      "priority": "essential|recommended|optional",
      "description": "Detailed description of this decor element",
      "colorMatch": 85,
      "styleMatch": 90,
      "estimatedCost": 150,
      "notes": "Additional notes or suggestions"
    }
  ],
  "colorAnalysis": {
    "primaryPalette": ["#hex1", "#hex2"],
    "complementaryColors": ["#hex1", "#hex2", "#hex3"],
    "accentColors": ["#hex1", "#hex2"],
    "neutrals": ["#hex1", "#hex2"],
    "avoidColors": ["#hex1"],
    "paletteDescription": "Description of the color harmony"
  },
  "styleNotes": "Overall design direction and key styling recommendations in 2-3 sentences"
}

Generate 5-6 mood board items and 5-8 decor plan items. Costs should be realistic for a ${eventType} event. Color hex values should complement the provided primary colors. Make the mood board creative and inspiring.`;

      const response = await fetch("https://api.openai.com/v1/chat/completions", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${process.env.AI_INTEGRATIONS_OPENAI_API_KEY || process.env.OPENAI_API_KEY || ""}`,
        },
        body: JSON.stringify({
          model: "gpt-4o-mini",
          max_tokens: 2000,
          messages: [
            { role: "system", content: "You are a professional event décor consultant. Always respond with valid JSON only, no markdown." },
            { role: "user", content: prompt },
          ],
          response_format: { type: "json_object" },
        }),
      });

      const data = await response.json() as any;
      const content = data.choices?.[0]?.message?.content;
      if (!content) {
        return res.status(500).json({ message: "No response from Agent" });
      }

      const plan = JSON.parse(content);
      res.json(plan);
    } catch (error: any) {
      console.error("Agent Decor generation error:", error?.message || error);
      res.status(500).json({ message: "Failed to generate Agent decor plan. Please try again." });
    }
  });

