  // Update an activity
  app.patch("/api/activities/:id", authenticateToken, async (req: any, res) => {
    try {
      const { id } = req.params;
      const existingActivity = await storage.getActivitiesByEventId(id);
      const currentActivity = existingActivity.find(a => a.id === id);
      
      const updatedActivity = await storage.updateActivity(id, req.body);
      if (!updatedActivity) {
        return res.status(404).json({ message: "Activity not found" });
      }

      // Log the activity update
      const changes = Object.keys(req.body);
      await storage.createActivityAuditLog({
        activityId: id,
        changedBy: req.user.id,
        changeType: "updated",
        oldValue: currentActivity ? JSON.stringify(currentActivity) : null,
        newValue: JSON.stringify(updatedActivity),
        fieldChanged: changes.join(", "),
      });

      res.json(updatedActivity);
    } catch (error: any) {
      console.error("Error updating activity:", error);
      res.status(500).json({ message: error.message });
    }
  });

