  app.get("/api/activities/:id/dependencies", authenticateToken, async (req: any, res) => {
    try {
      const deps = await db.select().from(taskDependencies).where(eq(taskDependencies.activityId, req.params.id));
      const blockedBy = await db.select().from(taskDependencies).where(eq(taskDependencies.dependsOnId, req.params.id));
      const depActivities = [];
      for (const d of deps) {
        const [act] = await db.select().from(activities).where(eq(activities.id, d.dependsOnId));
        if (act) depActivities.push({ ...d, activity: act });
      }
      const blockingActivities = [];
      for (const b of blockedBy) {
        const [act] = await db.select().from(activities).where(eq(activities.id, b.activityId));
        if (act) blockingActivities.push({ ...b, activity: act });
      }
      res.json({ dependsOn: depActivities, blocks: blockingActivities });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

