  app.post("/api/activities/:id/comments", authenticateToken, async (req: any, res) => {
    try {
      const { content } = req.body;
      if (!content?.trim()) return res.status(400).json({ message: "Content is required" });
      const mentionRegex = /@(\w+(?:\s\w+)?)/g;
      const mentions: string[] = [];
      let match;
      while ((match = mentionRegex.exec(content)) !== null) {
        mentions.push(match[1]);
      }
      const [comment] = await db.insert(taskComments).values({
        activityId: req.params.id,
        userId: req.user.id,
        userName: req.user.name || req.user.email,
        content,
        mentions,
      }).returning();

      if (mentions.length > 0) {
        const [activity] = await db.select().from(activities).where(eq(activities.id, req.params.id));
        for (const mentionName of mentions) {
          const matchedUsers = await db.select().from(users).where(
            sql`LOWER(name) LIKE LOWER(${'%' + mentionName + '%'})`
          );
          for (const mentionedUser of matchedUsers) {
            try {
              await db.insert(userNotifications).values({
                userId: mentionedUser.id,
                type: "mention",
                title: `${req.user.name || 'Someone'} mentioned you`,
                content: `In task "${activity?.taskName || 'a task'}": ${content.substring(0, 100)}`,
                isRead: false,
              });
            } catch (e) {}
          }
        }
      }

      res.json(comment);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

