  // Workflow rule execution engine - runs when activities are updated
  app.post("/api/workflow-rules/execute", authenticateToken, async (req: any, res) => {
    try {
      const { eventId, triggerType, triggerData } = req.body;
      const rules = await db.select().from(workflowRules).where(
        and(eq(workflowRules.eventId, eventId), eq(workflowRules.triggerType, triggerType), eq(workflowRules.isActive, true))
      );
      const executed: any[] = [];
      for (const rule of rules) {
        let shouldFire = false;
        const tc = rule.triggerConfig as any;

        switch (rule.triggerType) {
          case "task_completed":
            shouldFire = triggerData?.status === "completed";
            if (tc?.phase && triggerData?.phase !== tc.phase) shouldFire = false;
            break;
          case "task_overdue":
            shouldFire = triggerData?.isOverdue === true;
            break;
          case "status_changed":
            shouldFire = true;
            if (tc?.fromStatus && triggerData?.oldStatus !== tc.fromStatus) shouldFire = false;
            if (tc?.toStatus && triggerData?.newStatus !== tc.toStatus) shouldFire = false;
            break;
          case "priority_is":
            shouldFire = triggerData?.priority === (tc?.priority || "critical");
            break;
        }

        if (!shouldFire) continue;

        const ac = rule.actionConfig as any;
        let actionResult = "";

        switch (rule.actionType) {
          case "notify_team":
            actionResult = `Notification: ${ac?.message || rule.name}`;
            break;
          case "change_status":
            if (triggerData?.activityId && ac?.newStatus) {
              await db.update(activities).set({ status: ac.newStatus }).where(eq(activities.id, triggerData.activityId));
              actionResult = `Changed status to ${ac.newStatus}`;
            }
            break;
          case "assign_to":
            if (triggerData?.activityId && ac?.owner) {
              await db.update(activities).set({ owner: ac.owner }).where(eq(activities.id, triggerData.activityId));
              actionResult = `Assigned to ${ac.owner}`;
            }
            break;
          case "set_priority":
            if (triggerData?.activityId && ac?.priority) {
              await db.update(activities).set({ priority: ac.priority }).where(eq(activities.id, triggerData.activityId));
              actionResult = `Priority set to ${ac.priority}`;
            }
            break;
          case "create_task":
            if (ac?.taskName) {
              await db.insert(activities).values({
                eventId,
                taskName: ac.taskName,
                phase: ac?.phase || "planning",
                priority: ac?.priority || "medium",
                status: "not_started",
                owner: ac?.owner || "planner",
              });
              actionResult = `Created task: ${ac.taskName}`;
            }
            break;
        }

        const [log] = await db.insert(workflowRuleLog).values({
          ruleId: rule.id,
          triggeredBy: `${triggerType}: ${triggerData?.taskName || triggerData?.activityId || 'unknown'}`,
          actionTaken: `${rule.actionType}: ${actionResult}`,
          details: { triggerData, actionResult },
        }).returning();
        executed.push({ rule: rule.name, action: actionResult, log });
      }
      res.json({ executed: executed.length, results: executed });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

