  // ============ EVENT CLOSURE PACKAGE ============

  app.get("/api/events/:eventId/closure-package", authenticateToken, async (req: any, res) => {
    try {
      const { eventId } = req.params;
      const event = await storage.getEvent(eventId);
      if (!event) return res.status(404).json({ message: "Event not found" });

      const guests = await storage.getGuestsByEvent(eventId);
      const budgetItems = await storage.getBudgetItemsByEventId(eventId);
      const tasks = await storage.getTasksByEventId(eventId);
      const vendors = await storage.getVendorsByEventId(eventId);
      const notes = await storage.getEventNotesByEventId(eventId);

      const lessonsLearned = notes.filter(n => n.noteType === "lesson_learned");
      const closureNotes = notes.filter(n => n.noteType === "closure" || n.noteType === "general");
      const recommendations = notes.filter(n => n.noteType === "recommendation");

      const totalEstimated = budgetItems.reduce((s, b) => s + parseFloat(String(b.estimatedCost || 0)), 0);
      const totalActual = budgetItems.reduce((s, b) => s + parseFloat(String(b.actualCost || 0)), 0);
      const totalPaid = budgetItems.reduce((s, b) => s + parseFloat(String(b.paidAmount || 0)), 0);
      const outstanding = totalActual - totalPaid;

      const categoryBreakdown: Record<string, any> = {};
      budgetItems.forEach(b => {
        const cat = b.category || "Other";
        if (!categoryBreakdown[cat]) categoryBreakdown[cat] = { estimated: 0, actual: 0, paid: 0, count: 0 };
        categoryBreakdown[cat].estimated += parseFloat(String(b.estimatedCost || 0));
        categoryBreakdown[cat].actual += parseFloat(String(b.actualCost || 0));
        categoryBreakdown[cat].paid += parseFloat(String(b.paidAmount || 0));
        categoryBreakdown[cat].count++;
      });

      const totalTasks = tasks.length;
      const completedTasks = tasks.filter(t => t.status === "done" || t.status === "completed").length;
      const overdueTasks = tasks.filter(t => t.dueDate && new Date(t.dueDate) < new Date() && t.status !== "done" && t.status !== "completed");

      const closureChecklist = [
        { item: "All tasks completed", status: completedTasks === totalTasks && totalTasks > 0, detail: `${completedTasks}/${totalTasks} tasks done` },
        { item: "All vendor payments settled", status: budgetItems.filter(b => !b.paid).length === 0 && budgetItems.length > 0, detail: `${budgetItems.filter(b => b.paid).length}/${budgetItems.length} paid` },
        { item: "All vendor contracts signed", status: vendors.filter(v => !v.contractStatus || v.contractStatus === "pending").length === 0 && vendors.length > 0, detail: `${vendors.filter(v => v.contractStatus === "signed" || v.contractStatus === "confirmed").length}/${vendors.length}` },
        { item: "Guest check-in complete", status: guests.filter(g => g.checkedIn).length >= guests.filter(g => g.rsvpStatus === "accepted").length && guests.length > 0, detail: `${guests.filter(g => g.checkedIn).length}/${guests.filter(g => g.rsvpStatus === "accepted").length} checked in` },
        { item: "Client contract signed", status: !!event.contractSigned, detail: event.contractSigned ? "Signed" : "Pending" },
        { item: "Client deposit received", status: !!event.depositPaid, detail: event.depositPaid ? "Received" : "Pending" },
        { item: "Budget within estimate", status: totalActual <= totalEstimated || totalEstimated === 0, detail: totalEstimated > 0 ? `${((totalActual / totalEstimated) * 100).toFixed(0)}% of budget` : "No budget set" },
        { item: "All RSVPs received", status: guests.filter(g => g.rsvpStatus === "pending").length === 0 && guests.length > 0, detail: `${guests.filter(g => g.rsvpStatus === "pending").length} pending` },
        { item: "Lessons learned documented", status: lessonsLearned.length > 0, detail: `${lessonsLearned.length} lessons recorded` },
        { item: "Final reconciliation complete", status: outstanding <= 0, detail: outstanding > 0 ? `Outstanding: ${outstanding.toFixed(2)}` : "Fully settled" },
      ];

      const closurePackage = {
        generatedAt: new Date().toISOString(),
        event: {
          id: event.id, name: event.name, type: event.type, category: event.eventCategory,
          status: event.status, startDate: event.startDate, endDate: event.endDate,
          country: event.country, city: event.city, currency: event.currency || "GBP",
          budget: event.budget, guestCount: event.guestCount,
          ceremonyVenue: event.ceremonyVenue, receptionVenue: event.receptionVenue,
          afterPartyVenue: event.afterPartyVenue, currentPhase: event.currentPhase,
          timelineProgress: event.timelineProgress, contractSigned: event.contractSigned,
          depositPaid: event.depositPaid,
        },
        financials: {
          totalEstimated, totalActual, totalPaid, outstanding,
          variance: totalEstimated - totalActual,
          variancePercent: totalEstimated > 0 ? ((totalEstimated - totalActual) / totalEstimated * 100).toFixed(1) : "0",
          categoryBreakdown,
          unpaidItems: budgetItems.filter(b => !b.paid).map(b => ({ name: b.item, category: b.category, amount: b.actualCost || b.estimatedCost })),
          overBudgetItems: budgetItems.filter(b => parseFloat(String(b.actualCost || 0)) > parseFloat(String(b.estimatedCost || 0)) && parseFloat(String(b.estimatedCost || 0)) > 0).map(b => ({
            name: b.item, category: b.category, estimated: b.estimatedCost, actual: b.actualCost, over: parseFloat(String(b.actualCost || 0)) - parseFloat(String(b.estimatedCost || 0))
          })),
        },
        guestSummary: {
          total: guests.length,
          accepted: guests.filter(g => g.rsvpStatus === "accepted").length,
          declined: guests.filter(g => g.rsvpStatus === "declined").length,
          pending: guests.filter(g => g.rsvpStatus === "pending").length,
          tentative: guests.filter(g => g.rsvpStatus === "tentative").length,
          checkedIn: guests.filter(g => g.checkedIn).length,
          totalWithPlusOnes: guests.reduce((s, g) => s + 1 + (g.plusOnes || 0), 0),
          noShows: guests.filter(g => g.rsvpStatus === "accepted" && !g.checkedIn).length,
          tables: new Set(guests.filter(g => g.tableAssignment).map(g => g.tableAssignment)).size,
        },
        taskSummary: {
          total: totalTasks, completed: completedTasks,
          inProgress: tasks.filter(t => t.status === "in_progress" || t.status === "in-progress").length,
          todo: tasks.filter(t => t.status === "todo" || t.status === "not_started" || t.status === "pending").length,
          overdue: overdueTasks.length,
          completionRate: totalTasks > 0 ? Math.round(completedTasks / totalTasks * 100) : 0,
          overdueList: overdueTasks.map(t => ({ title: t.title, dueDate: t.dueDate, status: t.status })),
        },
        vendorSummary: {
          total: vendors.length,
          confirmed: vendors.filter(v => v.contractStatus === "signed" || v.contractStatus === "confirmed").length,
          pending: vendors.filter(v => !v.contractStatus || v.contractStatus === "pending").length,
          totalQuoted: vendors.reduce((s, v) => s + parseFloat(String(v.quotedAmount || 0)), 0),
          totalFinal: vendors.reduce((s, v) => s + parseFloat(String(v.finalAmount || 0)), 0),
          totalDeposit: vendors.reduce((s, v) => s + parseFloat(String(v.depositAmount || 0)), 0),
          vendors: vendors.map(v => ({
            company: v.companyName, service: v.serviceType, quoted: v.quotedAmount,
            final: v.finalAmount, deposit: v.depositAmount, paymentStatus: v.paymentStatus,
            contractStatus: v.contractStatus, priority: v.priority,
          })),
        },
        lessonsLearned,
        closureNotes,
        recommendations,
        closureChecklist,
        allBudgetItems: budgetItems.map(b => ({
          name: b.item, category: b.category, estimated: b.estimatedCost,
          actual: b.actualCost, paid: b.paidAmount, isPaid: b.paid, dueDate: b.dueDate,
        })),
        guestList: guests.map(g => ({
          name: `${g.firstName} ${g.lastName}`, group: g.group, rsvpStatus: g.rsvpStatus,
          checkedIn: g.checkedIn, table: g.tableAssignment, plusOnes: g.plusOnes,
          dietary: g.dietaryRequirements, meal: g.mealChoice,
        })),
      };

      res.json(closurePackage);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

