  app.post("/api/events/:eventId/guests/bulk-assign-tables", authenticateToken, async (req: any, res) => {
    try {
      const { assignments } = req.body;
      if (!Array.isArray(assignments)) {
        return res.status(400).json({ message: "assignments must be an array of { guestId, tableAssignment }" });
      }
      const results = await Promise.all(
        assignments.map((a: { guestId: string; tableAssignment: string }) =>
          storage.updateGuest(a.guestId, { tableAssignment: a.tableAssignment })
        )
      );
      res.json({ updated: results.length });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.post("/api/events/:eventId/guests/auto-assign-tables", authenticateToken, async (req: any, res) => {
    try {
      const { perTable = 10, tablePrefix = "Table", startFrom = 1, onlyUnassigned = true } = req.body;
      const guestList = await storage.getGuestsByEvent(req.params.eventId);
      const toAssign = onlyUnassigned
        ? guestList.filter(g => !g.tableAssignment || g.tableAssignment.trim() === "")
        : guestList;

      if (toAssign.length === 0) {
        return res.json({ message: "No guests to assign", assigned: 0 });
      }

      let tableNumber = startFrom;
      let seatCount = 0;
      const assignments: { guestId: string; tableAssignment: string }[] = [];

      for (const guest of toAssign) {
        if (seatCount >= perTable) {
          tableNumber++;
          seatCount = 0;
        }
        assignments.push({ guestId: guest.id as string, tableAssignment: `${tablePrefix} ${tableNumber}` });
        seatCount++;
      }

      await Promise.all(
        assignments.map(a => storage.updateGuest(a.guestId, { tableAssignment: a.tableAssignment }))
      );

      const totalTables = tableNumber - startFrom + 1;
      res.json({ assigned: assignments.length, tables: totalTables, perTable });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.patch("/api/guests/:guestId", authenticateToken, async (req: any, res) => {
    try {
      const extendedFields = ['travel_details', 'accommodation', 'arrival_date', 'departure_date', 'transport_needed', 'gift_description', 'gift_received_at', 'thank_you_sent'];
      const hasExtendedFields = extendedFields.some(f => req.body[f] !== undefined);

      if (hasExtendedFields) {
        const guestId = req.params.guestId;
        if (req.body.travel_details !== undefined) await db.execute(sql`UPDATE guests SET travel_details = ${req.body.travel_details} WHERE id = ${guestId}`);
        if (req.body.accommodation !== undefined) await db.execute(sql`UPDATE guests SET accommodation = ${req.body.accommodation} WHERE id = ${guestId}`);
        if (req.body.arrival_date !== undefined) await db.execute(sql`UPDATE guests SET arrival_date = ${req.body.arrival_date} WHERE id = ${guestId}`);
        if (req.body.departure_date !== undefined) await db.execute(sql`UPDATE guests SET departure_date = ${req.body.departure_date} WHERE id = ${guestId}`);
        if (req.body.transport_needed !== undefined) await db.execute(sql`UPDATE guests SET transport_needed = ${req.body.transport_needed} WHERE id = ${guestId}`);
        if (req.body.gift_description !== undefined) await db.execute(sql`UPDATE guests SET gift_description = ${req.body.gift_description} WHERE id = ${guestId}`);
        if (req.body.gift_received_at !== undefined) await db.execute(sql`UPDATE guests SET gift_received_at = ${req.body.gift_received_at} WHERE id = ${guestId}`);
        if (req.body.thank_you_sent !== undefined) await db.execute(sql`UPDATE guests SET thank_you_sent = ${req.body.thank_you_sent} WHERE id = ${guestId}`);

        const drizzleFields: any = {};
        Object.keys(req.body).forEach(k => {
          if (!extendedFields.includes(k)) drizzleFields[k] = req.body[k];
        });
        if (Object.keys(drizzleFields).length > 0) {
          await storage.updateGuest(guestId, drizzleFields);
        }
        const result = await db.execute(sql`SELECT * FROM guests WHERE id = ${guestId}`);
        res.json(result.rows[0] || {});
      } else {
        const updated = await storage.updateGuest(req.params.guestId, req.body);
        res.json(updated);
      }
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

