  // ============================================================================

  app.get("/api/events/:eventId/guests/checkin-analytics", authenticateToken, requireEventAccess(), async (req: any, res) => {
    try {
      const guestList = await storage.getGuestsByEvent(req.params.eventId);
      const accepted = guestList.filter(g => g.rsvpStatus === 'accepted' || g.rsvpStatus === 'attending');
      const checkedIn = guestList.filter(g => g.checkedIn);
      const notCheckedIn = accepted.filter(g => !g.checkedIn);
      const timeline: Record<string, number> = {};
      checkedIn.forEach(g => {
        if (g.checkedInAt) {
          const d = new Date(g.checkedInAt);
          const slot = `${d.getHours().toString().padStart(2, '0')}:${(Math.floor(d.getMinutes() / 15) * 15).toString().padStart(2, '0')}`;
          timeline[slot] = (timeline[slot] || 0) + 1;
        }
      });
      res.json({
        total_expected: accepted.length,
        total_all_guests: guestList.length,
        checked_in: checkedIn.length,
        remaining: notCheckedIn.length,
        check_in_rate: accepted.length > 0 ? Math.round((checkedIn.length / accepted.length) * 100) : 0,
        timeline: Object.entries(timeline).sort(([a], [b]) => a.localeCompare(b)).map(([time, count]) => ({ time, count })),
        still_missing: notCheckedIn.map(g => ({ id: g.id, firstName: g.firstName, lastName: g.lastName, group: g.group, tableAssignment: g.tableAssignment }))
      });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // ============================================================================
  // CATERING REPORT
  // ============================================================================

  app.get("/api/events/:eventId/guests/catering-report", authenticateToken, requireEventAccess(), async (req: any, res) => {
    try {
      const guestList = await storage.getGuestsByEvent(req.params.eventId);
      const attending = guestList.filter(g => g.rsvpStatus === 'accepted' || g.rsvpStatus === 'attending' || g.rsvpStatus === 'pending');
      const plusOnesResult = await db.execute(sql`SELECT * FROM plus_one_guests WHERE event_id = ${req.params.eventId}`);
      const plusOnes = plusOnesResult.rows as any[];

      const dietaryGroups: Record<string, { count: number; guests: string[] }> = {};
      const mealGroups: Record<string, { count: number; guests: string[] }> = {};

      attending.forEach(g => {
        const diet = g.dietaryRequirements || 'None specified';
        if (!dietaryGroups[diet]) dietaryGroups[diet] = { count: 0, guests: [] };
        dietaryGroups[diet].count++;
        dietaryGroups[diet].guests.push(`${g.firstName} ${g.lastName}`);

        const meal = g.mealChoice || 'No preference';
        if (!mealGroups[meal]) mealGroups[meal] = { count: 0, guests: [] };
        mealGroups[meal].count++;
        mealGroups[meal].guests.push(`${g.firstName} ${g.lastName}`);
      });

      plusOnes.forEach(p => {
        const diet = p.dietary_requirements || 'None specified';
        if (!dietaryGroups[diet]) dietaryGroups[diet] = { count: 0, guests: [] };
        dietaryGroups[diet].count++;
        dietaryGroups[diet].guests.push(`${p.name} (plus-one)`);

        const meal = p.meal_choice || 'No preference';
        if (!mealGroups[meal]) mealGroups[meal] = { count: 0, guests: [] };
        mealGroups[meal].count++;
        mealGroups[meal].guests.push(`${p.name} (plus-one)`);
      });

      res.json({
        total_attending: attending.length,
        total_plus_ones: plusOnes.length,
        total_covers: attending.length + plusOnes.length,
        dietary_breakdown: dietaryGroups,
        meal_breakdown: mealGroups
      });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // ============================================================================
  // SEGMENTED GROUP MESSAGING
  // ============================================================================

  app.post("/api/events/:eventId/guests/send-segment-message", authenticateToken, requireEventAccess(), async (req: any, res) => {
    try {
      const { segment_type, segment_value, channel, message_template } = req.body;
      if (!segment_type || !message_template) return res.status(400).json({ message: "Segment type and message are required" });

      const guestList = await storage.getGuestsByEvent(req.params.eventId);
      const event = await storage.getEvent(req.params.eventId);
      let filtered = guestList;

      if (segment_type === 'status') {
        if (segment_value === 'not_responded') filtered = guestList.filter(g => g.rsvpStatus === 'pending');
        else filtered = guestList.filter(g => g.rsvpStatus === segment_value);
      } else if (segment_type === 'table') {
        filtered = guestList.filter(g => g.tableAssignment === segment_value);
      } else if (segment_type === 'group') {
        filtered = guestList.filter(g => g.group === segment_value);
      }

      const results = [];
      for (const guest of filtered) {
        const personalizedMsg = message_template
          .replace(/\{name\}/g, `${guest.firstName} ${guest.lastName}`)
          .replace(/\{first_name\}/g, guest.firstName)
          .replace(/\{table\}/g, guest.tableAssignment || 'TBD')
          .replace(/\{event_name\}/g, event?.name || 'the event');

        try {
          if (channel === 'email' && guest.email) {
            await sendEmail(guest.email, `Message from ${event?.name || 'Event'}`, `<p>${personalizedMsg.replace(/\n/g, '<br>')}</p>`);
          }
          await db.execute(sql`
            INSERT INTO guest_communications (event_id, guest_id, guest_name, channel, message_preview, sent_by, status)
            VALUES (${req.params.eventId}, ${guest.id}, ${guest.firstName + ' ' + guest.lastName}, ${channel || 'email'}, ${personalizedMsg.substring(0, 200)}, ${req.user.name || 'Unknown'}, 'sent')
          `);
          results.push({ guestId: guest.id, name: `${guest.firstName} ${guest.lastName}`, message: personalizedMsg, status: 'sent' });
        } catch (err) {
          results.push({ guestId: guest.id, name: `${guest.firstName} ${guest.lastName}`, message: personalizedMsg, status: 'failed', error: (err as any).message });
        }
      }

      res.json({ sent: results.filter(r => r.status === 'sent').length, total: results.length, recipients: results });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

