  app.post("/api/events/:eventId/guests/send-digital-invitations", authenticateToken, async (req: any, res) => {
    try {
      const { eventId } = req.params;
      const { guestIds, subject, message } = req.body;

      const event = await storage.getEvent(eventId);
      if (!event) return res.status(404).json({ message: "Event not found" });

      const allGuests = await storage.getGuestsByEvent(eventId);
      const targetGuests = guestIds?.length
        ? allGuests.filter(g => guestIds.includes(g.id))
        : allGuests.filter(g => g.email && !g.invitationSent);

      let sentCount = 0;
      let failedCount = 0;
      const prodDomain = process.env.PRODUCTION_DOMAIN || "eventperfekt.net";
      const baseUrl = `https://${prodDomain}`;

      for (const guest of targetGuests) {
        if (!guest.email) { failedCount++; continue; }
        try {
          const rsvpUrl = guest.rsvpToken ? `${baseUrl}/rsvp/${guest.rsvpToken}` : baseUrl;
          const eventDate = event.startDate ? new Date(event.startDate).toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }) : 'TBC';

          await sendEmail(
            guest.email,
            subject || `You're Invited: ${event.name}`,
            `
            <div style="font-family: 'Georgia', serif; max-width: 640px; margin: 0 auto; background: #ffffff;">
              <div style="background: linear-gradient(135deg, #330311, #8B1538, #4a0a20); padding: 50px 40px; text-align: center;">
                <p style="color: rgba(255,255,255,0.5); font-size: 10px; letter-spacing: 4px; text-transform: uppercase; margin: 0 0 16px 0;">You are cordially invited</p>
                <h1 style="color: #ffffff; font-size: 28px; margin: 0; font-weight: normal; letter-spacing: 1px;">${event.name}</h1>
                <div style="width: 60px; height: 1px; background: rgba(255,255,255,0.3); margin: 20px auto;"></div>
                <p style="color: rgba(255,255,255,0.7); font-size: 14px; margin: 0;">${eventDate}</p>
              </div>
              <div style="padding: 40px;">
                <p style="color: #333; font-size: 15px; line-height: 1.8;">Dear ${guest.firstName} ${guest.lastName || ''},</p>
                <p style="color: #555; font-size: 14px; line-height: 1.8;">${message || `We are delighted to invite you to ${event.name}. Your presence would make this occasion truly special.`}</p>
                ${event.ceremonyVenue || event.receptionVenue ? `
                  <div style="background: #faf8f5; padding: 20px; border-radius: 8px; margin: 24px 0; border-left: 3px solid #8B1538;">
                    <p style="color: #8B1538; font-size: 11px; letter-spacing: 2px; text-transform: uppercase; margin: 0 0 8px 0; font-weight: bold;">Venue</p>
                    <p style="color: #333; font-size: 14px; margin: 0;">${event.ceremonyVenue || event.receptionVenue}</p>
                  </div>
                ` : ''}
                <div style="text-align: center; margin: 32px 0;">
                  <a href="${rsvpUrl}" style="display: inline-block; background: #8B1538; color: #ffffff; text-decoration: none; padding: 14px 40px; border-radius: 6px; font-size: 14px; letter-spacing: 1px;">RSVP Now</a>
                </div>
                <p style="color: #999; font-size: 12px; text-align: center;">Please respond by clicking the button above</p>
              </div>
              <div style="background: #330311; padding: 24px; text-align: center;">
                <p style="color: rgba(255,255,255,0.7); font-size: 12px; margin: 0;">Event Perfekt</p>
                <p style="color: rgba(255,255,255,0.4); font-size: 10px; font-style: italic; margin: 4px 0 0 0;">...making yours perfekt</p>
              </div>
            </div>
            `
          );
          await storage.updateGuest(guest.id, { invitationSent: true } as any);
          sentCount++;
        } catch (err) {
          console.error(`Failed to send invitation to ${guest.email}:`, err);
          failedCount++;
        }
      }

      res.json({ sent: sentCount, failed: failedCount, total: targetGuests.length });
    } catch (error) {
      console.error("Digital invitation send error:", error);
      res.status(500).json({ message: "Failed to send digital invitations" });
    }
  });

