  app.get("/api/artifacts/:id/download", authenticateToken, async (req: any, res) => {
    try {
      const { id } = req.params;
      const artifact = await storage.getArtifact(id);
      if (!artifact) {
        return res.status(404).json({ message: "Artifact not found" });
      }
      const fs = await import('fs');
      if (fs.existsSync(artifact.filePath)) {
        res.setHeader('Content-Disposition', `attachment; filename="${artifact.originalName}"`);
        res.setHeader('Content-Type', artifact.mimeType || 'application/octet-stream');
        fs.createReadStream(artifact.filePath).pipe(res);
      } else {
        res.status(404).json({ message: "File not found on disk" });
      }
    } catch (error) {
      console.error("Error downloading artifact:", error);
      res.status(500).json({ message: "Failed to download artifact" });
    }
  });

