  // Helper: get current admin user from request
  function getAdminUser(req: any): { id: string; name: string; email: string } {
    const u = req.user || {};
    return {
      id: u.id || u.userId || 'unknown',
      name: u.name || u.email || 'Unknown Admin',
      email: u.email || 'unknown@eventperfekt.com',
    };
  }

  // Helper: log every action to audit trail + update booking lastAction fields
  async function logBookingAction(
    bookingId: string,
    action: string,
    req: any,
    details?: string,
    oldValue?: string,
    newValue?: string
  ) {
    const admin = getAdminUser(req);
    try {
      await storage.createBoothBookingAuditLog({
        bookingId,
        action,
        performedBy: admin.name,
        performedById: admin.id,
        details: details || action,
        oldValue,
        newValue,
      });
      await storage.updateBoothBooking(bookingId, {
        lastActionAt: new Date(),
        lastActionBy: admin.name,
        lastActionType: action,
        updatedBy: admin.name,
      });
    } catch (e: any) {
      console.error("[AuditLog] Failed to log:", e.message);
    }
  }

  app.post("/api/booth-bookings", optionalAuth, async (req: any, res) => {
    try {
      const parsed = insertBoothBookingSchema.safeParse(req.body);
      if (!parsed.success) {
        return res.status(400).json({ message: "Invalid booking data", errors: parsed.error.format() });
      }
      const token = randomBytes(16).toString('hex');
      const admin = getAdminUser(req);
      const booking = await storage.createBoothBooking({
        ...parsed.data,
        token,
        status: 'pending',
        paymentStatus: 'unpaid',
        createdBy: admin.name,
        updatedBy: admin.name,
        createdAt: new Date(),
      });
      await logBookingAction(booking.id, 'create_booking', req, `Booking created by ${admin.name} for ${parsed.data.clientName}`);
      return res.status(201).json(booking);
    } catch (error: any) {
      console.error("[BoothBooking] Create error:", error);
      return res.status(500).json({ message: error.message || "Failed to create booking" });
    }
  });

