  app.post("/api/booth-bookings/:token/accept", optionalAuth, async (req, res) => {
    try {
      const { signedName, agreementAccepted, paymentMethod } = req.body;
      if (!signedName || !agreementAccepted) {
        return res.status(400).json({ message: "Signature and agreement acceptance required" });
      }
      const booking = await storage.getBoothBooking(req.params.token);
      if (!booking) return res.status(404).json({ message: "Booking not found" });
      if (booking.status !== 'pending') {
        return res.status(400).json({ message: `Booking already ${booking.status}` });
      }
      const updated = await storage.updateBoothBooking(booking.id, {
        signedName,
        agreementAccepted,
        signedIp: req.ip || req.headers['x-forwarded-for'] || 'unknown',
        signedUserAgent: req.headers['user-agent'] || '',
        agreementAcceptedAt: new Date(),
        status: 'accepted',
        paymentMethod: paymentMethod || booking.paymentMethod || null,
      });
      await logBookingAction(booking.id, 'client_accept_agreement', req,
        `Client ${signedName} accepted agreement via ${paymentMethod || 'bank_transfer'}`,
        booking.status, 'accepted'
      );
      res.json(updated);
    } catch (error: any) {
      console.error("[BoothBooking] Accept error:", error);
      res.status(500).json({ message: error.message || "Failed to accept booking" });
    }
  });

