  // STEP 3: Admin Approve & Send to Client
  app.post("/api/booth-bookings/:token/approve-send", optionalAuth, async (req, res) => {
    try {
      const booking = await storage.getBoothBooking(req.params.token);
      if (!booking) return res.status(404).json({ message: "Booking not found" });
      if (!booking.reviewEmailHtml || !booking.reviewEmailType) {
        return res.status(400).json({ message: "No draft email available for this booking. Generate a quote or invoice first." });
      }
      if (booking.adminReviewStatus === "approved") {
        return res.status(400).json({ message: "This email was already approved and sent to the client." });
      }

      const { emailType } = req.body; // "quote", "invoice", "confirmation"
      const type = emailType || booking.reviewEmailType;
      const subject = type === "quote"
        ? `Your 360 Booth Hire Quote — Event Perfekt`
        : type === "invoice"
        ? `Invoice ${booking.invoiceNumber || "EPB-" + new Date().getFullYear()} — Event Perfekt 360 Booth Hire`
        : `Your Event Perfekt 360 Booth Hire Confirmation`;

      // NOW send to client (ONLY after admin approval)
      await sendEmail(booking.clientEmail, subject, booking.reviewEmailHtml);
      console.log(`✅ [APPROVED] ${type} email sent to client ${booking.clientEmail}`);

      // Update status
      const statusUpdates: any = {
        adminReviewStatus: "approved",
        quoteSent: type === "quote" ? true : booking.quoteSent,
        updatedAt: new Date(),
      };
      if (type === "quote") statusUpdates.status = "quote_sent";
      if (type === "invoice") statusUpdates.status = "awaiting_deposit";

      await storage.updateBoothBooking(booking.id, statusUpdates);
      await logBookingAction(booking.id, 'approve_send_' + type, req,
        `${type.charAt(0).toUpperCase() + type.slice(1)} approved by admin and sent to client ${booking.clientEmail}`,
        booking.adminReviewStatus, 'approved'
      );
      res.json({
        success: true,
        message: `✅ ${type.charAt(0).toUpperCase() + type.slice(1)} approved and sent to ${booking.clientEmail}`,
        sentTo: booking.clientEmail,
      });
    } catch (error: any) {
      console.error("[BoothBooking] Approve-send error:", error);
      res.status(500).json({ message: error.message || "Failed to approve and send" });
    }
  });

