  app.get("/api/my-assignments", authenticateToken, async (req: any, res) => {
    try {
      const userEmail = req.user.email;
      const userName = req.user.fullName || req.user.email;
      
      // Get resource assignments
      const assignments = await db.select().from(eventResources)
        .where(or(
          eq(eventResources.email, userEmail),
          eq(eventResources.name, userName)
        ))
        .orderBy(desc(eventResources.createdAt));

      const enriched = await Promise.all(assignments.map(async (a: any) => {
        const [event] = await db.select({ name: events.name, date: events.startDate }).from(events).where(eq(events.id, a.eventId));
        return { ...a, eventName: event?.name || "Unknown Event", eventDate: event?.date, type: 'resource_assignment' };
      }));
      
      // Get calendar entries (meetings, reminders) where user is an attendee
      const calendarResult = await db.execute(sql`
        SELECT ce.*, e.name as event_name, u.name as creator_name
        FROM calendar_entries ce
        LEFT JOIN events e ON ce.event_id = e.id
        LEFT JOIN users u ON ce.created_by = u.id
        WHERE ce.attendees::text ILIKE ${'%' + userEmail + '%'} 
          OR ce.attendees::text ILIKE ${'%' + userName + '%'}
        ORDER BY ce.start_date DESC
      `);
      
      const calendarEntries = (calendarResult.rows || []).map((cal: any) => ({
        id: cal.id,
        eventId: cal.event_id,
        eventName: cal.event_name || 'No Event',
        title: cal.title,
        description: cal.description,
        type: 'calendar_entry',
        startDate: cal.start_date,
        endDate: cal.end_date,
        status: cal.status,
        location: cal.location,
        meetingLink: cal.meeting_link,
        meetingPlatform: cal.meeting_platform,
        creatorName: cal.creator_name
      }));
      
      // Combine both and sort by date
      const combined = [...enriched, ...calendarEntries].sort((a: any, b: any) => {
        const dateA = new Date(a.eventDate || a.startDate || 0).getTime();
        const dateB = new Date(b.eventDate || b.startDate || 0).getTime();
        return dateB - dateA;
      });
      
      res.json(combined);
    } catch (error: any) {
      console.error("Fetch my assignments error:", error);
      res.status(500).json({ message: "Failed to fetch assignments" });
    }
  });

  app.patch("/api/my-assignments/:id/status", authenticateToken, async (req: any, res) => {
    try {
      const { id } = req.params;
      const { status, resolutionNotes } = req.body;
      const validStatuses = ["pending", "confirmed", "completed", "cancelled"];
      if (!status || !validStatuses.includes(status)) {
        return res.status(400).json({ message: "Invalid status. Must be: " + validStatuses.join(", ") });
      }
      const userEmail = req.user.email;
      const userName = req.user.fullName || req.user.email;
      const [assignment] = await db.select().from(eventResources).where(eq(eventResources.id, id));
      if (!assignment) return res.status(404).json({ message: "Assignment not found" });
      const isOwner = assignment.email === userEmail || assignment.name === userName;
      const isAdmin = req.user.role === "admin" || req.user.role === "planner";
      if (!isOwner && !isAdmin) return res.status(403).json({ message: "You can only update your own assignments" });
      const updateData: any = { status, updatedAt: new Date() };
      if (resolutionNotes) updateData.resolutionNotes = resolutionNotes;
      if (status === "completed") updateData.completedAt = new Date();
      const [updated] = await db.update(eventResources).set(updateData).where(eq(eventResources.id, id)).returning();
      res.json(updated);
    } catch (error: any) {
      console.error("Update assignment status error:", error);
      res.status(500).json({ message: "Failed to update assignment status" });
    }
  });

  app.post("/api/events/:eventId/resources", authenticateToken, async (req: any, res) => {
    try {
      const { eventId } = req.params;
      const parsed = insertEventResourceSchema.safeParse({
        ...req.body,
        eventId,
        assignedBy: req.user.id,
      });
      if (!parsed.success) {
        return res.status(400).json({ message: "Validation failed", errors: parsed.error.flatten().fieldErrors });
      }
      const [resource] = await db.insert(eventResources).values(parsed.data).returning();

      if (resource.email) {
        const [assignedUser] = await db.select().from(users).where(eq(users.email, resource.email));
        if (assignedUser) {
          const [event] = await db.select({ name: events.name }).from(events).where(eq(events.id, eventId));
          const eventName = event?.name || "an event";
          try {
            await notificationService.sendNotification({
              userId: assignedUser.id,
              eventId,
              type: 'timeline_update',
              title: `New Assignment: ${resource.role}`,
              message: `You have been assigned as ${resource.role} for ${eventName}. ${resource.shift ? `Shift: ${resource.shift}.` : ""} ${resource.startDate ? `Starting: ${resource.startDate}.` : ""}`,
            });
          } catch (e) {
            console.log("Non-critical: notification send failed", e);
          }
        }
      }

      res.status(201).json(resource);
    } catch (error: any) {
      console.error("Create event resource error:", error);
      res.status(500).json({ message: "Failed to create event resource" });
    }
  });

