  app.get("/api/events/:eventId/resources/summary", authenticateToken, async (req: any, res) => {
    try {
      const { eventId } = req.params;
      const resources = await db.select().from(eventResources)
        .where(eq(eventResources.eventId, eventId));

      const summary = {
        totalStaff: resources.reduce((sum, r) => sum + (r.quantity || 1), 0),
        totalCost: resources.reduce((sum, r) => {
          const rate = r.ratePerUnit ? parseFloat(r.ratePerUnit) : 0;
          return sum + (rate * (r.quantity || 1));
        }, 0),
        byRole: {} as Record<string, { count: number; cost: number }>,
        byStatus: { pending: 0, confirmed: 0, cancelled: 0, completed: 0 } as Record<string, number>,
      };

      resources.forEach(r => {
        if (!summary.byRole[r.role]) {
          summary.byRole[r.role] = { count: 0, cost: 0 };
        }
        summary.byRole[r.role].count += r.quantity || 1;
        summary.byRole[r.role].cost += (r.ratePerUnit ? parseFloat(r.ratePerUnit) : 0) * (r.quantity || 1);
        summary.byStatus[r.status] = (summary.byStatus[r.status] || 0) + (r.quantity || 1);
      });

      res.json(summary);
    } catch (error: any) {
      console.error("Resource summary error:", error);
      res.status(500).json({ message: "Failed to generate resource summary" });
    }
  });

