  app.get("/api/canva/auth", authenticateToken, (req: any, res) => {
    try {
      if (!CanvaService.isConfigured()) {
        return res.status(503).json({ message: "Canva integration not configured" });
      }

      const prodDomain = process.env.PRODUCTION_DOMAIN || "eventperfekt.net";
      const baseUrl = `https://${prodDomain}`;
      const redirectUri = `${baseUrl}/api/canva/callback`;

      const { url } = CanvaService.getAuthorizationUrl(req.user.id.toString(), redirectUri);
      res.json({ authUrl: url });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.get("/api/canva/callback", async (req, res) => {
    try {
      const { code, state } = req.query;
      if (!code || !state) {
        return res.redirect('/invitations/designer?canva_error=missing_params');
      }

      const prodDomain = process.env.PRODUCTION_DOMAIN || "eventperfekt.net";
      const baseUrl = `https://${prodDomain}`;
      const redirectUri = `${baseUrl}/api/canva/callback`;

      await CanvaService.exchangeCodeForToken(
        code as string,
        state as string,
        redirectUri
      );

      res.redirect('/invitations/designer?canva_connected=true');
    } catch (error: any) {
      console.error("Canva auth error:", error);
      res.redirect(`/invitations/designer?canva_error=${encodeURIComponent(error.message)}`);
    }
  });

