          description: `Co-planner removed: ${collaborator.name || collaborator.email}`,
          entityType: 'collaborator',
          entityId: collaborator.id,
          entityName: collaborator.name || collaborator.email,
          changedByName: 'Planner',
          priority: 'low',
          tags: ['co-planning', 'removed', 'team'],
