  app.get("/api/staff-monitoring", authenticateToken, requireRole(["admin", "planner"]), async (req: any, res) => {
    try {
      const { period } = req.query;
      let interval = "7 days";
      if (period === "today") interval = "1 day";
      else if (period === "week") interval = "7 days";
      else if (period === "month") interval = "30 days";

      const onlineNow = await db.execute(sql`
        SELECT user_id, user_name, user_role, last_seen
        FROM user_presence
        WHERE last_seen > now() - interval '2 minutes'
        ORDER BY last_seen DESC
      `);

      const sessions = await db.execute(sql`
        SELECT user_id, user_name, user_role, login_at, logout_at, duration_minutes, ip_address
        FROM staff_sessions
        WHERE login_at > now() - ${sql.raw(`interval '${interval}'`)}
        ORDER BY login_at DESC
        LIMIT 200
      `);

      const sessionSummary = await db.execute(sql`
        SELECT user_id, user_name, user_role,
          COUNT(*) as total_sessions,
          COALESCE(SUM(duration_minutes), 0) as total_minutes,
          COALESCE(ROUND(AVG(duration_minutes)), 0) as avg_session_minutes,
          MAX(login_at) as last_login
        FROM staff_sessions
        WHERE login_at > now() - ${sql.raw(`interval '${interval}'`)}
        GROUP BY user_id, user_name, user_role
        ORDER BY total_minutes DESC
      `);

      const taskTimerSummary = await db.execute(sql`
        SELECT user_id, user_name, task_title, event_name,
          started_at, stopped_at, duration_minutes, notes
        FROM task_timers
        WHERE started_at > now() - ${sql.raw(`interval '${interval}'`)}
        ORDER BY started_at DESC
        LIMIT 200
      `);

      const taskTimerByUser = await db.execute(sql`
        SELECT user_id, user_name,
          COUNT(*) as tasks_timed,
          COALESCE(SUM(duration_minutes), 0) as total_task_minutes,
          COALESCE(ROUND(AVG(duration_minutes)), 0) as avg_task_minutes
        FROM task_timers
        WHERE started_at > now() - ${sql.raw(`interval '${interval}'`)} AND stopped_at IS NOT NULL
        GROUP BY user_id, user_name
        ORDER BY total_task_minutes DESC
      `);

      const activeTimers = await db.execute(sql`
        SELECT user_id, user_name, task_title, event_name, started_at
        FROM task_timers
        WHERE stopped_at IS NULL
      `);

      res.json({
        onlineNow: onlineNow.rows || [],
        sessions: sessions.rows || [],
        sessionSummary: sessionSummary.rows || [],
        taskTimers: taskTimerSummary.rows || [],
        taskTimerByUser: taskTimerByUser.rows || [],
        activeTimers: activeTimers.rows || [],
      });
    } catch (error) {
      console.error("Staff monitoring error:", error);
      res.status(500).json({ message: "Failed to fetch monitoring data" });
    }
  });

