  app.post("/api/events/:eventId/generate-invoice", authenticateToken, async (req: any, res) => {
    try {
      const { eventId } = req.params;
      const { clientId, dueDate, type, taxes } = req.body;

      const eventResult = await db.execute(sql`SELECT * FROM events WHERE id = ${eventId}`);
      const event = eventResult.rows[0] as any;
      if (!event) return res.status(404).json({ message: "Event not found" });

      const budgetResult = await db.execute(sql`SELECT * FROM budget_items WHERE event_id = ${eventId} ORDER BY category, item`);
      const budgetItems = budgetResult.rows as any[];

      const lineItems: any[] = [];

      const serviceMap: Record<string, string> = {
        needs_end_to_end_planning: "End-to-End Event Planning",
        needs_day_coordination: "Day-of Coordination",
        needs_venue_decoration: "Venue Decoration & Styling",
        needs_venue_search: "Venue Research & Selection",
        needs_branded_styling: "Branded Styling & Design",
        needs_human_resources: "Human Resources & Staffing",
        needs_party_packs: "Party Packs & Favours",
        needs_corporate_gifting: "Corporate Gifting",
        needs_concept_delivery: "Concept to Delivery",
      };

      for (const [field, label] of Object.entries(serviceMap)) {
        if (event[field]) {
          lineItems.push({ description: label, category: "Planning Services", quantity: 1, unitCost: 0, amount: 0 });
        }
      }

      if (event.needs_decor) lineItems.push({ description: "Event Décor", category: "Decoration", quantity: 1, unitCost: 0, amount: 0 });
      if (event.needs_catering) lineItems.push({ description: "Catering Services", category: "Catering", quantity: 1, unitCost: 0, amount: 0 });
      if (event.needs_branding) lineItems.push({ description: "Event Branding", category: "Branding", quantity: 1, unitCost: 0, amount: 0 });
      if (event.needs_vendor_coordination) lineItems.push({ description: "Vendor Coordination", category: "Coordination", quantity: 1, unitCost: 0, amount: 0 });

      for (const item of budgetItems) {
        lineItems.push({
          description: item.item || item.subcategory || 'Budget Item',
          category: item.category,
          quantity: parseFloat(item.quantity || '1'),
          unitCost: parseFloat(item.unit_cost || item.estimated_cost || '0'),
          amount: parseFloat(item.estimated_cost || '0'),
        });
      }

      if (event.other_services_details) {
        lineItems.push({ description: event.other_services_details, category: "Other Services", quantity: 1, unitCost: 0, amount: 0 });
      }

      const subtotal = lineItems.reduce((sum: number, li: any) => sum + (li.amount || 0), 0);
      const finalAmount = subtotal > 0 ? subtotal : parseFloat(event.budget || '0');

      if (subtotal === 0 && parseFloat(event.budget || '0') > 0) {
        lineItems.push({ description: `Event Budget — ${event.name}`, category: "Event Budget", quantity: 1, unitCost: parseFloat(event.budget), amount: parseFloat(event.budget) });
      }

      const invoiceNumber = `INV-${Date.now().toString(36).toUpperCase()}-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
      const resolvedClientId = clientId || event.client_id;
      if (!resolvedClientId) return res.status(400).json({ message: "No client associated with this event" });

      const itemsJson = JSON.stringify(lineItems);
      const taxesJson = JSON.stringify(taxes || [{"name":"Service Charge","rate":15},{"name":"FIRS VAT","rate":7.5}]);
      const due = dueDate || new Date(Date.now() + 14 * 24 * 60 * 60 * 1000).toISOString();

      const result = await db.execute(sql`
        INSERT INTO invoices (event_id, client_id, invoice_number, amount, currency, type, status, due_date, line_items, taxes)
        VALUES (${eventId}, ${resolvedClientId}, ${invoiceNumber}, ${finalAmount}, ${event.currency || 'NGN'}, ${type || 'final'}, 'pending', ${due}, ${itemsJson}::jsonb, ${taxesJson}::jsonb)
        RETURNING *
      `);

      const inv = result.rows[0] as any;
      const clientResult = await db.execute(sql`SELECT full_name, email FROM clients WHERE id = ${resolvedClientId}`);
      const client = clientResult.rows[0] as any;
      inv.event_name = event.name;
      inv.client_name = client?.full_name;
      inv.client_email = client?.email;

      res.json(inv);
    } catch (error) {
      console.error('Generate invoice error:', error);
      res.status(500).json({ message: "Failed to generate invoice" });
    }
  });

