  app.post("/api/webhooks/flutterwave", async (req, res) => {
    try {
      const signature = req.headers['verif-hash'] as string;
      if (signature && !PaymentService.verifyWebhookSignature(signature)) {
        return res.status(401).json({ message: "Invalid webhook signature" });
      }

      const { event: eventType, data } = req.body;
      if (eventType === 'charge.completed' && data?.status === 'successful') {
        const meta = data.meta || {};
        const invoiceId = meta.invoiceId;
        const txRef = data.tx_ref;

        if (invoiceId) {
          await db.execute(sql`
            UPDATE invoices SET status = 'paid', paid_date = NOW() WHERE id = ${invoiceId} AND status != 'paid'
          `);
          console.log(`Webhook: Invoice ${invoiceId} marked as paid via Flutterwave`);
        } else if (txRef) {
          await db.execute(sql`
            UPDATE invoices SET status = 'paid', paid_date = NOW() WHERE tx_ref = ${txRef} AND status != 'paid'
          `);
          console.log(`Webhook: Invoice with tx_ref ${txRef} marked as paid via Flutterwave`);
        }
      }

      res.status(200).json({ status: "ok" });
    } catch (error) {
      console.error('Webhook error:', error);
      res.status(200).json({ status: "ok" });
    }
  });

