  app.post("/api/reminders/generate", authenticateToken, async (req: any, res) => {
    try {
      const now = new Date();
      const weekFromNow = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
      const generated: any[] = [];

      const overdueActivities = await db.execute(sql`
        SELECT a.id, a.title, a.deadline, a.event_id, e.name as event_name
        FROM activities a
        LEFT JOIN events e ON a.event_id = e.id
        WHERE a.status != 'completed' AND a.deadline < ${now}
        AND NOT EXISTS (SELECT 1 FROM reminders r WHERE r.title = 'Overdue: ' || a.title AND r.user_id = ${req.user.id} AND r.status = 'pending')
        LIMIT 20
      `);
      for (const act of overdueActivities.rows as any[]) {
        const r = await db.execute(sql`
          INSERT INTO reminders (user_id, event_id, type, title, message, due_date)
          VALUES (${req.user.id}, ${act.event_id}, 'task_due', ${'Overdue: ' + act.title}, ${(act.event_name || 'Event') + ' - This task is past its deadline'}, ${act.deadline})
          RETURNING *
        `);
        generated.push(r.rows[0]);
      }

      const upcomingInvoices = await db.execute(sql`
        SELECT i.id, i.invoice_number, i.due_date, i.amount, i.currency, i.event_id
        FROM invoices i
        WHERE i.status = 'pending' AND i.due_date <= ${weekFromNow} AND i.due_date >= ${now}
        AND NOT EXISTS (SELECT 1 FROM reminders r WHERE r.title = 'Payment Due: ' || i.invoice_number AND r.user_id = ${req.user.id} AND r.status = 'pending')
        LIMIT 20
      `);
      for (const inv of upcomingInvoices.rows as any[]) {
        const r = await db.execute(sql`
          INSERT INTO reminders (user_id, event_id, type, title, message, due_date)
          VALUES (${req.user.id}, ${inv.event_id}, 'payment_due', ${'Payment Due: ' + inv.invoice_number}, ${(inv.currency || 'NGN') + ' ' + inv.amount + ' due soon'}, ${inv.due_date})
          RETURNING *
        `);
        generated.push(r.rows[0]);
      }

      try {
        const expiringVendors = await db.execute(sql`
          SELECT v.id, v.name, v.contract_end_date, v.event_id, e.name as event_name
          FROM vendors v
          LEFT JOIN events e ON v.event_id = e.id
          WHERE v.contract_end_date IS NOT NULL AND v.contract_end_date <= ${weekFromNow} AND v.contract_end_date >= ${now}
          AND NOT EXISTS (SELECT 1 FROM reminders r WHERE r.title = 'Contract Expiring: ' || v.name AND r.user_id = ${req.user.id} AND r.status = 'pending')
          LIMIT 20
        `);
        for (const v of expiringVendors.rows as any[]) {
          const r = await db.execute(sql`
            INSERT INTO reminders (user_id, event_id, type, title, message, due_date)
            VALUES (${req.user.id}, ${v.event_id}, 'vendor_followup', ${'Contract Expiring: ' + v.name}, ${(v.event_name || 'Event') + ' - Vendor contract expires soon'}, ${v.contract_end_date})
            RETURNING *
          `);
          generated.push(r.rows[0]);
        }
      } catch (e) {
        // vendor contract_end_date column may not exist, skip gracefully
      }

      try {
        const upcomingEvents = await db.execute(sql`
          SELECT e.id, e.name, e.start_date
          FROM events e
          WHERE e.start_date <= ${weekFromNow} AND e.start_date >= ${now}
          AND NOT EXISTS (SELECT 1 FROM reminders r WHERE r.title = 'Upcoming Event: ' || e.name AND r.user_id = ${req.user.id} AND r.status = 'pending')
          LIMIT 10
        `);
        for (const ev of upcomingEvents.rows as any[]) {
          const r = await db.execute(sql`
            INSERT INTO reminders (user_id, event_id, type, title, message, due_date)
            VALUES (${req.user.id}, ${ev.id}, 'milestone', ${'Upcoming Event: ' + ev.name}, ${'Event is coming up soon - review all preparations'}, ${ev.start_date})
            RETURNING *
          `);
          generated.push(r.rows[0]);
        }
      } catch (e) {
        // skip if events table structure differs
      }

      res.json({ generated: generated.length, reminders: generated });
    } catch (error) {
      console.error("Generate reminders error:", error);
      res.status(500).json({ message: "Failed to generate reminders" });
    }
  });

