  app.post("/api/document-requests", authenticateToken, async (req: any, res) => {
    try {
      const { eventId, recipientName, recipientEmail, recipientType, subject, message, requestedDocuments } = req.body;
      if (!recipientEmail || !recipientName || !subject) {
        return res.status(400).json({ message: "Recipient name, email, and subject are required" });
      }
      const token = randomBytes(32).toString('hex');
      const docsArray = requestedDocuments || [];

      const result = await db.execute(sql`
        INSERT INTO document_requests (event_id, recipient_name, recipient_email, recipient_type, subject, message, requested_documents, token)
        VALUES (${eventId || null}, ${recipientName}, ${recipientEmail}, ${recipientType || 'client'}, ${subject}, ${message || null}, ${docsArray}, ${token})
        RETURNING *
      `);

      const docRequest: any = result.rows[0];
      const uploadUrl = `${process.env.APP_URL || `https://${process.env.REPL_SLUG}.${process.env.REPL_OWNER}.repl.co`}/upload-docs/${token}`;

      const docsListHtml = docsArray.length > 0
        ? `<div style="margin:20px 0;padding:16px;background:#faf8f5;border-radius:8px;border:1px solid #e8e0d8;">
            <p style="font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:1px;color:#8B1538;margin-bottom:8px;">Documents Requested:</p>
            <ul style="margin:0;padding-left:20px;color:#555;font-size:14px;line-height:1.8;">
              ${docsArray.map((d: string) => `<li>${d}</li>`).join('')}
            </ul>
          </div>`
        : '';

      const emailHtml = `
        <div style="font-family:'Inter',Arial,sans-serif;max-width:600px;margin:0 auto;border:1px solid #e8e0d8;border-radius:12px;overflow:hidden;">
          <div style="padding:30px 40px;background:linear-gradient(135deg,#330311,#8B1538);color:white;">
            <h1 style="font-family:'Playfair Display',Georgia,serif;font-size:22px;margin:0;">Document Request</h1>
            <p style="font-size:11px;color:rgba(255,255,255,0.6);font-style:italic;margin-top:4px;">Event Perfekt ...making yours perfekt</p>
          </div>
          <div style="padding:30px 40px;">
            <p style="font-size:14px;color:#333;margin-bottom:16px;">Dear ${recipientName},</p>
            ${message ? `<p style="font-size:14px;color:#555;margin-bottom:16px;">${message}</p>` : ''}
            <p style="font-size:14px;color:#555;margin-bottom:16px;">We kindly request you to upload the following documents for your event. Please click the button below to securely upload your files.</p>
            ${docsListHtml}
            <div style="text-align:center;margin:28px 0;">
              <a href="${uploadUrl}" style="display:inline-block;background:#8B1538;color:white;padding:14px 32px;text-decoration:none;border-radius:8px;font-weight:600;font-size:14px;">Upload Documents</a>
            </div>
            <p style="font-size:12px;color:#999;text-align:center;">This is a secure link. Only use it to upload the requested documents.</p>
          </div>
          <div style="text-align:center;padding:20px;background:#faf8f5;border-top:1px solid #e8e0d8;">
            <p style="font-size:12px;color:#999;">Event Perfekt &bull; www.eventperfekt.com</p>
          </div>
        </div>
      `;

      try {
        await sendEmail(recipientEmail, subject, emailHtml);
        await db.execute(sql`UPDATE document_requests SET status = 'sent' WHERE id = ${docRequest.id}`);
        docRequest.status = 'sent';
      } catch (emailErr) {
        console.log('Email send skipped (SendGrid not configured):', recipientEmail);
      }

      res.json({ ...docRequest, uploadUrl });
    } catch (error) {
      console.error("Create document request error:", error);
      res.status(500).json({ message: "Failed to create document request" });
    }
  });

