  app.post("/api/upload-docs/:token", upload.array('files', 10), async (req: any, res) => {
    try {
      const result = await db.execute(sql`SELECT * FROM document_requests WHERE token = ${req.params.token}`);
      if (!result.rows.length) return res.status(404).json({ message: "Invalid link" });
      const docReq: any = result.rows[0];

      if (!req.files || req.files.length === 0) return res.status(400).json({ message: "No files uploaded" });

      const newUploads = req.files.map((f: any) => ({
        fileName: f.originalname,
        fileUrl: `/uploads/${f.filename}`,
        fileSize: f.size,
        fileType: f.mimetype,
        uploadedAt: new Date().toISOString(),
      }));

      const existingUploads = docReq.uploads || [];
      const allUploads = [...existingUploads, ...newUploads];

      await db.execute(sql`
        UPDATE document_requests
        SET uploads = ${JSON.stringify(allUploads)}::jsonb, status = 'completed', completed_at = NOW()
        WHERE id = ${docReq.id}
      `);

      if (docReq.event_id) {
        for (const upload of newUploads) {
          await db.execute(sql`
            INSERT INTO documents (event_id, name, file_name, file_url, file_type, file_size, category, uploaded_by, shared_with_client)
            VALUES (${docReq.event_id}, ${upload.fileName}, ${upload.fileName}, ${upload.fileUrl}, ${upload.fileType}, ${upload.fileSize}, 'vendor_docs', ${docReq.recipient_name}, false)
          `);
        }
      }

      res.json({ message: "Documents uploaded successfully", uploads: allUploads });
    } catch (error) {
      console.error("Document upload error:", error);
      res.status(500).json({ message: "Upload failed" });
    }
  });

