  app.post("/api/event-templates/from-event/:eventId", authenticateToken, async (req: any, res) => {
    try {
      const { eventId } = req.params;
      const { name, description } = req.body;

      const eventResult = await db.execute(sql`SELECT * FROM events WHERE id = ${eventId}`);
      if (!eventResult.rows.length) return res.status(404).json({ message: "Event not found" });
      const event: any = eventResult.rows[0];

      const budgetResult = await db.execute(sql`SELECT category, subcategory, estimated_cost, unit_type, quantity FROM budget_items WHERE event_id = ${eventId}`);
      const activitiesResult = await db.execute(sql`SELECT title, phase, category, priority FROM activities WHERE event_id = ${eventId}`);
      const vendorsResult = await db.execute(sql`SELECT service_type, category FROM vendors WHERE event_id = ${eventId}`);

      const templateData = {
        eventType: event.type,
        eventCategory: event.event_category,
        currency: event.currency,
        budgetItems: budgetResult.rows,
        activities: activitiesResult.rows,
        vendorTypes: vendorsResult.rows,
        serviceNeeds: {
          needsVenueDecoration: event.needs_venue_decoration,
          needsCatering: event.needs_catering,
          needsPhotography: event.needs_photography,
          needsEntertainment: event.needs_entertainment,
        }
      };

      const result = await db.execute(sql`
        INSERT INTO event_templates (name, description, event_type, template_data, created_by)
        VALUES (${name || event.name + ' Template'}, ${description || 'Template from ' + event.name}, ${event.type}, ${JSON.stringify(templateData)}, ${req.user.id})
        RETURNING *
      `);
      res.json(result.rows[0]);
    } catch (error) {
      console.error("Create template from event error:", error);
      res.status(500).json({ message: "Failed to create template" });
    }
  });

