  function parseBudgetRange(budgetRange: string, currency: string): number {
    if (!budgetRange || budgetRange === '0') {
      if (currency === 'NGN') return 5000000;
      if (currency === 'GBP') return 10000;
      return 15000;
    }
    const cleaned = budgetRange.replace(/[^0-9,.\-+]/g, '').replace(/,/g, '');
    const numbers = cleaned.match(/\d+/g);
    if (!numbers || numbers.length === 0) {
      if (currency === 'NGN') return 5000000;
      if (currency === 'GBP') return 10000;
      return 15000;
    }
    if (numbers.length >= 2) {
      return Math.round((parseInt(numbers[0]) + parseInt(numbers[1])) / 2);
    }
    const single = parseInt(numbers[0]);
    if (budgetRange.toLowerCase().includes('under') || budgetRange.includes('<')) {
      return Math.round(single * 0.75);
    }
    if (budgetRange.includes('+') || budgetRange.toLowerCase().includes('over')) {
      return Math.round(single * 1.25);
    }
    return single;
  }

