  app.patch("/api/proposals/:id", authenticateToken, async (req: any, res) => {
    try {
      const { id } = req.params;
      const { title, content, status, totalAmount, validUntil, heroImage, galleryImages, sections } = req.body;

      if (title !== undefined) {
        const result = await db.execute(sql`UPDATE proposals SET title = ${title} WHERE id = ${id} RETURNING *`);
        if (!result.rows.length) return res.status(404).json({ message: "Proposal not found" });
      }
      if (content !== undefined) {
        await db.execute(sql`UPDATE proposals SET content = ${content} WHERE id = ${id}`);
      }
      if (heroImage !== undefined) {
        await db.execute(sql`UPDATE proposals SET hero_image = ${heroImage} WHERE id = ${id}`);
      }
      if (galleryImages !== undefined) {
        await db.execute(sql`UPDATE proposals SET gallery_images = ${galleryImages} WHERE id = ${id}`);
      }
      if (sections !== undefined) {
        await db.execute(sql`UPDATE proposals SET sections = ${JSON.stringify(sections)} WHERE id = ${id}`);
      }
      if (status !== undefined) {
        await db.execute(sql`UPDATE proposals SET status = ${status} WHERE id = ${id}`);
        if (status === 'sent') {
          await db.execute(sql`UPDATE proposals SET sent_date = NOW() WHERE id = ${id}`);
        }
        if (status === 'accepted' || status === 'rejected') {
          await db.execute(sql`UPDATE proposals SET responded_date = NOW() WHERE id = ${id}`);
        }
      }
      if (totalAmount !== undefined) {
        await db.execute(sql`UPDATE proposals SET total_amount = ${String(totalAmount)} WHERE id = ${id}`);
      }
      if (validUntil !== undefined) {
        await db.execute(sql`UPDATE proposals SET valid_until = ${new Date(validUntil)} WHERE id = ${id}`);
      }

      const updated = await db.execute(sql`SELECT * FROM proposals WHERE id = ${id}`);
      res.json(updated.rows[0]);
    } catch (error) {
      console.error("Proposal update error:", error);
      res.status(500).json({ message: "Failed to update proposal" });
    }
  });

