  app.get("/api/client/events/:eventId/summary", authenticateToken, async (req: any, res) => {
    try {
      const { eventId } = req.params;

      const event = await db.execute(sql`SELECT * FROM events WHERE id = ${eventId}`);
      if (!event.rows.length) return res.status(404).json({ message: "Event not found" });
      const e: any = event.rows[0];

      const activities = await db.execute(sql`
        SELECT status, COUNT(*) as count FROM activities WHERE event_id = ${eventId} GROUP BY status
      `);
      const totalTasks = (activities.rows as any[]).reduce((s: number, r: any) => s + Number(r.count), 0);
      const completedTasks = (activities.rows as any[]).find((r: any) => r.status === 'completed')?.count || 0;

      const budget = await db.execute(sql`
        SELECT
          SUM(CAST(COALESCE(estimated_cost, '0') AS DECIMAL)) as total_budget,
          SUM(CAST(COALESCE(actual_cost, '0') AS DECIMAL)) as total_spent
        FROM budget_items WHERE event_id = ${eventId}
      `);

      const invoices = await db.execute(sql`
        SELECT status, SUM(CAST(amount AS DECIMAL)) as total FROM invoices WHERE event_id = ${eventId} GROUP BY status
      `);

      const sharedDocs = await db.execute(sql`
        SELECT * FROM documents WHERE event_id = ${eventId} AND shared_with_client = TRUE ORDER BY created_at DESC
      `);

      const notes = await db.execute(sql`
        SELECT * FROM planner_notes WHERE event_id = ${eventId} ORDER BY created_at DESC LIMIT 10
      `);

      const pendingApprovals = await db.execute(sql`
        SELECT COUNT(*) as count FROM inspiration_images
        WHERE event_id = ${eventId} AND (approval_status = 'pending' OR approval_status IS NULL)
      `);

      res.json({
        event: e,
        progress: {
          totalTasks,
          completedTasks: Number(completedTasks),
          percentage: totalTasks > 0 ? Math.round(Number(completedTasks) / totalTasks * 100) : 0,
          phase: e.current_phase || 'planning',
          taskBreakdown: activities.rows
        },
        budget: {
          totalBudget: Number((budget.rows[0] as any)?.total_budget) || 0,
          totalSpent: Number((budget.rows[0] as any)?.total_spent) || 0
        },
        pendingApprovals: Number((pendingApprovals.rows[0] as any)?.count) || 0,
        invoices: invoices.rows,
        documents: sharedDocs.rows,
        notes: notes.rows
      });
    } catch (error) {
      console.error("Client summary error:", error);
      res.status(500).json({ message: "Failed to fetch client summary" });
    }
  });

