  // === TIMELINE DATA ===
  app.get("/api/timeline", authenticateToken, async (req: any, res) => {
    try {
      const eventId = req.query.eventId;
      const whereClause = eventId ? sql`WHERE a.event_id = ${eventId}` : sql``;

      const activities = await db.execute(sql`
        SELECT a.id, a.task_name as title, a.status, a.priority, a.phase, a.deadline,
          a.event_id, a.created_at, a.owner, a.custom_owner,
          e.name as event_name, e.start_date as event_start, e.end_date as event_end
        FROM activities a
        LEFT JOIN events e ON a.event_id = e.id
        ${whereClause}
        ORDER BY a.deadline ASC NULLS LAST
      `);

      let milestoneRows: any[] = [];
      try {
        const milestones = await db.execute(sql`
          SELECT m.id, m.title, m.target_date, m.status, m.event_id, e.name as event_name
          FROM timeline_milestones m
          LEFT JOIN events e ON m.event_id = e.id
          ${eventId ? sql`WHERE m.event_id = ${eventId}` : sql``}
          ORDER BY m.target_date ASC NULLS LAST
        `);
        milestoneRows = milestones.rows;
      } catch (e) {
      }

      const tasks = await db.execute(sql`
        SELECT t.id, t.title, t.status, t.due_date, t.assigned_to, t.description,
          t.event_id, t.created_at,
          e.name as event_name, e.start_date as event_start, e.end_date as event_end,
          u.name as assignee_name
        FROM tasks t
        LEFT JOIN events e ON t.event_id = e.id
        LEFT JOIN users u ON t.assigned_to = u.id
        ${eventId ? sql`WHERE t.event_id = ${eventId}` : sql``}
        ORDER BY t.due_date ASC NULLS LAST
      `);

      res.json({
        activities: activities.rows,
        milestones: milestoneRows,
        tasks: tasks.rows
      });
    } catch (error) {
      console.error("Timeline error:", error);
      res.status(500).json({ message: "Failed to fetch timeline data" });
    }
  });

