      if (req.params.id === req.user.id) return res.status(400).json({ message: "Cannot deactivate yourself" });

      const current = await db.execute(sql`SELECT status, name FROM users WHERE id = ${req.params.id}`);
      if (!current.rows.length) return res.status(404).json({ message: "User not found" });

      const newStatus = (current.rows[0] as any).status === 'active' ? 'suspended' : 'active';
      const result = await db.execute(sql`
        UPDATE users SET status = ${newStatus} WHERE id = ${req.params.id}
        RETURNING id, name, email, role, status
      `);

      await db.execute(sql`
        INSERT INTO access_logs (user_id, action, target_type, target_id, details)
        VALUES (${req.user.id}, ${newStatus === 'suspended' ? 'suspend_user' : 'activate_user'}, 'user', ${req.params.id}, ${`${(current.rows[0] as any).name} ${newStatus}`})
      `);

