      const ticketNumber = `EP-${String(num).padStart(4, '0')}`;

      const result = await db.execute(sql`
        INSERT INTO tickets (ticket_number, title, description, category, priority, event_id, reported_by)
        VALUES (${ticketNumber}, ${title}, ${description || null}, ${category || 'general'}, ${priority || 'medium'}, ${eventId || null}, ${req.user.id})
        RETURNING *
      `);
