  // === LOGIN BRIEFING ===
  app.get("/api/briefing", optionalAuth, async (req: any, res) => {
    try {
      const userId = req.user.id;
      const userRole = req.user.role;

      const eventsResult = await db.execute(sql`SELECT * FROM events ORDER BY start_date ASC`);
      let allEvents = eventsResult.rows as any[];

      if (userRole === 'planner') {
        allEvents = allEvents.filter((e: any) => String(e.planner_id) === String(userId));
      } else if (userRole === 'staff' || userRole === 'collaborator') {
        const collabResult = await db.execute(sql`
          SELECT DISTINCT event_id FROM event_collaborators WHERE user_id = ${userId}
          UNION
          SELECT DISTINCT event_id FROM event_resources WHERE user_id = ${userId}
        `);
        const allowedIds = new Set((collabResult.rows as any[]).map((r: any) => r.event_id));
        allEvents = allEvents.filter((e: any) => allowedIds.has(e.id));
      }

      const now = new Date();
      const upcomingEvents = allEvents.filter((e: any) => new Date(e.start_date) > now)
        .sort((a: any, b: any) => new Date(a.start_date).getTime() - new Date(b.start_date).getTime());
      const nextEvent = upcomingEvents[0] || null;

      let overdueTasks = 0;
      let pendingTasks = 0;
      let inProgressTasks = 0;
      let completedTasks = 0;
      let totalTasks = 0;

      try {
        const eventIds = allEvents.map((e: any) => e.id);
        if (eventIds.length > 0) {
          const activitiesResult = await db.execute(sql`
            SELECT status, COUNT(*) as count FROM activities 
            WHERE event_id = ANY(${eventIds})
            GROUP BY status
          `);
          for (const row of activitiesResult.rows as any[]) {
            const count = Number(row.count);
            totalTasks += count;
            if (row.status === 'completed') completedTasks = count;
            else if (row.status === 'in-progress') inProgressTasks = count;
            else if (row.status === 'overdue') overdueTasks = count;
            else pendingTasks += count;
          }

          const overdueCheck = await db.execute(sql`
            SELECT COUNT(*) as count FROM activities 
            WHERE event_id = ANY(${eventIds}) 
            AND status != 'completed' 
            AND deadline IS NOT NULL 
            AND deadline < NOW()
          `);
          overdueTasks = Math.max(overdueTasks, Number((overdueCheck.rows[0] as any)?.count || 0));
        }
      } catch (e) {}

      let unpaidInvoices = 0;
      let overdueInvoices = 0;
      let totalOutstanding = 0;
      let outstandingCurrency = 'NGN';
      try {
        const eventIds = allEvents.map((e: any) => e.id);
        if (eventIds.length > 0) {
          const invResult = await db.execute(sql`
            SELECT status, amount, currency, due_date FROM invoices 
            WHERE event_id = ANY(${eventIds})
          `);
          for (const inv of invResult.rows as any[]) {
            if (inv.status !== 'paid') {
              unpaidInvoices++;
              totalOutstanding += Number(inv.amount || 0);
              outstandingCurrency = inv.currency || 'NGN';
              if (inv.due_date && new Date(inv.due_date) < now) {
                overdueInvoices++;
              }
            }
          }
        }
      } catch (e) {}

      let pendingReminders = 0;
      try {
        const remResult = await db.execute(sql`
          SELECT COUNT(*) as count FROM reminders 
          WHERE user_id = ${userId} AND status = 'pending'
        `);
        pendingReminders = Number((remResult.rows[0] as any)?.count || 0);
      } catch (e) {}

      let openTickets = 0;
      try {
        const ticketResult = await db.execute(sql`
          SELECT COUNT(*) as count FROM tickets 
          WHERE status IN ('open', 'in_progress')
        `);
        openTickets = Number((ticketResult.rows[0] as any)?.count || 0);
      } catch (e) {}

      const urgentEvents = allEvents.filter((e: any) => {
        const daysUntil = Math.ceil((new Date(e.start_date).getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
        return daysUntil > 0 && daysUntil <= 30;
      });

      const briefingItems: any[] = [];

      if (nextEvent) {
        const daysUntil = Math.ceil((new Date(nextEvent.start_date).getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
        if (daysUntil > 0) {
          briefingItems.push({ type: 'next_event', priority: daysUntil <= 7 ? 'urgent' : daysUntil <= 30 ? 'warning' : 'info', message: `Your next event "${nextEvent.name}" is in ${daysUntil} day${daysUntil !== 1 ? 's' : ''}`, detail: `${nextEvent.type} · ${nextEvent.event_category || 'Event'} · ${nextEvent.guest_count || 0} guests`, eventId: nextEvent.id });
        }
      }

      if (overdueTasks > 0) {
        briefingItems.push({ type: 'overdue_tasks', priority: 'urgent', message: `${overdueTasks} overdue task${overdueTasks !== 1 ? 's' : ''} need attention`, detail: 'These tasks have passed their deadline' });
      }

      if (overdueInvoices > 0) {
        briefingItems.push({ type: 'overdue_invoices', priority: 'urgent', message: `${overdueInvoices} overdue invoice${overdueInvoices !== 1 ? 's' : ''}`, detail: `${new Intl.NumberFormat('en', { style: 'currency', currency: outstandingCurrency }).format(totalOutstanding)} outstanding` });
      } else if (unpaidInvoices > 0) {
        briefingItems.push({ type: 'unpaid_invoices', priority: 'warning', message: `${unpaidInvoices} unpaid invoice${unpaidInvoices !== 1 ? 's' : ''}`, detail: `${new Intl.NumberFormat('en', { style: 'currency', currency: outstandingCurrency }).format(totalOutstanding)} outstanding` });
      }

      if (pendingReminders > 0) {
        briefingItems.push({ type: 'reminders', priority: 'info', message: `${pendingReminders} pending reminder${pendingReminders !== 1 ? 's' : ''}`, detail: 'Check your reminders page' });
      }

      if (openTickets > 0) {
        briefingItems.push({ type: 'tickets', priority: 'info', message: `${openTickets} open support ticket${openTickets !== 1 ? 's' : ''}`, detail: 'Issues awaiting resolution' });
      }

      for (const ue of urgentEvents.slice(0, 3)) {
        const daysUntil = Math.ceil((new Date(ue.start_date).getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
        if (ue.id !== nextEvent?.id) {
          briefingItems.push({ type: 'upcoming_event', priority: 'warning', message: `"${ue.name}" is in ${daysUntil} days`, detail: `${ue.type} · ${ue.guest_count || 0} guests`, eventId: ue.id });
        }
      }

      if (briefingItems.length === 0) {
        briefingItems.push({ type: 'all_clear', priority: 'success', message: 'All caught up!', detail: 'No urgent items need your attention right now' });
      }

      res.json({
        greeting: getGreeting(),
        summary: {
          totalEvents: allEvents.length,
          upcomingEvents: upcomingEvents.length,
          totalTasks,
          completedTasks,
          inProgressTasks,
          pendingTasks,
          overdueTasks,
          unpaidInvoices,
          overdueInvoices,
          totalOutstanding,
          outstandingCurrency,
          pendingReminders,
          openTickets,
        },
        items: briefingItems,
        nextEvent: nextEvent ? { id: nextEvent.id, name: nextEvent.name, date: nextEvent.start_date, type: nextEvent.type, guestCount: nextEvent.guest_count } : null,
      });
    } catch (error) {
      console.error("Briefing error:", error);
      res.status(500).json({ message: "Failed to load briefing" });
    }
  });

