  app.get("/api/vendor-ratings", authenticateToken, async (req: any, res) => {
    try {
      const { vendor_id, event_id } = req.query;
      let query = `SELECT * FROM vendor_ratings`;
      const conditions: string[] = [];
      if (vendor_id) conditions.push(`vendor_id = '${vendor_id}'`);
      if (event_id) conditions.push(`event_id = '${event_id}'`);
      if (conditions.length > 0) query += ` WHERE ` + conditions.join(' AND ');
      query += ` ORDER BY created_at DESC`;
      const result = await db.execute(sql.raw(query));
      res.json(result.rows);
    } catch (error) {
      console.error('Error fetching vendor ratings:', error);
      res.status(500).json({ message: "Failed to fetch vendor ratings" });
    }
  });

  app.post("/api/vendor-ratings", authenticateToken, async (req: any, res) => {
    try {
      const { vendor_id, event_id, communication, quality, punctuality, value, review_text, recommended } = req.body;
      if (!vendor_id) return res.status(400).json({ message: "vendor_id is required" });
      const overall = ((communication + quality + punctuality + value) / 4).toFixed(1);
      const rated_by = req.user?.id || req.user?.userId || 'unknown';
      const result = await db.execute(sql`
        INSERT INTO vendor_ratings (vendor_id, event_id, rated_by, communication, quality, punctuality, value, overall, review_text, recommended)
        VALUES (${vendor_id}, ${event_id || null}, ${rated_by}, ${communication}, ${quality}, ${punctuality}, ${value}, ${parseFloat(overall)}, ${review_text || null}, ${recommended !== false})
        RETURNING *
      `);
      res.json(result.rows[0]);
    } catch (error) {
      console.error('Error creating vendor rating:', error);
      res.status(500).json({ message: "Failed to create vendor rating" });
    }
  });

  app.get("/api/vendors/:id/ratings", authenticateToken, async (req: any, res) => {
    try {
      const { id } = req.params;
      const ratings = await db.execute(sql`SELECT * FROM vendor_ratings WHERE vendor_id = ${id} ORDER BY created_at DESC`);
      const aggregate = await db.execute(sql`
        SELECT 
          COUNT(*)::int as total_reviews,
          ROUND(AVG(communication)::numeric, 1) as avg_communication,
          ROUND(AVG(quality)::numeric, 1) as avg_quality,
          ROUND(AVG(punctuality)::numeric, 1) as avg_punctuality,
          ROUND(AVG(value)::numeric, 1) as avg_value,
          ROUND(AVG(overall)::numeric, 1) as avg_overall,
          COUNT(*) FILTER (WHERE recommended = true)::int as recommend_count
        FROM vendor_ratings WHERE vendor_id = ${id}
      `);
      res.json({
        ratings: ratings.rows,
        aggregate: aggregate.rows[0]
      });
    } catch (error) {
      console.error('Error fetching vendor ratings:', error);
      res.status(500).json({ message: "Failed to fetch vendor ratings" });
    }
  });

