  app.patch("/api/enquiries/:id", authenticateToken, async (req: any, res) => {
    try {
      const { id } = req.params;
      const { status, assigned_to, notes } = req.body;
      const setClauses: string[] = [];
      const values: any[] = [];

      if (status !== undefined) {
        setClauses.push(`status = '${status}'`);
      }
      if (assigned_to !== undefined) {
        setClauses.push(`assigned_to = '${assigned_to}'`);
      }
      if (notes !== undefined) {
        setClauses.push(`notes = '${notes}'`);
      }

      if (setClauses.length === 0) {
        return res.status(400).json({ message: "No fields to update" });
      }

      const result = await db.execute(sql`
        UPDATE enquiries 
        SET status = COALESCE(${status || null}, status),
            assigned_to = COALESCE(${assigned_to || null}, assigned_to),
            notes = COALESCE(${notes || null}, notes)
        WHERE id = ${id}
        RETURNING *
      `);

      if (result.rows.length === 0) {
        return res.status(404).json({ message: "Enquiry not found" });
      }
      res.json(result.rows[0]);
    } catch (error) {
      console.error('Error updating enquiry:', error);
      res.status(500).json({ message: "Failed to update enquiry" });
    }
  });

  app.post("/api/enquiries/:id/convert", authenticateToken, async (req: any, res) => {
    try {
      const { id } = req.params;
      const enquiryResult = await db.execute(sql`SELECT * FROM enquiries WHERE id = ${id}`);
      if (enquiryResult.rows.length === 0) {
        return res.status(404).json({ message: "Enquiry not found" });
      }
      const enquiry: any = enquiryResult.rows[0];

      const eventDate = enquiry.preferred_date ? new Date(enquiry.preferred_date) : new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);
      const endDate = new Date(eventDate.getTime() + 24 * 60 * 60 * 1000);

      const typeMap: Record<string, string> = {
        wedding: "private",
        birthday: "private",
        corporate: "corporate",
        conference: "corporate",
        seminar: "corporate",
        gala: "corporate",
        product_launch: "corporate",
      };
      const eventType = typeMap[enquiry.event_type] || "private";

      const event = await storage.createEvent({
        name: `${enquiry.name} - ${enquiry.event_type.charAt(0).toUpperCase() + enquiry.event_type.slice(1)}`,
        description: enquiry.message || `Event created from booking enquiry by ${enquiry.name}`,
        type: eventType,
        eventCategory: enquiry.event_type,
        startDate: eventDate,
        endDate: endDate,
        eventDays: 1,
        country: enquiry.country || "Nigeria",
        city: "TBD",
        currency: enquiry.country?.toLowerCase() === "uk" || enquiry.country?.toLowerCase() === "united kingdom" ? "GBP" : "NGN",
        guestCount: enquiry.guest_count || 0,
        budget: enquiry.budget_range || "0",
        status: "active",
      } as any);

      await db.execute(sql`
        UPDATE enquiries SET status = 'converted' WHERE id = ${id}
      `);

      res.json({ message: "Enquiry converted to event", event });
    } catch (error) {
      console.error('Error converting enquiry:', error);
      res.status(500).json({ message: "Failed to convert enquiry to event" });
    }
  });

