  app.get("/api/gallery-albums", authenticateToken, async (req: any, res) => {
    try {
      const eventId = req.query.eventId;
      let albumsResult;
      if (eventId) {
        albumsResult = await db.execute(sql`SELECT * FROM gallery_albums WHERE event_id = ${eventId} ORDER BY created_at DESC`);
      } else {
        albumsResult = await db.execute(sql`SELECT * FROM gallery_albums ORDER BY created_at DESC`);
      }
      // Enrich each album with photo count and up to 4 preview thumbnails
      const enriched = await Promise.all(albumsResult.rows.map(async (album: any) => {
        const countResult = await db.execute(sql`SELECT COUNT(*) as count FROM gallery_items WHERE album_id = ${album.id}`);
        const previewResult = await db.execute(sql`SELECT file_url, file_type FROM gallery_items WHERE album_id = ${album.id} AND file_type = 'image' ORDER BY sort_order ASC, created_at DESC LIMIT 4`);
        return {
          ...album,
          item_count: parseInt((countResult.rows[0] as any).count) || 0,
          preview_urls: previewResult.rows.map((r: any) => r.file_url),
        };
      }));
      res.json(enriched);
    } catch (error) {
      console.error('Error fetching gallery albums:', error);
      res.status(500).json({ message: "Failed to fetch gallery albums" });
    }
  });

