  app.patch("/api/campaigns/:id", authenticateToken, async (req: any, res) => {
    try {
      const { id } = req.params;
      const { subject, body_html, recipients, status, scheduled_at, event_id } = req.body;
      const fields: string[] = [];
      if (subject !== undefined) fields.push(`subject = '${subject.replace(/'/g, "''")}'`);
      if (body_html !== undefined) fields.push(`body_html = '${body_html.replace(/'/g, "''")}'`);
      if (recipients !== undefined) fields.push(`recipients = '${JSON.stringify(recipients)}'::jsonb`);
      if (status !== undefined) fields.push(`status = '${status}'`);
      if (scheduled_at !== undefined) fields.push(`scheduled_at = ${scheduled_at ? `'${scheduled_at}'` : 'NULL'}`);
      if (event_id !== undefined) fields.push(`event_id = ${event_id ? `'${event_id}'` : 'NULL'}`);

      if (fields.length === 0) {
        return res.status(400).json({ message: "No fields to update" });
      }

      const query = `UPDATE email_campaigns SET ${fields.join(', ')} WHERE id = '${id}' RETURNING *`;
      const result = await db.execute(sql.raw(query));
      if (result.rows.length === 0) {
        return res.status(404).json({ message: "Campaign not found" });
      }
      res.json(result.rows[0]);
    } catch (error) {
      console.error('Error updating campaign:', error);
      res.status(500).json({ message: "Failed to update campaign" });
    }
  });

