  app.post("/api/campaigns/:id/send", authenticateToken, async (req: any, res) => {
    try {
      const { id } = req.params;
      const result = await db.execute(sql`SELECT * FROM email_campaigns WHERE id = ${id}`);
      if (result.rows.length === 0) {
        return res.status(404).json({ message: "Campaign not found" });
      }
      const campaign = result.rows[0] as any;
      const recipientList: { email: string; name?: string }[] = campaign.recipients || [];

      if (recipientList.length === 0) {
        return res.status(400).json({ message: "No recipients specified" });
      }

      let sentCount = 0;
      for (const recipient of recipientList) {
        try {
          await emailService.sendEmail(recipient.email, campaign.subject, campaign.body_html);
          sentCount++;
        } catch (err) {
          console.error(`Failed to send to ${recipient.email}:`, err);
        }
      }

      await db.execute(sql`
        UPDATE email_campaigns SET status = 'sent', sent_at = NOW(), sent_count = ${sentCount} WHERE id = ${id}
      `);

      const updated = await db.execute(sql`SELECT * FROM email_campaigns WHERE id = ${id}`);
      res.json(updated.rows[0]);
    } catch (error) {
      console.error('Error sending campaign:', error);
      res.status(500).json({ message: "Failed to send campaign" });
    }
  });

  // ============================================================================
