  app.get("/api/audit-log", authenticateToken, async (req: any, res) => {
    try {
      const { user, action, dateFrom, dateTo, eventId, source, limit: qLimit, offset: qOffset } = req.query;
      const limitVal = Math.min(parseInt(qLimit as string) || 100, 500);
      const offsetVal = parseInt(qOffset as string) || 0;

      const results: any[] = [];

      const activityAudit = await db.execute(sql`
        SELECT 
          a.id, a.change_type as action, a.field_changed, a.old_value, a.new_value, a.timestamp,
          a.changed_by as user_id, u.name as user_name, u.email as user_email,
          'activity_audit' as source, a.activity_id as target
        FROM activity_audit_log a
        LEFT JOIN users u ON a.changed_by = u.id
        ORDER BY a.timestamp DESC
        LIMIT 500
      `);
      for (const row of activityAudit.rows) {
        results.push({
          id: row.id,
          action: row.action,
          source: 'activity_audit',
          userId: row.user_id,
          userName: row.user_name || 'System',
          userEmail: row.user_email,
          target: row.target,
          targetType: 'activity',
          fieldChanged: row.field_changed,
          oldValue: row.old_value,
          newValue: row.new_value,
          details: {},
          timestamp: row.timestamp,
        });
      }

      const plannerLog = await db.execute(sql`
        SELECT 
          p.id, p.action, p.section, p.details, p.timestamp, p.duration_seconds,
          p.planner_id as user_id, u.name as user_name, u.email as user_email
        FROM planner_activity_log p
        LEFT JOIN users u ON p.planner_id = u.id
        ORDER BY p.timestamp DESC
        LIMIT 500
      `);
      for (const row of plannerLog.rows) {
        results.push({
          id: row.id,
          action: row.action,
          source: 'planner_activity',
          userId: row.user_id,
          userName: row.user_name || 'System',
          userEmail: row.user_email,
          target: row.section,
          targetType: 'section',
          fieldChanged: null,
          oldValue: null,
          newValue: null,
          details: row.details || {},
          timestamp: row.timestamp,
        });
      }

      const userAudit = await db.execute(sql`
        SELECT 
          ua.id, ua.action, ua.target, ua.target_type, ua.details, ua.ip_address, ua.user_agent, ua.timestamp,
          ua.user_id, u.name as user_name, u.email as user_email
        FROM user_audit_log ua
        LEFT JOIN users u ON ua.user_id = u.id
        ORDER BY ua.timestamp DESC
        LIMIT 500
      `);
      for (const row of userAudit.rows) {
        results.push({
          id: row.id,
          action: row.action,
          source: 'user_audit',
          userId: row.user_id,
          userName: row.user_name || 'System',
          userEmail: row.user_email,
          target: row.target,
          targetType: row.target_type,
          fieldChanged: null,
          oldValue: null,
          newValue: null,
          details: { ...(row.details as any || {}), ipAddress: row.ip_address, userAgent: row.user_agent },
          timestamp: row.timestamp,
        });
      }

      results.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

      let filtered = results;
      if (user) {
        const u = (user as string).toLowerCase();
        filtered = filtered.filter(r => r.userName?.toLowerCase().includes(u) || r.userEmail?.toLowerCase().includes(u));
      }
      if (action) {
        const a = (action as string).toLowerCase();
        filtered = filtered.filter(r => r.action?.toLowerCase().includes(a));
      }
      if (source) {
        filtered = filtered.filter(r => r.source === source);
      }
      if (dateFrom) {
        const from = new Date(dateFrom as string);
        filtered = filtered.filter(r => new Date(r.timestamp) >= from);
      }
      if (dateTo) {
        const to = new Date(dateTo as string);
        to.setHours(23, 59, 59, 999);
        filtered = filtered.filter(r => new Date(r.timestamp) <= to);
      }

      const total = filtered.length;
      const paginated = filtered.slice(offsetVal, offsetVal + limitVal);

      res.json({ logs: paginated, total, limit: limitVal, offset: offsetVal });
    } catch (error) {
      console.error('Error fetching audit log:', error);
      res.status(500).json({ message: "Failed to fetch audit log" });
    }
  });

