  app.get("/api/expense-requests", authenticateToken, async (req: any, res) => {
    try {
      const { department, status, requester_id, event_id, category } = req.query;
      const conditions: any[] = [];
      if (department && department !== "all") conditions.push(sql`department = ${department}`);
      if (status && status !== "all") conditions.push(sql`status = ${status}`);
      if (requester_id) conditions.push(sql`requester_id = ${parseInt(requester_id as string)}`);
      if (event_id && event_id !== "all") {
        if (event_id === "company") conditions.push(sql`event_id IS NULL`);
        else conditions.push(sql`event_id = ${parseInt(event_id as string)}`);
      }
      if (category && category !== "all") conditions.push(sql`category = ${category}`);

      let result;
      if (conditions.length === 0) {
        result = await db.execute(sql`SELECT * FROM expense_requests ORDER BY created_at DESC`);
      } else {
        const whereClause = conditions.reduce((acc, cond, i) => i === 0 ? cond : sql`${acc} AND ${cond}`);
        result = await db.execute(sql`SELECT * FROM expense_requests WHERE ${whereClause} ORDER BY created_at DESC`);
      }
      res.json(result.rows);
    } catch (error: any) {
      console.error("Error fetching expense requests:", error);
      res.status(500).json({ message: error.message });
    }
  });

  app.get("/api/expense-requests/summary", authenticateToken, async (req: any, res) => {
    try {
      const totals = await db.execute(sql`
        SELECT
          COUNT(*) as total,
          COUNT(*) FILTER (WHERE status = 'pending') as pending,
          COUNT(*) FILTER (WHERE status = 'approved') as approved,
          COUNT(*) FILTER (WHERE status = 'rejected') as rejected,
          COUNT(*) FILTER (WHERE status = 'purchased') as purchased,
          COALESCE(SUM(estimated_cost) FILTER (WHERE status = 'approved'), 0) as approved_total,
          COALESCE(SUM(estimated_cost) FILTER (WHERE status = 'pending'), 0) as pending_total,
          COALESCE(SUM(estimated_cost), 0) as all_total
        FROM expense_requests
      `);
      const byDept = await db.execute(sql`
        SELECT department, COUNT(*) as count,
          COALESCE(SUM(estimated_cost), 0) as total_cost,
          COUNT(*) FILTER (WHERE status = 'pending') as pending,
          COUNT(*) FILTER (WHERE status = 'approved') as approved
        FROM expense_requests WHERE department IS NOT NULL
        GROUP BY department ORDER BY total_cost DESC
      `);
      const byRequester = await db.execute(sql`
        SELECT requester_name, requester_id, COUNT(*) as count,
          COALESCE(SUM(estimated_cost), 0) as total_cost,
          COUNT(*) FILTER (WHERE status = 'pending') as pending,
          COUNT(*) FILTER (WHERE status = 'approved') as approved
        FROM expense_requests
        GROUP BY requester_name, requester_id ORDER BY total_cost DESC
      `);
      res.json({ totals: totals.rows[0], byDepartment: byDept.rows, byRequester: byRequester.rows });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

