  app.patch("/api/expense-requests/:id/approve", authenticateToken, async (req: any, res) => {
    try {
      if (!["admin", "planner"].includes(req.user.role)) return res.status(403).json({ message: "Only admins and planners can approve expenses" });
      const { id } = req.params;
      const { notes } = req.body;
      const existing = await db.execute(sql`SELECT * FROM expense_requests WHERE id = ${parseInt(id)}`);
      if (existing.rows.length === 0) return res.status(404).json({ message: "Request not found" });
      const expense = existing.rows[0] as any;

      let budgetItemId = null;
      if (expense.event_id) {
        try {
          const budgetResult = await db.execute(sql`
            INSERT INTO budget_items (id, event_id, category, item, description, estimated_cost, currency, status, priority)
            VALUES (${`exp-${id}-${Date.now()}`}, ${expense.event_id}, ${expense.category === 'equipment' ? 'Equipment & Technology' : expense.category === 'supplies' ? 'Stationery & Supplies' : expense.category === 'travel' ? 'Transport & Logistics' : expense.category === 'training' ? 'Staff & Human Resources' : expense.category === 'software' ? 'Equipment & Technology' : 'Miscellaneous'},
              ${expense.item_name}, ${expense.description || expense.reason || `Expense request by ${expense.requester_name}`},
              ${expense.estimated_cost}, ${expense.currency || 'GBP'}, ${'confirmed'}, ${expense.priority || 'medium'})
            RETURNING id
          `);
          if (budgetResult.rows.length > 0) budgetItemId = (budgetResult.rows[0] as any).id;
        } catch (budgetErr: any) {
          console.error("Failed to auto-create budget item from expense:", budgetErr.message);
        }
      }

      const result = await db.execute(sql`
        UPDATE expense_requests SET status = 'approved', approved_by = ${req.user.name || 'Admin'},
          approved_at = NOW(), notes = ${notes || expense.notes}, budget_item_id = ${budgetItemId}, updated_at = NOW()
        WHERE id = ${parseInt(id)} RETURNING *
      `);
      res.json(result.rows[0]);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

