  app.post("/api/polls/:id/vote", async (req: any, res) => {
    try {
      const { id } = req.params;
      const { option } = req.body;
      if (!option) {
        return res.status(400).json({ message: "Option is required" });
      }
      const pollResult = await db.execute(sql`SELECT * FROM polls WHERE id = ${id}`);
      if (pollResult.rows.length === 0) {
        return res.status(404).json({ message: "Poll not found" });
      }
      const poll = pollResult.rows[0] as any;
      if (poll.status !== "active") {
        return res.status(400).json({ message: "This poll is closed" });
      }
      const votes = poll.votes || {};
      if (!(option in votes)) {
        return res.status(400).json({ message: "Invalid option" });
      }
      votes[option] = (votes[option] || 0) + 1;
      await db.execute(sql`UPDATE polls SET votes = ${JSON.stringify(votes)}::jsonb WHERE id = ${id}`);
      res.json({ message: "Vote recorded", votes });
    } catch (error) {
      console.error("Error recording vote:", error);
      res.status(500).json({ message: "Failed to record vote" });
    }
  });

