  async function loadBidVaultContext(): Promise<string> {
    try {
      const docsResult = await db.execute(sql`
        SELECT bvf.file_name, bvf.notes, bvf.file_type, bvfl.name as folder_name
        FROM bid_vault_files bvf
        LEFT JOIN bid_vault_folders bvfl ON bvf.folder_id = bvfl.id
        ORDER BY bvfl.name, bvf.created_at DESC
        LIMIT 50
      `);
      if (docsResult.rows.length === 0) return "";

      const lessonsLearnt = (docsResult.rows as any[]).filter((d: any) => d.folder_name === "Lessons Learnt" && d.notes);
      const otherDocs = (docsResult.rows as any[]).filter((d: any) => d.folder_name !== "Lessons Learnt");

      const lines = otherDocs.map((d: any) =>
        `- [${d.folder_name || "Unfiled"}] ${d.file_name}${d.notes ? ` — ${d.notes}` : ""}`
      );

      let lessonsContext = "";
      if (lessonsLearnt.length > 0) {
        lessonsContext = "\n\n=== LESSONS LEARNT FROM PAST BIDS ===\nIMPORTANT: Apply these lessons when writing bid responses. Avoid past mistakes and build on what worked.\n" +
          lessonsLearnt.map((d: any) => `\n• ${d.file_name}: ${d.notes}`).join("");
      }

      const tenderDocsResult = await db.execute(sql`
        SELECT td.name, td.section_label, td.content, t.title as tender_title
        FROM tender_documents td
        JOIN tenders t ON td.tender_id = t.id
        WHERE td.status = 'final' AND td.content IS NOT NULL AND td.content != ''
        ORDER BY td.created_at DESC LIMIT 20
      `);
      let pastBidContent = "";
      if (tenderDocsResult.rows.length > 0) {
        pastBidContent = "\n\n=== FINALISED BID SECTIONS FROM PREVIOUS TENDERS ===\n" +
          tenderDocsResult.rows.map((d: any) =>
            `\n--- ${d.tender_title} > ${d.section_label || d.name} ---\n${(d.content || "").slice(0, 1500)}`
          ).join("\n");
      }
      return `\n\n=== BID VAULT — STORED DOCUMENTS ===\n${lines.join("\n")}${lessonsContext}${pastBidContent}`;
    } catch (e: any) {
      console.error("Bid vault context load error:", e.message);
      return "";
    }
  }

