  app.get("/api/tender-feed/ted-eu", authenticateTenderUser, async (req: any, res) => {
    // TED EU — real API call (replaces previous AI hallucination approach)
    const keyword = (req.query.keyword as string) || "event management";
    try {
      const limit = Math.min(parseInt(req.query.size as string) || 15, 30);
      const url = `https://ted.europa.eu/api/v2.0/notices/search?q=${encodeURIComponent(keyword)}&pageNum=1&pageSize=${limit}&scope=ACTIVE`;
      const tedRes = await fetch(url, {
        headers: { Accept: "application/json", "User-Agent": "Mozilla/5.0 (compatible; EventPerfekt/1.0)" },
        signal: AbortSignal.timeout(18000),
      });
      if (!tedRes.ok) {
        return res.json({ tenders: [], total: 0, keyword, note: `TED EU returned HTTP ${tedRes.status}` });
      }
      const ct = tedRes.headers.get("content-type") || "";
      if (!ct.includes("json")) {
        return res.json({ tenders: [], total: 0, keyword, note: "TED EU returned non-JSON response" });
      }
      const data = await tedRes.json() as any;
      const now = new Date();
      const notices: any[] = data?.results || data?.notices || data?.data || [];
      const tenders = notices
        .filter((n: any) => {
          const dl = n.deadlineForSubmission || n.deadline || "";
          return !dl || new Date(dl) > now;
        })
        .map((n: any) => {
          const docNo = n.docNo || n.id || "";
          return {
            title: (n.title || "").trim().slice(0, 250),
            description: (n.shortDescription || n.description || "").toString().slice(0, 300),
            buyer: n.orgName || n.authorityName || "EU Contracting Authority",
            value_amount: n.value || null,
            value_currency: n.valueCode || "EUR",
            deadline: n.deadlineForSubmission ? n.deadlineForSubmission.split("T")[0] : "",
            published: n.publicationDate ? n.publicationDate.split("T")[0] : "",
            status: "Open",
            source: "TED (EU)",
            source_url: docNo
              ? `https://ted.europa.eu/udl?uri=TED:NOTICE:${docNo}:TEXT:EN:HTML`
              : "https://ted.europa.eu/",
            region: "EU",
          };
        });
      res.json({ tenders, total: tenders.length, keyword, source: "TED/EU" });
    } catch (error: any) {
      console.error("TED/EU search error:", error.message);
      res.json({ tenders: [], total: 0, keyword, note: "TED/EU search unavailable" });
    }
  });

