  app.post("/api/tender-ai/assistant", authenticateTenderUser, async (req: any, res) => {
    try {
      const { messages } = req.body;
      if (!messages || !Array.isArray(messages) || messages.length === 0) {
        return res.status(400).json({ message: "Messages array is required" });
      }

      let companyContext = "";
      try {
        const profileResult = await db.execute(sql`SELECT * FROM tender_company_profile LIMIT 1`);
        if (profileResult.rows.length > 0) {
          const p = profileResult.rows[0] as any;
          companyContext = `
COMPANY: ${p.company_name || "Event Perfekt Global Ltd"} (Companies House: ${p.company_number || "15678934"})
Director: ${p.directors || "Tolulope Kumolu Johnson"}
UK Address: ${p.registered_address || "20 Wenlock Road, London, N1 7PG"}
Nigeria Entity: ${p.ng_company_name || "Event Perfekt Management Services Limited"}
Services: ${p.sector_experience || "Events, Conferences, PMO, GDPR, Training, International Development"}
Policies: ${p.policies || "GDPR, H&S, Safeguarding, Equal Opportunities, Environmental, Modern Slavery"}`;
        }
      } catch (e: any) { console.error("Assistant profile load:", e.message); }

      let tendersContext = "";
      try {
        const tendersResult = await db.execute(sql`
          SELECT id, title, buyer, status, deadline, value_amount, category, reference_number
          FROM tenders ORDER BY created_at DESC LIMIT 50
        `);
        if (tendersResult.rows.length > 0) {
          const rows = tendersResult.rows as any[];
          const byStatus: Record<string, any[]> = {};
          rows.forEach(t => {
            const s = (t.status || "Active").toUpperCase();
            if (!byStatus[s]) byStatus[s] = [];
            byStatus[s].push(t);
          });
          tendersContext = "\n\n=== CURRENT TENDERS (from database) ===\n";
          for (const [status, tenders] of Object.entries(byStatus)) {
            tendersContext += `\n--- ${status} (${tenders.length}) ---\n`;
            tenders.forEach(t => {
              tendersContext += `• [ID:${t.id}] "${t.title}" — Buyer: ${t.buyer || "N/A"}, Deadline: ${t.deadline || "N/A"}, Value: ${t.value_amount ? `£${Number(t.value_amount).toLocaleString()}` : "N/A"}, Category: ${t.category || "N/A"}, Ref: ${t.reference_number || "N/A"}\n`;
            });
          }

          const pipeline: Record<string, { count: number; value: number }> = {};
          rows.forEach(t => {
            const s = (t.status || "Active");
            if (!pipeline[s]) pipeline[s] = { count: 0, value: 0 };
            pipeline[s].count++;
            pipeline[s].value += Number(t.value_amount || 0);
          });
          tendersContext += "\n--- PIPELINE SUMMARY ---\n";
          for (const [status, data] of Object.entries(pipeline)) {
            tendersContext += `${status}: ${data.count} tenders, total value £${data.value.toLocaleString()}\n`;
          }
        }
      } catch (e: any) { console.error("Assistant tenders load:", e.message); }

      let docsContext = "";
      try {
        const docsResult = await db.execute(sql`
          SELECT td.name, td.section_label, td.status as doc_status, td.content,
                 t.title as tender_title, t.id as tender_id
          FROM tender_documents td
          JOIN tenders t ON td.tender_id = t.id
          ORDER BY td.created_at DESC LIMIT 30
        `);
        if (docsResult.rows.length > 0) {
          docsContext = "\n\n=== BID DOCUMENTS STATUS ===\n";
          const byTender: Record<string, any[]> = {};
          (docsResult.rows as any[]).forEach(d => {
            const key = `[ID:${d.tender_id}] ${d.tender_title}`;
            if (!byTender[key]) byTender[key] = [];
            byTender[key].push(d);
          });
          for (const [tender, docs] of Object.entries(byTender)) {
            const total = docs.length;
            const final = docs.filter((d: any) => d.doc_status === "final").length;
            const draft = docs.filter((d: any) => d.doc_status === "draft").length;
            docsContext += `\n${tender}: ${total} sections (${final} final, ${draft} draft)\n`;
            docs.forEach((d: any) => {
              docsContext += `  - ${d.section_label || d.name}: ${(d.doc_status || "draft").toUpperCase()}${d.content ? ` (${d.content.length} chars)` : " (empty)"}\n`;
            });
          }
        }
      } catch (e: any) { console.error("Assistant docs load:", e.message); }

      let requirementsContext = "";
      try {
        const reqResult = await db.execute(sql`
          SELECT tr.*, t.title as tender_title FROM tender_requirements tr
          JOIN tenders t ON tr.tender_id = t.id
          ORDER BY tr.created_at DESC LIMIT 50
        `);
        if (reqResult.rows.length > 0) {
          requirementsContext = "\n\n=== COMPLIANCE REQUIREMENTS ===\n";
          const byTender: Record<string, any[]> = {};
          (reqResult.rows as any[]).forEach(r => {
            if (!byTender[r.tender_title as string]) byTender[r.tender_title as string] = [];
            byTender[r.tender_title as string].push(r);
          });
          for (const [tender, reqs] of Object.entries(byTender)) {
            const met = reqs.filter((r: any) => r.is_met).length;
            requirementsContext += `\n${tender}: ${met}/${reqs.length} requirements met\n`;
            reqs.forEach((r: any) => {
              requirementsContext += `  ${r.is_met ? "✅" : "❌"} [${(r.category || "general").toUpperCase()}] ${r.requirement}\n`;
            });
          }
        }
      } catch (e: any) { console.error("Assistant requirements load:", e.message); }

      const bidVaultCtx = await loadBidVaultContext();

      const systemPrompt = `You are EP Agent — Event Perfekt's intelligent tender management assistant. You have FULL ACCESS to the company's live tender database, bid documents, compliance requirements, company profile, and bid vault.

Your capabilities:
1. CHECK BID STATUS — Look up any tender by name, ID, or reference and report its status, deadline, documents progress, and compliance
2. PIPELINE OVERVIEW — Summarise the full pipeline by stage with counts and values
3. BID READINESS — For any tender, check how many bid sections are complete (final vs draft), what requirements are met/unmet
4. STRATEGIC ADVICE — Recommend next steps, flag approaching deadlines, suggest priorities
5. COMPANY KNOWLEDGE — Answer any question about Event Perfekt's capabilities, policies, experience, and team
6. SEARCH GUIDANCE — Suggest keywords, CPV codes, and portals for finding relevant tenders

IMPORTANT RULES:
- Always reference REAL data from the context below — never make up tender names, IDs, or statuses
- When asked about a specific tender, search through the data and give precise details
- When asked to "check" or "close" a bid, provide the current status and what actions are needed
- Be concise but thorough — use bullet points for clarity
- If you can't find something in the data, say so honestly
- Format responses clearly with headers and structure

${companyContext}
${tendersContext}
${docsContext}
${requirementsContext}
${bidVaultCtx}`;

      const chatMessages = [
        { role: "system" as const, content: systemPrompt },
        ...messages.slice(-10).map((m: any) => ({
          role: m.role as "user" | "assistant",
          content: m.content,
        })),
      ];

      const conversationMessages = chatMessages
        .filter((m: any) => m.role !== "system")
        .map((m: any) => ({ role: m.role as "user" | "assistant", content: m.content }));
      const content = await callClaudeChat(systemPrompt, conversationMessages, 3000);
      res.json({ content: content || "I couldn't process that request." });
    } catch (error: any) {
      console.error("Agent error:", error.message);
      res.status(500).json({ message: error.message });
    }
  });

