  async function fetchAllRelevantTenders(): Promise<any[]> {
    const searchTerms = [
      "event management", "conference management", "event planning",
      "training services", "capacity building", "corporate gifts",
      "souvenirs", "stakeholder engagement", "programme management",
      "hospitality services", "venue management", "exhibition",
      "FCDO", "DEFRA", "international development",
      "consultancy services", "GDPR", "data protection",
      "data privacy", "information governance", "DPO services",
      "security services", "cyber security", "it services",
      "payments", "electronic payments", "disbursements",
      "direct payments", "appointeeships", "managing agent",
    ];
    const now = new Date();
    const minDeadline = new Date("2026-01-01");
    const closedStatuses = ["closed", "cancelled", "complete", "awarded", "unsuccessful", "withdrawn"];
    const seen = new Set<string>();
    const allTenders: any[] = [];
    const publishedFrom = `2025-01-01`;

    for (const term of searchTerms) {
      try {
        const apiUrl = `https://www.contractsfinder.service.gov.uk/Published/Notices/OCDS/Search?queryString=${encodeURIComponent(term)}&stage=tender&output=json&publishedFrom=${publishedFrom}&size=100`;
        const response = await fetch(apiUrl, { headers: { "Accept": "application/json" }, signal: AbortSignal.timeout(15000) });
        if (!response.ok) continue;
        const data = await response.json() as any;
        for (const r of (data?.releases || [])) {
          const tender = r.tender || {};
          const status = (tender.status || "").toLowerCase();
          if (closedStatuses.includes(status)) continue;
          const deadlineStr = tender.tenderPeriod?.endDate || "";
          if (!deadlineStr) continue;
          const deadlineDate = new Date(deadlineStr);
          if (deadlineDate < minDeadline) continue;
          const title = tender.title || "";
          const desc = tender.description || "";
          if (!isRelevantTender(title, desc)) continue;
          if (seen.has(title)) continue;
          seen.add(title);
          const buyer = r.buyer || {};
          const value = tender.value || tender.minValue || {};
          const idParts = (r.id || "").split("-");
          const noticeGuid = idParts.length >= 5 ? idParts.slice(0, 5).join("-") : r.id || "";
          allTenders.push({
            title, description: desc.slice(0, 300),
            buyer: buyer.name || "Not specified",
            value_amount: value.amount || null, value_currency: value.currency || "GBP",
            deadline: deadlineStr.split("T")[0],
            published: r.date ? r.date.split("T")[0] : "",
            source_url: noticeGuid ? `https://www.contractsfinder.service.gov.uk/Notice/${noticeGuid}` : "",
            source: "Contracts Finder",
            ext_id: r.id || noticeGuid || "",
          });
        }
      } catch {}
    }

    const ftTerms = ["HMRC", "HM Revenue Customs", "event management", "conference", "training delivery", "FCDO", "DEFRA", "programme management", "GDPR", "data protection", "capacity building", "corporate gifts"];
    for (const term of ftTerms) {
      try {
        const apiUrl = `https://www.find-tender.service.gov.uk/api/1.0/ocdsReleasePackages?queryString=${encodeURIComponent(term)}&stage=tender&size=50`;
        const response = await fetch(apiUrl, { headers: { "Accept": "application/json" }, signal: AbortSignal.timeout(15000) });
        if (!response.ok) continue;
        const data = await response.json() as any;
        const packages = data?.results || data?.releasePackages || data || [];
        const releasesArr = Array.isArray(packages) ? packages : [];
        for (const pkg of releasesArr) {
          const releases = pkg.releases || [pkg];
          for (const r of releases) {
            const tender = r.tender || {};
            const status = (tender.status || "").toLowerCase();
            if (closedStatuses.includes(status)) continue;
            const deadlineStr = tender.tenderPeriod?.endDate || "";
            if (!deadlineStr) continue;
            const deadlineDate = new Date(deadlineStr);
            if (deadlineDate < minDeadline) continue;
            const title = tender.title || "";
            const desc = tender.description || "";
            if (!isRelevantTender(title, desc)) continue;
            if (seen.has(title)) continue;
            seen.add(title);
            const buyer = r.buyer || {};
            const value = tender.value || {};
            const noticeId = (r.id || r.ocid || "").split("-").slice(0, 5).join("-");
            allTenders.push({
              title, description: desc.slice(0, 300),
              buyer: buyer.name || "Not specified",
              value_amount: value.amount || null, value_currency: value.currency || "GBP",
              deadline: deadlineStr.split("T")[0],
              published: r.date ? r.date.split("T")[0] : "",
              source_url: noticeId ? `https://www.find-tender.service.gov.uk/Notice/${noticeId}` : "",
              source: "Find a Tender",
              ext_id: r.id || r.ocid || noticeId || "",
            });
          }
        }
      } catch {}
    }

    // ── Add SAM.gov (US Federal Procurement) ────────────────────────────────────
    const samTerms = ["event management", "conference", "training", "corporate gifts", "consultancy"];
    for (const term of samTerms) {
      try {
        const samTenders = await searchSamGov(term, 20);
        for (const t of samTenders) {
          if (seen.has(t.title)) continue;
          seen.add(t.title);
          const deadline = t.deadline || t.postedDate;
          if (!deadline) continue;
          const deadlineDate = new Date(deadline);
          if (deadlineDate < minDeadline) continue;
          allTenders.push({
            title: t.title || "",
            description: (t.description || t.summary || "").slice(0, 300),
            buyer: t.agency || t.buyer || "US Federal",
            value_amount: t.estimatedAmount || null,
            value_currency: "USD",
            deadline: deadline.split("T")?.[0] || deadline,
            published: t.postedDate?.split("T")?.[0] || "",
            source_url: t.url || t.source_url || "",
            source: "SAM.gov",
            ext_id: t.id || t.opportunityId || "",
          });
        }
      } catch (err) { console.error("SAM.gov fetch error:", err); }
    }

    // ── Add TED (EU Tender Electronic Daily) ───────────────────────────────────
    const tedTerms = ["event management", "conference", "training", "consulting"];
    for (const term of tedTerms) {
      try {
        const apiUrl = `https://ted.europa.eu/api/hub/search/openTendersXml?queryText=${encodeURIComponent(term)}&scope=NOTICE&pageSize=50`;
        const response = await fetch(apiUrl, { signal: AbortSignal.timeout(10000) });
        if (!response.ok) continue;
        const data = await response.json() as any;
        const results = data?.results || [];
        for (const r of results) {
          const title = r.title || r.textTitle || "";
          if (seen.has(title)) continue;
          seen.add(title);
          const deadline = r.deadline || r.deadlineRcDate || "";
          if (!deadline) continue;
          const deadlineDate = new Date(deadline);
          if (deadlineDate < minDeadline) continue;
          allTenders.push({
            title,
            description: (r.description || r.shortSummary || "").slice(0, 300),
            buyer: r.buyer || r.buyerName || "EU Buyer",
            value_amount: r.estimatedAmount || null,
            value_currency: "EUR",
            deadline: deadline.split("T")?.[0] || deadline,
            published: r.publicationDate?.split("T")?.[0] || "",
            source_url: r.noticeUrl || `https://ted.europa.eu/search?query=${encodeURIComponent(title)}`,
            source: "TED (EU)",
            ext_id: r.id || r.noticeNumber || "",
          });
        }
      } catch (err) { console.error("TED fetch error:", err); }
    }

    // ── Add Nigeria BPP (Nigeria Bureau of Public Procurement) ──────────────────
    const ngTerms = ["event management", "conference", "training", "corporate gifts"];
    for (const term of ngTerms) {
      try {
        // Note: Nigeria BPP may require authentication. This is a fallback search.
        const apiUrl = `https://www.bpp.gov.ng/api/tender/search?keyword=${encodeURIComponent(term)}&limit=20`;
        const response = await fetch(apiUrl, { signal: AbortSignal.timeout(10000) });
        if (!response.ok) continue;
        const data = await response.json() as any;
        const results = Array.isArray(data) ? data : data?.results || [];
        for (const r of results) {
          const title = r.title || r.tenderTitle || "";
          if (seen.has(title)) continue;
          seen.add(title);
          const deadline = r.deadline || r.closingDate || "";
          if (!deadline) continue;
          const deadlineDate = new Date(deadline);
          if (deadlineDate < minDeadline) continue;
          allTenders.push({
            title,
            description: (r.description || r.scope || "").slice(0, 300),
            buyer: r.buyer || r.procuringEntity || "Nigeria Government",
            value_amount: r.estimatedValue || null,
            value_currency: "NGN",
            deadline: deadline.split("T")?.[0] || deadline,
            published: r.publishedDate?.split("T")?.[0] || "",
            source_url: r.url || `https://www.bpp.gov.ng/tender/${r.id || ""}`,
            source: "Nigeria BPP",
            ext_id: r.id || r.tenderNumber || "",
          });
        }
      } catch (err) { console.error("Nigeria BPP fetch error:", err); }
    }

    allTenders.sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime());
    return allTenders;
  }

  async function fetchAllTenderResults(): Promise<any[]> {
    const tenders = await fetchAllRelevantTenders();
    if (tenders.length > 0) return tenders;
    const fallback: any[] = [];
    try {
      const response = await fetch(`https://www.contractsfinder.service.gov.uk/Published/Notices/OCDS/Search?queryString=${encodeURIComponent("tender")}&stage=tender&output=json&publishedFrom=2025-01-01&size=100`, {
        headers: { "Accept": "application/json" },
        signal: AbortSignal.timeout(15000),
      });
      if (response.ok) {
        const data = await response.json() as any;
        for (const r of (data?.releases || [])) {
          const tender = r.tender || {};
          const title = tender.title || "";
          const deadline = tender.tenderPeriod?.endDate || "";
          if (!title || !deadline) continue;
          fallback.push({
            title,
            description: (tender.description || "").slice(0, 300),
            buyer: r.buyer?.name || "Not specified",
            value_amount: tender.value?.amount || null,
            value_currency: tender.value?.currency || "GBP",
            deadline: deadline.split("T")[0],
            published: r.date ? r.date.split("T")[0] : "",
            source_url: r.id ? `https://www.contractsfinder.service.gov.uk/Notice/${r.id.split("-").slice(0, 5).join("-")}` : "",
            source: "Contracts Finder",
          });
        }
      }
    } catch {}
    return fallback.slice(0, 20);
  }

