  app.post("/api/tender-requirements/:tenderId/extract", authenticateTenderUser, async (req: any, res) => {
    try {
      const tenderId = parseInt(req.params.tenderId);
      const tender = await db.execute(sql`SELECT * FROM tenders WHERE id = ${tenderId}`);
      if (tender.rows.length === 0) return res.status(404).json({ message: "Tender not found" });
      const t = tender.rows[0] as any;

      const docs = await db.execute(sql`SELECT name, content, section_label FROM tender_documents WHERE tender_id = ${tenderId} AND content IS NOT NULL AND content != '' LIMIT 10`);
      const docContext = docs.rows.map((d: any) => `[${d.section_label || d.name}]: ${(d.content || "").slice(0, 1000)}`).join("\n\n");

      const profileResult = await db.execute(sql`SELECT * FROM tender_company_profile LIMIT 1`);
      const profile = profileResult.rows[0] as any || {};

      const response = await tenderOpenAI.chat.completions.create({
        model: "gpt-4o-mini",
        messages: [
          { role: "system", content: `You are a bid compliance analyst. Analyse the tender and extract all requirements. Return a JSON array of objects with: requirement_type (one of: mandatory, insurance, certification, document, deadline, evaluation, staffing, financial, technical, compliance), description (clear requirement statement), sort_order (number). Group by type. Include all mandatory requirements, insurance levels, certifications needed, documents to submit, evaluation criteria, word limits, staffing requirements, and financial requirements. Be thorough and specific. Return ONLY valid JSON array.` },
          { role: "user", content: `Tender: ${t.title}\nBuyer: ${t.buyer}\nCategory: ${t.category}\nValue: ${t.value_text}\nDeadline: ${t.deadline}\nScoring Criteria: ${t.scoring_criteria || "Not specified"}\nWord Limits: ${t.word_limits || "Not specified"}\nNotes: ${t.notes || ""}\n\nCompany Profile:\n- Insurance PII: ${profile.insurance_pii || "Not provided"}\n- Insurance PL: ${profile.insurance_public_liability || "Not provided"}\n- Certifications: ${profile.certifications || "Not provided"}\n- Policies: ${profile.policies || "Not provided"}\n\nTender Documents:\n${docContext || "No documents uploaded yet"}` }
        ],
        temperature: 0.3, max_tokens: 3000,
      });

      const content = response.choices[0]?.message?.content || "[]";
      const jsonMatch = content.match(/\[[\s\S]*\]/);
      if (!jsonMatch) return res.status(500).json({ message: "Failed to parse requirements" });

      const requirements = JSON.parse(jsonMatch[0]);
      await db.execute(sql`DELETE FROM tender_requirements WHERE tender_id = ${tenderId}`);

      let inserted = 0;
      for (const req of requirements) {
        await db.execute(sql`INSERT INTO tender_requirements (tender_id, requirement_type, description, sort_order) VALUES (${tenderId}, ${req.requirement_type || "mandatory"}, ${req.description}, ${req.sort_order || inserted})`);
        inserted++;
      }

      const result = await db.execute(sql`SELECT * FROM tender_requirements WHERE tender_id = ${tenderId} ORDER BY sort_order ASC`);
      res.json({ message: `${inserted} requirements extracted`, requirements: result.rows });
    } catch (error: any) {
      console.error("Requirements extraction error:", error.message);
      res.status(500).json({ message: error.message });
    }
  });

