  app.get("/api/procurement-intelligence", optionalTenderAuth, async (req: any, res) => {
    try {
      const { category, country, watchlistOnly } = req.query;
      let query = `SELECT pi.*, 
        CASE WHEN pw.id IS NOT NULL THEN true ELSE false END as on_watchlist
        FROM procurement_intelligence pi
        LEFT JOIN procurement_intel_watchlist pw ON pw.intel_id = pi.id
      `;
      const conditions: string[] = ["pi.ai_generated = false"];
      if (category && category !== "all") conditions.push(`pi.category = '${category.replace(/'/g, "''")}'`);
      if (country && country !== "all") conditions.push(`pi.country = '${country.replace(/'/g, "''")}'`);
      if (watchlistOnly === "true") conditions.push(`pw.id IS NOT NULL`);
      if (conditions.length > 0) query += " WHERE " + conditions.join(" AND ");
      query += " ORDER BY pi.created_at DESC LIMIT 100";
      const result = await db.execute(sql.raw(query));
      const items = (result.rows as any[]).map(item => {
        if (item.source && item.title) {
          item.source_url = resolveSourceUrl(item.source, item.source_url || "", item.title);
        }
        return item;
      });
      res.json(items);
    } catch (error: any) { res.status(500).json({ message: error.message }); }
  });

