  function resolveSourceUrl(source: string, aiUrl: string, title?: string): string {
    const extractKeywords = (t: string) => {
      const stopWords = new Set(["the", "a", "an", "of", "for", "in", "to", "and", "is", "has", "new", "via", "on", "its", "by", "with", "from", "at", "as", "this", "that", "are", "was", "been"]);
      return t.replace(/[^a-zA-Z0-9\s]/g, "").split(/\s+/).filter(w => w.length > 2 && !stopWords.has(w.toLowerCase())).slice(0, 5).join(" ");
    };
    const keywords = title ? extractKeywords(title) : "";

    const entry = SEARCHABLE_SOURCE_URLS[source];
    if (entry) return keywords ? entry.searchUrl(keywords) : entry.base;

    for (const [key, val] of Object.entries(SEARCHABLE_SOURCE_URLS)) {
      if (source.toLowerCase().includes(key.toLowerCase()) || key.toLowerCase().includes(source.toLowerCase())) {
        return keywords ? val.searchUrl(keywords) : val.base;
      }
    }

    if (aiUrl && aiUrl.startsWith("https://") && !aiUrl.includes("example.com")) {
      const domain = aiUrl.split("/")[2] || "";
      const realDomains = ["gov.uk", "ungm.org", "undp.org", "unicef.org", "worldbank.org", "afdb.org", "crowncommercial.gov.uk", "bpp.gov.ng", "ico.org.uk", "europa.eu"];
      if (realDomains.some(d => domain.includes(d))) return aiUrl;
    }
    return "";
  }

