    try {
      const { tenders } = req.body || {};
      if (!Array.isArray(tenders) || tenders.length === 0) return res.json({ imported: 0 });
      let imported = 0;
      for (const t of tenders) {
        if (!t.title) continue;
        const exists = await db.execute(sql`SELECT id FROM procurement_intelligence WHERE title = ${t.title}`);
        if (exists.rows.length === 0) {
          await db.execute(sql`
            INSERT INTO procurement_intelligence
              (title, summary, source, source_url, country, category, item_type, published_date, is_new, ai_generated)
            VALUES
              (${t.title}, ${t.summary || ""}, ${t.source || "Live Feed"}, ${t.source_url || null},
               ${t.country || "UK"}, ${t.category || "Tender"}, ${t.item_type || "tender"},
               ${t.published_date || new Date().toISOString()}, true, false)
          `);
          imported++;
        }
      }
      res.json({ imported, total: tenders.length });
    } catch (error: any) { res.status(500).json({ message: error.message }); }
