  let digestInterval: any = null;
  let lastDigestDate = ""; // prevents re-fire when server restarts inside the 7am window
  function startDailyDigest() {
    if (digestInterval) clearInterval(digestInterval);
    const checkAndSend = async () => {
      const now = new Date();
      if (now.getHours() === 7 && now.getMinutes() < 5) {
        const today = now.toISOString().split("T")[0];
        if (lastDigestDate === today) return; // already sent today — skip
        lastDigestDate = today;
        console.log("Running daily tender digest + intelligence scan...");
        try {
          // Run intelligence scan
          try {
            const existingIntel = await db.execute(sql`SELECT COUNT(*)::int as cnt FROM procurement_intelligence WHERE created_at > NOW() - INTERVAL '12 hours'`);
            if ((existingIntel.rows[0] as any).cnt === 0) {
              const intelResponse = await tenderOpenAI.chat.completions.create({
                model: "gpt-4o-mini",
                messages: [
                  { role: "system", content: `You are a procurement intelligence analyst. Generate a JSON array of 12-15 current procurement intelligence items covering: Framework Announcements, Funding Programmes, Procurement News, Tender Alerts, Remittance & Payments, Africa Programmes, Donor Announcements. Sources: Contracts Finder, Find a Tender, UNGM, UNDP, UNICEF, World Bank, AfDB, FCDO, Nigeria BPP, CCS. Countries: UK, Nigeria, Ghana, Kenya, Multi-country, Global, Africa. Return ONLY valid JSON array with: title, summary, source, source_url, country, category, item_type, published_date.` },
                  { role: "user", content: `Generate procurement intelligence for ${now.toLocaleDateString("en-GB")}.` }
                ],
                temperature: 0.8, max_tokens: 4000,
              });
              const intelContent = intelResponse.choices[0]?.message?.content || "[]";
              const intelMatch = intelContent.match(/\[[\s\S]*\]/);
              if (intelMatch) {
                const intelItems = JSON.parse(intelMatch[0]);
                for (const item of intelItems) {
                  const exists = await db.execute(sql`SELECT id FROM procurement_intelligence WHERE title = ${item.title}`);
                  if (exists.rows.length === 0) {
                    const resolvedUrl = resolveSourceUrl(item.source || "", item.source_url || "", item.title || "");
                    await db.execute(sql`INSERT INTO procurement_intelligence (title, summary, source, source_url, country, category, item_type, published_date, is_new, ai_generated) VALUES (${item.title}, ${item.summary}, ${item.source}, ${resolvedUrl}, ${item.country || "UK"}, ${item.category || "Procurement News"}, ${item.item_type || "news"}, ${item.published_date || now.toISOString().split("T")[0]}, true, true)`);
                  }
                }
                console.log(`Intelligence scan: ${intelItems.length} items processed`);
              }
            }
          } catch (intelErr: any) { console.error("Intelligence scan error:", intelErr.message); }

          const tenders = await fetchAllRelevantTenders();

          // ── EP Domain Scoring ────────────────────────────────────────────────
          // Scores each tender 0–100 based on genuine EP business fit.
          // Only tenders scoring ≥ 15 surface in the digest.
          // Buyers producing consistently zero-fit tenders are logged to audit.

          // Hard negative title patterns — instant 0 score, logged to audit
          // NOTE: Use \b word-boundaries on the final word to avoid false-positive matches.
          // e.g. /\bworks\b/ avoids matching "workshop"; /\bworks\b/ won't match "workshop"
          const digestNegativeTitlePatterns = [
            /\benergy storage\b/,
            /\bhousehold appliance/,
            /\bdomestic appliance/,
            /\bwhite goods\b/,
            /\bflatbed\b/,
            /pick.?up truck/,
            /procurement of vehicle/,
            /procurement of.*truck\b/,
            /procurement of.*appliance/,
            /procurement of energy\b/,
            /procurement of.*generator/,
            /procurement of.*fuel\b/,
            /procurement of.*spare part/,
            /supply of.*vehicle\b/,
            /supply of.*truck\b/,
            /supply of.*appliance\b/,
            /supply of.*generator\b/,
            /procurement of.*solar\b/,
            /procurement of.*battery\b/,
            /\bcivil works\b/,
            /\broad works\b/,
            /\bconstruction works\b/,
            /\bbuilding works\b/,
            /procurement of furniture/,
            /medical.*supplies/,
            /\bpharmaceutical\b/,
            /\blaboratory.*equipment/,
            /procurement of.*electrical\b/,
            /\bsupply of fuel\b/,
            /\bafter[- ]school\b/,
            /\bholiday clubs?\b/,
            /\bchild[- ]friendly\b/,
            /\bchild care\b/,
            /\bchildcare\b/,
            /\bchildren'?s centre\b/,
            /\bschool(s)?\b/,
            /\beducation(al)?\b/,
            /\bacademy|academies\b/,
            /\btemporary accommodation\b/,
            /\byouth clubs?\b/,
            /\bcare leavers?\b/,
            /\bsocial and emotional support\b/,
            /\bemotional support\b/,
            /\bsupport programmes?\b/,
            /\bcommunity programmes?\b/,
            /\bthriving together\b/,
            /\bmens? sheds\b/,
            /\bshared bench\b/,
          ];

          // EP domain positive scoring keywords — title match = 12 pts, description match = 6 pts
          const epTitleKeywords = [
            "event management", "conference management", "event planning", "event production",
            "event coordination", "hospitality services", "catering services",
            "venue management", "exhibition management", "gala", "awards ceremony",
            "summit", "symposium", "stakeholder engagement", "programme management",
            "training delivery", "capacity building", "workshop facilitation",
            "brand activation", "product launch", "corporate event", "corporate hospitality",
            "team building", "meeting room", "event decor", "wedding planning",
            "data protection", "gdpr", "dpo services", "information governance",
            "direct payment", "managing agent", "disbursements", "appointeeships",
            "remittance", "cross-border payment", "financial inclusion", "mobile money",
            "fcdo", "uk-africa", "africa programme", "international development",
          ];
          const epDescKeywords = [
            "event", "conference", "hospitality", "catering", "venue", "exhibition",
            "summit", "workshop", "training delivery", "stakeholder", "programme delivery",
            "decor", "entertainment", "ceremony", "delegation", "gala", "award",
            "gdpr", "data protection", "remittance", "diaspora", "financial inclusion",
            "capacity building", "fcdo", "africa", "nigeria",
          ];

          // Known zero-fit buyer watchlist — tenders from these are logged but not blocked
          const zeroFitBuyerWatchlist = [
            "chemonics international", "chemonics",
          ];

          type ScoredTender = { tender: any; score: number; reasons: string[] };
          const scored: ScoredTender[] = [];
          const auditLog: { title: string; buyer: string; reason: string }[] = [];

          for (const t of tenders) {
            const title = (t.title || "").toLowerCase();
            const desc = (t.description || "").toLowerCase(); // FIX: was t.summary (undefined)
            const buyer = (t.buyer || "").toLowerCase();

            // Check watchlist buyers — log to audit regardless of outcome
            const isWatchlisted = zeroFitBuyerWatchlist.some(w => buyer.includes(w));

            // Hard negative title check
            let hardRejected = false;
            let rejectReason = "";
            for (const p of digestNegativeTitlePatterns) {
              if (p.test(title)) { hardRejected = true; rejectReason = `Negative title pattern: ${p}`; break; }
            }
            if (hardRejected) {
              auditLog.push({ title: t.title || "", buyer: t.buyer || "", reason: rejectReason + (isWatchlisted ? " [WATCHLIST]" : "") });
              continue;
            }

            // Score
            let score = 0;
            const reasons: string[] = [];
            for (const kw of epTitleKeywords) {
              if (title.includes(kw)) { score += 12; reasons.push(`title:"${kw}"`); }
            }
            for (const kw of epDescKeywords) {
              if (desc.includes(kw) && !title.includes(kw)) { score += 6; reasons.push(`desc:"${kw}"`); }
            }

            if (score === 0) {
              auditLog.push({ title: t.title || "", buyer: t.buyer || "", reason: "Score 0 — no EP keyword match" + (isWatchlisted ? " [WATCHLIST]" : "") });
              continue;
            }
            if (isWatchlisted) {
              // Log watchlist match with their score — let them through only if score ≥ 15
              auditLog.push({ title: t.title || "", buyer: t.buyer || "", reason: `Score ${score} — watchlist buyer passed through` });
            }

            scored.push({ tender: t, score: Math.min(score, 100), reasons });
          }

          // Sort by score desc, take top 20
          scored.sort((a, b) => b.score - a.score);
          const eventPerfektTenders = scored.filter(s => s.score >= 15).slice(0, 20).map(s => s.tender);

          // Log audit entries to DB (best effort)
          if (auditLog.length > 0) {
            try {
              for (const entry of auditLog) {
                await db.execute(sql`
                  INSERT INTO tender_digest_audit (title, buyer, reason, audited_at)
                  VALUES (${entry.title}, ${entry.buyer}, ${entry.reason}, NOW())
                  ON CONFLICT DO NOTHING
                `).catch(() => {}); // table may not exist yet — suppress
              }
            } catch {}
            const watchlistHits = auditLog.filter(e => e.reason.includes("[WATCHLIST]"));
            if (watchlistHits.length > 0) {
              console.log(`[DigestAudit] Watchlist buyer hits today (${watchlistHits.length}):`, watchlistHits.map(e => `"${e.title}" (${e.buyer})`).join("; "));
            }
            console.log(`[DigestAudit] ${auditLog.length} tenders rejected, ${eventPerfektTenders.length} passed scoring (≥15)`);
          }

          // ── Value display helper — fix £1 bug ───────────────────────────────
          // Contracts Finder uses £1 as placeholder when value is undisclosed
          const fmtValue = (t: any): string => {
            const amt = parseFloat(t.value_amount);
            if (!t.value_amount || isNaN(amt) || amt <= 1) return "TBC";
            const currency = (t.value_currency || "GBP") === "USD" ? "$" : (t.value_currency === "EUR" ? "€" : "£");
            return `${currency}${Math.round(amt).toLocaleString("en-GB")}`;
          };

          const recipients = ["admin@eventperfekt.com", "adminuk@eventperfekt.com", "info@eventperfekt.com"];
          const dateLabel = now.toLocaleDateString("en-GB", { weekday: "long", year: "numeric", month: "long", day: "numeric" });

          if (eventPerfektTenders.length > 0) {
            const tenderRows = eventPerfektTenders.map((t: any) => `<tr><td style="padding:8px;border-bottom:1px solid #2a1520;"><a href="${t.source_url}" style="color:#C9A84C;text-decoration:none;">${t.title}</a><br/><span style="color:#999;font-size:11px;">${t.buyer}</span></td><td style="padding:8px;border-bottom:1px solid #2a1520;color:#C9A84C;">${fmtValue(t)}</td><td style="padding:8px;border-bottom:1px solid #2a1520;color:#ff9f43;">${t.deadline}</td><td style="padding:8px;border-bottom:1px solid #2a1520;"><a href="${t.source_url}" style="background:#C9A84C;color:#1A0A0E;padding:4px 10px;text-decoration:none;font-weight:700;font-size:11px;">VIEW</a></td></tr>`).join("");
            const digestHtml = `<div style="background:#1A0A0E;color:#f0e8dc;font-family:Arial,sans-serif;max-width:800px;margin:0 auto;"><div style="background:#330311;padding:20px;text-align:center;"><h1 style="color:#C9A84C;margin:0;">Event Perfekt Tender Digest</h1><p style="color:#f0e8dc;margin:4px 0 0;font-size:13px;">${dateLabel}</p></div><div style="padding:16px;"><p style="color:#C9A84C;font-size:13px;font-weight:700;">${eventPerfektTenders.length} RELEVANT TENDER${eventPerfektTenders.length === 1 ? "" : "S"} TODAY</p><p style="color:#888;font-size:11px;margin-top:-8px;">Scored ≥15/100 on EP domain fit · irrelevant tenders filtered out</p><table style="width:100%;border-collapse:collapse;"><thead><tr style="border-bottom:2px solid #C9A84C;"><th style="text-align:left;padding:8px;color:#C9A84C;font-size:11px;">TENDER</th><th style="text-align:left;padding:8px;color:#C9A84C;font-size:11px;">VALUE</th><th style="text-align:left;padding:8px;color:#C9A84C;font-size:11px;">DEADLINE</th><th></th></tr></thead><tbody>${tenderRows}</tbody></table></div><div style="background:#330311;padding:12px;text-align:center;font-size:11px;color:#999;">Event Perfekt Global Ltd | London & Lagos</div></div>`;
            try {
              for (const recipient of recipients) {
                await emailService.sendEmail(recipient, `EP Tender Digest — ${eventPerfektTenders.length} match${eventPerfektTenders.length === 1 ? "" : "es"} | ${dateLabel}`, digestHtml);
              }
              console.log(`Daily digest sent: ${eventPerfektTenders.length} EP-relevant tenders to ${recipients.join(", ")}`);
            } catch (digestErr: any) {
              console.error("Daily digest email failed:", digestErr.message);
            }
          } else {
            // Send explicit "0 matches" email — do not silently skip
            const zeroHtml = `<div style="background:#1A0A0E;color:#f0e8dc;font-family:Arial,sans-serif;max-width:800px;margin:0 auto;"><div style="background:#330311;padding:20px;text-align:center;"><h1 style="color:#C9A84C;margin:0;">Event Perfekt Tender Digest</h1><p style="color:#f0e8dc;margin:4px 0 0;font-size:13px;">${dateLabel}</p></div><div style="padding:24px 16px;text-align:center;"><p style="color:#C9A84C;font-size:16px;font-weight:700;margin:0;">0 matches today</p><p style="color:#888;font-size:13px;margin-top:8px;">${tenders.length} tenders fetched from live sources — none met the EP relevance threshold (score ≥15).<br/>No action needed. The next sweep runs tomorrow at 07:00.</p></div><div style="background:#330311;padding:12px;text-align:center;font-size:11px;color:#999;">Event Perfekt Global Ltd | London & Lagos</div></div>`;
            try {
              for (const recipient of recipients) {
                await emailService.sendEmail(recipient, `EP Tender Digest — 0 matches today | ${dateLabel}`, zeroHtml);
              }
              console.log(`Daily digest sent: 0 matches (${tenders.length} fetched, none passed scoring)`);
            } catch (digestErr: any) {
              console.error("Daily digest (zero) email failed:", digestErr.message);
            }
          }
        } catch (err: any) { console.error("Daily digest error:", err.message); }
      }
    };
    digestInterval = setInterval(checkAndSend, 5 * 60 * 1000);
    console.log("Daily tender digest scheduled (7:00 AM)");
  }
  startDailyDigest();

  // DISABLED 28 Apr 2026 — replaced by signal-based discovery in scripts/discovery/
  // Do not re-enable without explicit instruction.
  // The old generator hallucinated CEFAS/FCDO/Africa-programme prospects every 5 minutes.
  // New discovery pipeline: Companies House anniversaries → funding RSS → Product Hunt launches.
  // prospectInterval left as null; startDailyProspectGeneration() is intentionally not called.
  let prospectInterval: any = null;

  // ── Outreach: Contact Finding + Morning Briefing at 7:30 AM ─────────────
  let briefingInterval: ReturnType<typeof setInterval> | null = null;
  async function runMorningOutreachJob() {
    try {
      const { runContactAndDraftForProspect, sendMorningBriefing } = await import("../outreach-routes");
      // Get prospects added in the last 24h that are NOT quarantined
      const recent = await db.execute(sql`
        SELECT id, company_name, milestone_type, industry, location, priority
        FROM company_prospects
        WHERE created_at > NOW() - INTERVAL '24 hours'
          AND (quarantined IS NOT TRUE)
        ORDER BY id DESC
      `);
      const prospects = (recent.rows as any[]);
      let contactsFound = 0;
      let emailsDrafted = 0;
      for (const p of prospects) {
        const { contactFound, emailDrafted } = await runContactAndDraftForProspect(p.id);
        if (contactFound) contactsFound++;
        if (emailDrafted) emailsDrafted++;
      }
      await sendMorningBriefing({
        prospectsAdded: prospects.length,
        contactsFound,
        emailsDrafted,
        prospects,
      });
    } catch (err: any) {
      console.error("Morning outreach job error:", err.message);
    }
  }

  let lastBriefingDate = ""; // prevents re-fire when server restarts inside the 7:30am window
  function startMorningBriefingScheduler() {
    function checkAndBrief() {
      const now = new Date();
      if (now.getDay() === 0) return; // Skip Sunday
      if (now.getHours() === 7 && now.getMinutes() >= 30 && now.getMinutes() < 35) {
        const today = now.toISOString().split("T")[0];
        if (lastBriefingDate === today) return; // already sent today — skip
        lastBriefingDate = today;
        runMorningOutreachJob();
      }
    }
    briefingInterval = setInterval(checkAndBrief, 5 * 60 * 1000);
    console.log("Morning briefing scheduled (7:30 AM)");
  }
  startMorningBriefingScheduler();

  // ── Enquiry Follow-up Reminder (every 2 hours) ─────────────────────────
  let enquiryReminderInterval: ReturnType<typeof setInterval> | null = null;

  async function checkUnreviewedEnquiries() {
    try {
      const result = await db.execute(sql`
        SELECT id, name, email, event_type, created_at 
        FROM enquiries 
        WHERE status = 'new' 
        AND created_at < NOW() - INTERVAL '24 hours'
        LIMIT 10
      `);
      
      if (result.rows.length > 0) {
        const enquiries = result.rows as any[];
        const enquiryList = enquiries
          .map(e => `• ${e.name} (${e.event_type}) — submitted ${new Date(e.created_at).toLocaleDateString()}`)
          .join('\n');
        
        try {
          await sendEmail(
            'info@eventperfekt.com',
            `⏰ Reminder: ${result.rows.length} Enquiries Pending Review (24+ hours)`,
            `
            <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
              <h2 style="color: #8B1538;">⏰ Enquiries Pending Review</h2>
              <p>The following <strong>${result.rows.length} enquiries</strong> have been waiting for review for <strong>24+ hours</strong>:</p>
              <div style="background: #f8f9fa; padding: 20px; border-radius: 8px; margin: 20px 0; white-space: pre-wrap; color: #666;">
${enquiryList}
              </div>
              <p>Please review these enquiries and either:</p>
              <ul style="color: #666;">
                <li>✅ Approve & convert to event</li>
                <li>📧 Request more information</li>
                <li>❌ Decline with reason</li>
              </ul>
              <p><a href="https://eventperfekt.net/lead-pipeline" style="background: #8B1538; color: white; padding: 10px 20px; text-decoration: none; border-radius: 4px; display: inline-block;">View Lead Pipeline</a></p>
            </div>
            `
          );
          console.log(`✉️ Sent follow-up reminder for ${result.rows.length} unreviewed enquiries`);
        } catch (err) {
          console.error('Failed to send enquiry reminder:', err);
        }
      }
    } catch (err) {
      console.error('Error checking unreviewed enquiries:', err);
    }
  }

  function startEnquiryReminderScheduler() {
    // Run once daily at 10:00 UTC — using setTimeout chain so deploys/restarts
    // don't cause extra fires (the next scheduled time is always recalculated from now)
    const scheduleNextEnquiryReminder = () => {
      const now = new Date();
      const next = new Date(now);
      next.setUTCHours(10, 0, 0, 0);
      if (next <= now) next.setUTCDate(next.getUTCDate() + 1);
      const ms = next.getTime() - now.getTime();
      enquiryReminderInterval = setTimeout(async () => {
        await checkUnreviewedEnquiries();
        scheduleNextEnquiryReminder();
      }, ms);
      console.log(`Enquiry reminder scheduler started — next run at ${next.toISOString()} (in ${Math.round(ms / 60000)} min)`);
    };
    scheduleNextEnquiryReminder();
  }
  startEnquiryReminderScheduler();

  // ── Tender: 6-hour discovery cycle ─────────────────────────────────────────
  async function runTenderDiscoveryCycle() {
    try {
      console.log("[Tender Discovery] Running automated 6-hour cycle...");
      const keywords = ["event management", "conference", "hospitality", "training", "programme management"];
      let found = 0;
      for (const kw of keywords) {
        try {
          const cfResp = await fetch(`https://www.contractsfinder.service.gov.uk/Published/Notices/OCDS/Search?searchTerm=${encodeURIComponent(kw)}&limit=5&order=publishedDate`, { signal: AbortSignal.timeout(10000) });
          if (cfResp.ok) {
            const cfData = await cfResp.json() as any;
            const notices = cfData?.results || cfData?.releases || [];
            for (const notice of notices.slice(0, 3)) {
              const title = notice?.tender?.title || notice?.title || notice?.name || "";
              const buyer = notice?.buyer?.name || notice?.parties?.[0]?.name || "";
              const deadline = notice?.tender?.tenderPeriod?.endDate || notice?.tender?.submissionDeadline || null;
              const value = notice?.tender?.value?.amount || null;
              if (title) {
                await db.execute(sql`
                  INSERT INTO tenders (title, buyer, deadline, value, value_text, status, source, category, created_at, updated_at)
                  VALUES (${title}, ${buyer}, ${deadline}, ${value}, ${value ? `£${value.toLocaleString()}` : null}, 'Researching', 'Contracts Finder', 'Event Management', NOW(), NOW())
                  ON CONFLICT DO NOTHING
                `).catch(() => {});
                found++;
              }
            }
          }
        } catch {}
      }
      await db.execute(sql`INSERT INTO tender_automation_log (entity, action, result, email_sent) VALUES ('GB', 'auto_discovery', ${`6-hour cycle: ${found} tenders found`}, false)`).catch(() => {});
      console.log(`[Tender Discovery] 6-hour cycle complete — ${found} tenders found`);
    } catch (e: any) { console.error("[Tender Discovery] Error:", e.message); }
  }
  // Run immediately on startup, then every 6 hours
  runTenderDiscoveryCycle();
  setInterval(runTenderDiscoveryCycle, 6 * 60 * 60 * 1000);
  console.log("Tender discovery cycle scheduled (every 6 hours)");

  // ── Register outreach approval routes ────────────────────────────────────
