  app.post("/api/tender-ai/bid-chat", authenticateTenderUser, async (req: any, res) => {
    try {
      const { message, tender, active_section, current_content, context, history } = req.body;
      if (!message) return res.status(400).json({ message: "Message required" });

      let profileContext = "";
      try {
        const profileResult = await db.execute(sql`SELECT * FROM tender_company_profile LIMIT 1`);
        if (profileResult.rows.length > 0) {
          const p = profileResult.rows[0] as any;
          profileContext = `Company: ${p.company_name || "Event Perfekt Global Ltd"} | Nigeria: ${p.ng_company_name || "Event Perfekt Management Services Limited"} | Sector: ${p.sector_experience || "Events, Conferences, Marketing, Branding"}`;
        }
      } catch (e: any) {}

      const systemPrompt = `${EP_AGENT_SYSTEM_PROMPT}

You are the EP Bid Writer Agent — a specialist in writing winning bids and tenders for Event Perfekt.
${profileContext ? `\nCOMPANY: ${profileContext}` : ""}

CURRENT CONTEXT:
- Tender: ${tender?.title || "Unknown"}
- Buyer: ${tender?.buyer || "Unknown"}
- Value: ${tender?.value_text || "Not specified"}
- Active Section: ${active_section || "None"}
- Requirements/Context: ${context || "None provided"}
${current_content ? `\nCURRENT SECTION CONTENT:\n${current_content.substring(0, 1000)}` : ""}

Your role:
1. Help improve, refine, or rewrite bid sections
2. Answer questions about bid strategy and requirements
3. Suggest specific content, phrases, and evidence to include
4. Flag compliance gaps or missing elements
5. Provide guidance on next steps

If the user asks you to rewrite or generate content for a section, include it in your response prefixed with [SECTION_CONTENT_START] and ending with [SECTION_CONTENT_END] — this will automatically update the editor.

Be specific, actionable, and professional. Use UK/Nigeria bid writing conventions as appropriate.`;

      const messages = [
        ...(history || []).slice(-6).map((m: any) => ({ role: m.role as "user" | "assistant", content: m.content })),
        { role: "user" as const, content: message }
      ];

      const response = await tenderOpenAI.chat.completions.create({
        model: "gpt-4o",
        messages: [{ role: "system", content: systemPrompt }, ...messages],
        max_tokens: 1500,
      });

      const responseText = response.choices[0]?.message?.content || "I couldn't process that — please try again.";

      // Extract suggested section content if present
      const sectionMatch = responseText.match(/\[SECTION_CONTENT_START\]([\s\S]*?)\[SECTION_CONTENT_END\]/);
      const suggestedContent = sectionMatch ? sectionMatch[1].trim() : null;
      const cleanResponse = responseText.replace(/\[SECTION_CONTENT_START\][\s\S]*?\[SECTION_CONTENT_END\]/, "").trim();

      res.json({
        content: cleanResponse || responseText,
        suggested_content: suggestedContent
      });
    } catch (error: any) {
      res.status(500).json({ message: "Bid chat failed: " + error.message });
    }
  });

