  function normalizeStatus(rawStatus: string, deadline?: string): string {
    const s = (rawStatus || "").toLowerCase().trim();
    const closedWords = ["closed", "complete", "completed", "ended", "expired"];
    const awardedWords = ["awarded", "contract awarded", "award", "intent to award"];
    const cancelledWords = ["cancelled", "canceled", "withdrawn", "abandoned", "suspended"];
    const openWords = ["open", "active", "published", "tender", "planning", "planned"];
    if (cancelledWords.some(w => s.includes(w))) return "CANCELLED";
    if (awardedWords.some(w => s.includes(w))) return "AWARDED";
    if (closedWords.some(w => s.includes(w))) return "CLOSED";
    if (openWords.some(w => s.includes(w))) return "OPEN";
    if (deadline) {
      const dl = new Date(deadline);
      if (dl > new Date()) return "OPEN";
    }
    return "UNKNOWN";
  }

  function fuzzyMatch(a: string, b: string): boolean {
    const normalize = (s: string) => s.toLowerCase().replace(/[^a-z0-9]/g, " ").replace(/\s+/g, " ").trim();
    const na = normalize(a);
    const nb = normalize(b);
    if (na === nb) return true;
    if (na.length < 10 || nb.length < 10) return false;
    const wordsA = na.split(" ").filter(w => w.length > 2);
    const wordsB = nb.split(" ").filter(w => w.length > 2);
    if (wordsA.length === 0 || wordsB.length === 0) return false;
    const common = wordsA.filter(w => wordsB.includes(w));
    return common.length / Math.max(wordsA.length, wordsB.length) > 0.85;
  }

