  function detectProgrammeDisbursement(title: string, description: string): boolean {
    const text = `${title} ${description}`.toLowerCase();
    const programmeKeywords = [
      /programme\s+implementation/, /in[- ]country\s+delivery/, /field\s+coordination/,
      /workshop\s+(or\s+)?training\s+delivery/, /grant\s+administration/,
      /stakeholder\s+engagement/, /beneficiary\s+management/, /sme\s+support\s+programme/,
    ];
    const disbursementKeywords = [
      /cash\s+transfer/, /stipend\s+payments?/, /beneficiary\s+payments?/,
      /grant\s+disbursement/, /bulk\s+payments?/, /incentive\s+payments?/,
      /humanitarian\s+cash\s+assistance/, /voucher\s+payments?/, /reimbursement\s+payments?/,
    ];
    const hasProgramme = programmeKeywords.some(kw => kw.test(text));
    const hasDisbursement = disbursementKeywords.some(kw => kw.test(text));
    return hasProgramme && hasDisbursement;
  }

  function detectHighStrategicOpportunity(tender: any): boolean {
    const country = (tender.country || "").toLowerCase();
    const location = (tender.location || "").toLowerCase();
    const titleLower = (tender.title || "").toLowerCase();
    const summaryLower = (tender.short_summary || tender.description || "").toLowerCase();
    const combined = `${country} ${location} ${titleLower} ${summaryLower}`;
    const africaTerms = ["africa", "nigeria", "ghana", "kenya", "zambia", "senegal", "sierra leone", "morocco", "egypt", "mozambique", "madagascar", "south africa", "tanzania", "ethiopia", "uganda", "cameroon", "ivory coast", "rwanda", "malawi", "zimbabwe", "botswana", "namibia", "angola", "togo", "benin", "burkina faso", "mali", "niger", "chad", "gabon", "liberia", "guinea"];
    const isAfrica = africaTerms.some(term => combined.includes(term));
    const isProgrammeDisbursement = tender.programme_disbursement === true;
    const value = parseFloat(tender.value_estimate) || 0;
    const isHighValue = value >= 100000;
    return isAfrica && isProgrammeDisbursement && isHighValue;
  }

