  app.get("/api/cascade/enquiries", authenticateToken, async (req: any, res: any) => {
    try {
      const { status } = req.query;
      let result;
      if (status && status !== "all") {
        result = await db.execute(sql`SELECT * FROM enquiries WHERE status = ${status} ORDER BY created_at DESC`);
      } else {
        result = await db.execute(sql`SELECT * FROM enquiries ORDER BY created_at DESC`);
      }
      res.json(result.rows);
    } catch (error: any) {
      console.error("Cascade enquiries fetch error:", error);
      res.status(500).json({ message: "Failed to fetch enquiries" });
    }
  });

  // Approval cascade — manager approves enquiry, assigns planner, full event setup triggers
  app.post("/api/cascade/approve/:enquiryId", authenticateToken, async (req: any, res: any) => {
    try {
      const { enquiryId } = req.params;
      const { assignedPlannerId, notes } = req.body;
      const managerId = req.user?.id || req.user?.userId;

      if (!assignedPlannerId) {
        return res.status(400).json({ success: false, message: "assignedPlannerId is required" });
      }

      // Save intake notes to enquiry
      if (notes) {
        await db.execute(sql`UPDATE enquiries SET intake_notes = ${notes}, status = 'approved' WHERE id = ${enquiryId}`);
      } else {
        await db.execute(sql`UPDATE enquiries SET status = 'approved' WHERE id = ${enquiryId}`);
      }

      const { triggerApprovalCascade } = await import("../cascadeService");
      const result = await triggerApprovalCascade(enquiryId, managerId, assignedPlannerId);
      res.json(result);
    } catch (error: any) {
      console.error("Cascade approve error:", error);
      res.status(500).json({ success: false, message: error.message || "Approval failed" });
    }
  });

  // Reject enquiry
