  // TASK ASSIGNMENT & NOTIFICATIONS
  // ═══════════════════════════════════════════════════════════════════════

  app.post("/api/events/:eventId/tasks/assign", authenticateToken, async (req: any, res) => {
    try {
      const { eventId } = req.params;
      const { title, description, assigned_to, due_date, priority, notify_via } = req.body;

      if (!title || !assigned_to || !due_date) {
        return res.status(400).json({ message: "Title, assigned_to, and due_date required" });
      }

      // Create task
      const taskResult = await db.execute(sql`
        INSERT INTO tasks (event_id, title, description, assigned_to, due_date, priority, status, created_by)
        VALUES (${eventId}, ${title}, ${description || null}, ${assigned_to}, ${due_date}, ${priority || 'medium'}, 'todo', ${req.user?.userId || req.user?.id})
        RETURNING *
      `);

      const task = taskResult.rows[0] as any;

      // Get assignee details
      const assigneeResult = await db.execute(sql`
        SELECT id, name, email, phone FROM users WHERE id = ${assigned_to}
      `);
      const assignee = assigneeResult.rows[0] as any;

      // Get creator details
      const creatorResult = await db.execute(sql`
        SELECT id, name FROM users WHERE id = ${req.user?.userId || req.user?.id}
      `);
      const creator = creatorResult.rows[0] as any;

      // Get event details
      const eventResult = await db.execute(sql`
        SELECT id, name FROM events WHERE id = ${eventId}
      `);
      const event = eventResult.rows[0] as any;

      // Send notifications
      if (notify_via === "email" || notify_via === "both") {
        if (assignee?.email) {
          const emailService = new (await import("../emailService")).EmailNotificationService();
          const html = `
            <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
              <div style="background: #8B1538; color: white; padding: 20px; text-align: center;">
                <h1>New Task Assignment</h1>
              </div>
              <div style="padding: 20px; background: #f9f9f9;">
                <p>Hi ${assignee.name},</p>
                <p><strong>${creator.name}</strong> has assigned you a task:</p>
                
                <div style="background: white; padding: 15px; border-left: 4px solid #8B1538; margin: 15px 0;">
                  <h3>${title}</h3>
                  <p>${description || "No description provided"}</p>
                  <p><strong>Event:</strong> ${event?.name || 'Event'}</p>
                  <p><strong>Due Date:</strong> ${due_date}</p>
                  <p><strong>Priority:</strong> ${priority}</p>
                </div>
                
                <p>Please log in to Event Perfekt to view and update the task status.</p>
                <p>Best regards,<br/>Event Perfekt Team</p>
              </div>
            </div>
          `;
          
          try {
            await emailService.sendEmail(assignee.email, `New Task Assignment: ${title}`, html);
            console.log(`✓ Email sent to ${assignee.email}`);
          } catch (err) {
            console.warn("Email sending failed (fallback mode):", err);
          }
        }
      }

      // WhatsApp notification (placeholder for future integration)
      if ((notify_via === "whatsapp" || notify_via === "both") && assignee?.phone) {
        const whatsappMessage = `
📋 New Task Assignment
From: ${creator.name}
Task: ${title}
Event: ${event?.name || 'Event'}
Due: ${due_date}
Priority: ${priority}

Log in to Event Perfekt to manage this task.
        `.trim();
        console.log(`📱 [WHATSAPP READY] ${assignee.phone}: ${whatsappMessage}`);
        // TODO: Integrate with WhatsApp Business API when available
      }

      res.json({
        success: true,
        task,
        notification: {
          email_sent: notify_via === "email" || notify_via === "both",
          whatsapp_ready: notify_via === "whatsapp" || notify_via === "both",
        },
      });
    } catch (error: any) {
      console.error("Task assignment error:", error);
      res.status(500).json({ message: "Failed to assign task" });
    }
  });

