  // Governance — approve / reject / request-changes
  app.post("/api/tender-governance/action/:id", authenticateTenderUser, async (req: any, res) => {
    try {
      const id = parseInt(req.params.id);
      const { action, notes } = req.body; // action: approve | reject | request_changes
      const statusMap: Record<string, string> = { approve: "approved", reject: "rejected", request_changes: "changes_requested" };
      const newStatus = statusMap[action];
      if (!newStatus) return res.status(400).json({ message: "Invalid action" });
      await db.execute(sql`UPDATE tender_bid_sections SET governance_status = ${newStatus}, updated_at = NOW() WHERE id = ${id}`);
      const user = await db.execute(sql`SELECT name FROM tender_users WHERE id = ${req.tenderUser.userId}`);
      const userName = (user.rows[0] as any)?.name || req.tenderUser.email;
      await db.execute(sql`INSERT INTO tender_governance_log (tender_id, section_id, action, performed_by, notes) SELECT tender_id, id, ${action}, ${userName}, ${notes || null} FROM tender_bid_sections WHERE id = ${id}`);
      // If changes requested → auto-rewrite with EP Agent
      if (action === "request_changes" && notes) {
        try {
          const sec = await db.execute(sql`SELECT s.*, t.title as tender_title, t.buyer, t.category FROM tender_bid_sections s LEFT JOIN tenders t ON t.id = s.tender_id WHERE s.id = ${id}`);
          const s = sec.rows[0] as any;
          if (s) {
              const newContent = await callClaude(
              EP_AGENT_SYSTEM_PROMPT + "\n\nRewrite the bid section below, addressing ALL reviewer feedback points precisely. Improve weaknesses, strengthen evidence, keep strong parts.",
              `Section: ${s.name}\nTender: ${s.tender_title}\nBuyer: ${s.buyer}\n\nCurrent content:\n${s.content || ""}\n\nReviewer feedback:\n${notes}\n\nRewrite addressing all feedback points.`,
              1500
            );
            const newVersion = (s.version || 1) + 1;
            await db.execute(sql`UPDATE tender_bid_sections SET content = ${newContent}, version = ${newVersion}, governance_status = 'rewritten', updated_at = NOW() WHERE id = ${id}`);
            await db.execute(sql`INSERT INTO tender_governance_log (tender_id, section_id, action, performed_by, notes) SELECT tender_id, id, 'auto_rewritten', 'EP Agent', ${'Auto-rewritten (v' + newVersion + ')'} FROM tender_bid_sections WHERE id = ${id}`);
          }
        } catch {}
      }
      res.json({ message: `Section ${action}d successfully` });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

